namespace Skyline.DataMiner.Utils.MediaOps.Common
{
	using System;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.MediaOps.Communication.Exceptions;
	using Skyline.DataMiner.Utils.MediaOps.Common.Utils;

	public abstract class MediaOpsScript
	{
		protected abstract string ScriptName { get; }

		protected abstract ScriptType ScriptType { get; }

		protected IEngineContext Context { get; private set; }

		public void Run(IEngine engine)
		{
			Context = new EngineContext
			{
				Engine = engine,
				Logger = new MediaOpsLogger(ScriptType, ScriptName),
			};

			Initialize();

			using (Context.Logger)
			{
				try
				{
					Context.Logger.Information(this, $"Script started by {engine.UserDisplayName}");

					RunSafe();
				}
				catch (ScriptAbortException)
				{
					// Catch normal abort exceptions (engine.ExitFail or engine.ExitSuccess)
					throw; // Comment if it should be treated as a normal exit of the script.
				}
				catch (ScriptForceAbortException)
				{
					// Catch forced abort exceptions, caused via external maintenance messages.
					throw;
				}
				catch (ScriptTimeoutException)
				{
					// Catch timeout exceptions for when a script has been running for too long.
					throw;
				}
				catch (InteractiveUserDetachedException)
				{
					// Catch a user detaching from the interactive script by closing the window.
					// Only applicable for interactive scripts, can be removed for non-interactive scripts.
					throw;
				}
				catch (MediaOpsException mediaOpsException)
				{
					Context.Logger.Warning(nameof(MediaOpsScript), nameof(Run), mediaOpsException, $"MediaOps exception occurred in {ScriptName}");
					HandleMediaOpsException(mediaOpsException);
				}
				catch (Exception exception)
				{
					Context.Logger.Error(nameof(MediaOpsScript), nameof(Run), exception, $"Exception occurred in {ScriptName}");
					HandleException(exception);
				}
				finally
				{
					Finally();
				}
			}
		}

		protected abstract void RunSafe();

		protected virtual void Initialize()
		{
			Context.Engine.Timeout = TimeSpan.FromHours(10);
			Context.Engine.SetFlag(RunTimeFlags.NoKeyCaching);
			Context.Engine.SetFlag(RunTimeFlags.NoInformationEvents);
			Context.Engine.SetFlag(RunTimeFlags.NoCheckingSets);
		}

		protected virtual void HandleException(Exception exception)
		{
			// override to do something when an unexpected exception is caught
		}

		protected virtual void HandleMediaOpsException(MediaOpsException mediaOpsException)
		{
			// override to do something when a MediaOpsException is caught
		}

		protected virtual void Finally()
		{
			// override to do something at the end of every script run regardless whether exception were thrown or not.
		}

		protected void Exit(string reason = null)
		{
			Context.Engine.ExitSuccess(reason ?? "Exit Script");
		}

		protected string GetStringInputParameter(string parameterName)
		{
			var inputParameter = Context.Engine.GetScriptParam(parameterName);
			if (inputParameter == null) throw new InvalidOperationException($"No {parameterName} input parameter found");

			return inputParameter.Value;
		}

		protected Guid GetGuidInputParameter(string parameterName)
		{
			string value = GetStringInputParameter(parameterName);
			if (!Guid.TryParse(value, out Guid guid)) throw new InvalidOperationException($"Unable to parse {value} to a valid GUID");
			return guid;
		}

		private sealed class EngineContext : IEngineContext
		{
			public IEngine Engine { get; set; }

			public ILogger Logger { get; set; }
		}
	}
}

