	using Skyline.DataMiner.Utils.SecureCoding.SecureIO;

	public class IconHandler
	{
		private const string IconsFolderPath = @"C:\Skyline DataMiner\Webpages\Public\MediaOps\Icons";

		private readonly Lazy<IEnumerable<string>> icons = new Lazy<IEnumerable<string>>(() => GetIcons());

		public IEnumerable<string> Icons => icons.Value;

		private static IEnumerable<string> GetIcons()
		{
			SecurePath path = SecurePath.CreateSecurePath(IconsFolderPath);
			if (!Directory.Exists(path)) return Enumerable.Empty<string>();
			var iconsFilePaths = Directory.GetFiles(path, "*.svg");
			return iconsFilePaths.Select(x => Path.GetFileNameWithoutExtension(x));
		}
	}
}

