namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow.Validation
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Messages;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Net.ResourceManager.Objects;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling;
	using Skyline.DataMiner.Utils.MediaOps.Common.Extensions;
	using Skyline.DataMiner.Utils.MediaOps.Common.SRM;

	using CoreResource = Skyline.DataMiner.Net.Messages.Resource;
	using DomResource = Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio.Resource;

	public class JobValidator : IValidator<Job>
	{
		private const int MaxErrorMessageLength = 300;
		private readonly ResourceManagerHelper _resourceManagerHelper;
		private readonly ResourceStudioHandler _resourceStudioHandler;
		private readonly SrmHelpers _srmHelper;

		private readonly List<string> quarantinedNodeIds = new List<string>();

		public JobValidator(IEngine engine, ResourceManagerHelper resourceManagerHelper = null, ResourceStudioHandler resourceStudioHandler = null)
		{
			if (engine == null)
			{
				throw new ArgumentNullException(nameof(engine));
			}

			_resourceManagerHelper = resourceManagerHelper ?? new ResourceManagerHelper(engine.SendSLNetSingleResponseMessage);
			_resourceStudioHandler = resourceStudioHandler ?? new ResourceStudioHandler(engine);
			_srmHelper = new SrmHelpers(engine);
		}

		public IReadOnlyCollection<string> QuarantinedNodeIds => quarantinedNodeIds;

		public ValidatorResults<Job> Validate(Job job)
		{
			var results = new ValidatorResults<Job>(job);
			quarantinedNodeIds.Clear();

			try
			{
				var domResources = GetDomResources(job, results);

				foreach (var domResource in domResources)
				{
					ValidateDomResource(domResource, results);
				}

				var coreResources = GetCoreResources(domResources, results);

				foreach (var coreResource in coreResources)
				{
					ValidateCoreResource(coreResource, results);
				}

				var jobReservations = GetJobReservations(job);

				foreach (var jobReservation in jobReservations)
				{
					ValidateJobReservation(jobReservation, results);
				}
			}
			catch (Exception ex)
			{
				results.SetResult(Errors.GenericException.CreateResult($"ERROR: {ex}"));
			}

			return results;
		}

		private ICollection<DomResource> GetDomResources(Job job, ValidatorResults<Job> results)
		{
			var resourceNodes = job.Nodes.Where(x => x.NodeType == SlcWorkflow.Enums.NodeType.Resource).ToList();
			var resourceIds = resourceNodes.Select(x => x.ReferenceId).Distinct().ToList();

			var resources = _resourceStudioHandler.GetResourcesByDomInstanceIds(resourceIds).ToDictionary(x => x.InstanceId);

			// check
			foreach (var node in resourceNodes)
			{
				if (!resources.ContainsKey(node.ReferenceId))
				{
					var message = $"Couldn't find DOM resource with ID '{node.ReferenceId}' for node {node.Id}";
					results.SetResult(Errors.Resource.DomResourceNotFound.CreateResult(message));
				}
			}

			return resources.Values;
		}

		private void ValidateDomResource(DomResource resource, ValidatorResults<Job> results)
		{
			if (resource.StatusId != SlcResource_Studio.Behaviors.Resource_Behavior.Statuses.Complete)
			{
				var message = $"Resource '{resource.Name}' is not in complete state";
				results.SetResult(Errors.Resource.DomResourceError.CreateResult(message));
			}

			if (resource.HasErrors)
			{
				var message = $"Resource '{resource.Name}' has active errors";
				results.SetResult(Errors.Resource.DomResourceError.CreateResult(message));
			}
		}

		private ICollection<CoreResource> GetCoreResources(ICollection<DomResource> domResources, ValidatorResults<Job> results)
		{
			if (domResources == null || !domResources.Any())
			{
				return Array.Empty<CoreResource>();
			}

			var domResourcesWithCoreIds = domResources
				.Where(x => x.InternalProperties != null && x.InternalProperties.ResourceId != Guid.Empty)
				.SafeToDictionary(x => x.InternalProperties.ResourceId, x => x);

			var coreResourceIds = domResourcesWithCoreIds.Keys;

			var filter = new ORFilterElement<CoreResource>(coreResourceIds.Select(x => ResourceExposers.ID.Equal(x)).ToArray());
			var resources = _resourceManagerHelper.GetResources(filter).ToDictionary(x => x.ID);

			foreach (var resourceId in coreResourceIds)
			{
				if (!resources.ContainsKey(resourceId))
				{
					var domResource = domResourcesWithCoreIds[resourceId];
					var message = $"Couldn't find core resource with ID '{resourceId}' linked to DOM resource '{domResource.Name}'";
					results.SetResult(Errors.Resource.CoreResourceNotFound.CreateResult(message));
				}
			}

			return resources.Values;
		}

		private void ValidateCoreResource(CoreResource resource, ValidatorResults<Job> results)
		{
			if (resource.Mode != ResourceMode.Available)
			{
				var message = $"Resource '{resource.Name}' has state {resource.Mode}";
				results.SetResult(Errors.Resource.CoreResourceError.CreateResult(message));
			}
		}

		private ICollection<ReservationInstance> GetJobReservations(Job job)
		{
			var coreReservationIds = job.Nodes.Select(x => x.LinkedBookingId).Distinct().ToList();

			if (coreReservationIds.Count > 0)
			{
				var reservationFilter = new ORFilterElement<ReservationInstance>(coreReservationIds.Select(id => ReservationInstanceExposers.ID.Equal(id)).ToArray());
				return _srmHelper.ResourceManagerHelper.GetReservationInstances(reservationFilter).ToList();
			}
			else
			{
				return Array.Empty<ReservationInstance>();
			}
		}

		private void ValidateJobReservation(ReservationInstance reservation, ValidatorResults<Job> results)
		{
			if (reservation.IsQuarantined)
			{
				var message = ComposeQuarantineMessage(reservation);
				results.SetResult(Errors.Resource.CoreResourceMovedToQuarantine.CreateResult(message));
			}
		}

		private string ComposeQuarantineMessage(ReservationInstance reservation)
		{
			var resourceNames = new List<string>();

			var quarantinedResourceIds = reservation.QuarantinedResources.Select(x => x.QuarantinedResourceUsage.GUID).ToList();

			foreach (var quarantinedResource in reservation.QuarantinedResources)
			{
				var resourceName = string.Empty;

				foreach (var quarantineTrigger in quarantinedResource.QuarantineTriggers)
				{
					if (quarantineTrigger.UpdateTrigger.NewResource != null)
					{
						resourceName = quarantineTrigger.UpdateTrigger.NewResource.Name;
					}
					else if (quarantineTrigger.UpdateTrigger.OldResource != null)
					{
						resourceName = quarantineTrigger.UpdateTrigger.OldResource.Name;
					}
				}

				var nodeId = string.Empty;
				if (quarantinedResource.QuarantinedResourceUsage is ServiceResourceUsageDefinition serviceResourceUsageDefinition)
				{
					nodeId = serviceResourceUsageDefinition.ServiceDefinitionNodeID.ToString();
					quarantinedNodeIds.Add(nodeId);
				}

				if (quarantinedResourceIds.Count(x => x == quarantinedResource.QuarantinedResourceUsage.GUID) > 1 && !string.IsNullOrEmpty(nodeId))
				{
					resourceName += $" ({nodeId})";
				}

				resourceNames.Add(resourceName);
			}

			var message = $"Reservation contains quarantined resources: {String.Join(", ", resourceNames.Distinct())}. Consider swapping the overbooked resources.";

			if (message.Length > MaxErrorMessageLength)
			{
				message = $"Reservation contains {reservation.QuarantinedResources.Count} quarantined resources. Consider swapping the overbooked resources.";
			}

			return message;
		}
	}
}

//---------------------------------
// Comparers\ResourceNameComparer.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Comparers
{
	using System;
	using System.Collections.Generic;
	using System.Text.RegularExpressions;

	public class ResourceNameComparer : IComparer<string>
	{
		private static readonly Regex _splitRegex = new Regex(@"\d+|\D+", RegexOptions.Compiled);

		public int Compare(string x, string y)
		{
			if (ReferenceEquals(x, y))
				return 0;

			if (x == null)
				return -1;

			if (y == null)
				return 1;

			var xParts = _splitRegex.Matches(x);
			var yParts = _splitRegex.Matches(y);

			int maxParts = Math.Max(xParts.Count, yParts.Count);

			for (int i = 0; i < maxParts; i++)
			{
				if (i >= xParts.Count) return -1;
				if (i >= yParts.Count) return 1;

				string xPart = xParts[i].Value;
				string yPart = yParts[i].Value;

				if (TryCompareParts(xPart, yPart, out int comparison))
				{
					return comparison;
				}
			}

			return x.Length.CompareTo(y.Length);
		}

		private bool TryCompareParts(string xPart, string yPart, out int comparison)
		{
			bool xIsNumber = int.TryParse(xPart, out int xNum);
			bool yIsNumber = int.TryParse(yPart, out int yNum);

			if (xIsNumber && yIsNumber)
			{
				comparison = xNum.CompareTo(yNum);
				if (comparison != 0) return true;
			}
			else
			{
				comparison = String.Compare(xPart, yPart, StringComparison.OrdinalIgnoreCase);
				if (comparison != 0) return true;
			}

			return false;
		}
	}
}

