	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel.Concatenation;
	using Skyline.DataMiner.Utils.DOM.Builders;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;

	public class SlcWorkflowBuilder : DomInstanceBuilder<SlcWorkflowBuilder>
	{
		public SlcWorkflowBuilder() : base(SlcWorkflow.Definitions.Workflows)
		{
		}

		public SlcWorkflowBuilder(DomInstance basedOn) : base(basedOn)
		{
		}

		public static DomInstanceNameDefinition NameDefinition { get; } = new DomInstanceNameDefinition
		{
			ConcatenationItems = new List<IDomInstanceConcatenationItem>
			{
				new FieldValueConcatenationItem(SlcWorkflow.Sections.WorkflowInfo.WorkflowName),
			},
		};

		public SlcWorkflowBuilder WithName(string name)
		{
			var builder = WithFieldValue(
				SlcWorkflow.Sections.WorkflowInfo.Id,
				SlcWorkflow.Sections.WorkflowInfo.WorkflowName,
				name);

			NameDefinition.SetNameOnDomInstance(_instance);

			return builder;
		}

		public SlcWorkflowBuilder WithScriptName(string scriptName)
		{
			return WithFieldValue(
				SlcWorkflow.Sections.WorkflowExecution.Id,
				SlcWorkflow.Sections.WorkflowExecution.WorkflowExecutionScript,
				scriptName);
		}

		public SlcWorkflowBuilder AddNode(Action<SlcWorkflowNodeBuilder> builder)
		{
			if (builder == null)
			{
				throw new ArgumentNullException(nameof(builder));
			}

			var nodeBuilder = new SlcWorkflowNodeBuilder();
			builder(nodeBuilder);

			return AddSection(nodeBuilder.Build());
		}

		public SlcWorkflowBuilder AddConnection(Action<SlcWorkflowConnectionBuilder> builder)
		{
			if (builder == null)
			{
				throw new ArgumentNullException(nameof(builder));
			}

			var connectionBuilder = new SlcWorkflowConnectionBuilder();
			builder(connectionBuilder);

			return AddSection(connectionBuilder.Build());
		}
	}
}

