namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications
{
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;

	public static class EnumsToString
	{
		public static string Convert(SlcWorkflow.Enums.ConnectionType type)
		{
			switch (type)
			{
				case SlcWorkflow.Enums.ConnectionType.LevelBased: return "Level Based";
				case SlcWorkflow.Enums.ConnectionType.TagBased: return "Tag Based";
				default: return System.Convert.ToString(type);
			}
		}

		public static string Convert(SlcWorkflow.Enums.ConnectionSubtype subtype)
		{
			switch (subtype)
			{
				case SlcWorkflow.Enums.ConnectionSubtype.All: return "All";
				case SlcWorkflow.Enums.ConnectionSubtype.PredefinedSubset: return "Predefined Subset";
				default: return System.Convert.ToString(subtype);
			}
		}

		public static string Convert(SlcWorkflow.Enums.PredefinedSubset subset)
		{
			switch (subset)
			{
				case SlcWorkflow.Enums.PredefinedSubset.V: return "V";
				case SlcWorkflow.Enums.PredefinedSubset.A: return "A";
				case SlcWorkflow.Enums.PredefinedSubset.D: return "D";
				case SlcWorkflow.Enums.PredefinedSubset.VA: return "V+A";
				case SlcWorkflow.Enums.PredefinedSubset.VD: return "V+D";
				case SlcWorkflow.Enums.PredefinedSubset.AD: return "A+D";
				case SlcWorkflow.Enums.PredefinedSubset.VAD: return "V+A+D";
				default: return System.Convert.ToString(subset);
			}
		}

		public static string Convert(SlcWorkflow.Enums.NodeType type)
		{
			switch (type)
			{
				case SlcWorkflow.Enums.NodeType.Source: return "Source";
				case SlcWorkflow.Enums.NodeType.SourceType: return "Source Type";
				case SlcWorkflow.Enums.NodeType.Resource: return "Resource";
				case SlcWorkflow.Enums.NodeType.ResourcePool: return "Resource Pool";
				case SlcWorkflow.Enums.NodeType.Destination: return "Destination";
				case SlcWorkflow.Enums.NodeType.DestinationType: return "Destination Type";
				case SlcWorkflow.Enums.NodeType.SourceInstance: return "Source Instance";
				case SlcWorkflow.Enums.NodeType.DestinationInstance: return "Destination Instance";
				default: return System.Convert.ToString(type);
			}
		}

		public static string Convert(SlcResource_Studio.Enums.Type type)
		{
			switch (type)
			{
				case SlcResource_Studio.Enums.Type.Unmanaged: return "Unmanaged";
				case SlcResource_Studio.Enums.Type.VirtualFunction: return "Virtual Function";
				case SlcResource_Studio.Enums.Type.Element: return "Element";
				case SlcResource_Studio.Enums.Type.Service: return "Service";
				default: return System.Convert.ToString(type);
			}
		}
	}
}

