namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications
{
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.ResourceManager.Objects;

	using CoreResource = Skyline.DataMiner.Net.Messages.Resource;

	/// <summary>
	/// Compares two CoreResource objects by their ID.
	/// </summary>
	public class CoreResourceByIdComparer : IEqualityComparer<CoreResource>
	{
		public bool Equals(CoreResource x, CoreResource y)
		{
			return x.ID == y.ID;
		}

		public int GetHashCode(CoreResource obj)
		{
			return obj.ID.GetHashCode();
		}
	}

	internal class InstanceBaseByIdComparer<T> : IEqualityComparer<T> where T : InstanceBase<T>
	{
		public bool Equals(T x, T y)
		{
			return x.InstanceId == y.InstanceId;
		}

		public int GetHashCode(T obj)
		{
			return obj.InstanceId.GetHashCode();
		}
	}

	internal class DomInstanceByIdComparer : IEqualityComparer<DomInstance>
	{
		public bool Equals(DomInstance x, DomInstance y)
		{
			return x.ID.Id == y.ID.Id;
		}

		public int GetHashCode(DomInstance obj)
		{
			return obj.ID.Id.GetHashCode();
		}
	}

	internal class ReservationInstanceByIdComparer : IEqualityComparer<ReservationInstance>
	{
		public bool Equals(ReservationInstance x, ReservationInstance y)
		{
			return x.ID == y.ID;
		}

		public int GetHashCode(ReservationInstance obj)
		{
			return obj.ID.GetHashCode();
		}
	}
}
