namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.MediaOps
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;

	public class MediaOpsHandler : ModuleHandlerBase
	{
		public MediaOpsHandler(IEngine engine) : base(engine, DomIds.SlcMedia_Ops.ModuleId)
		{
		}

		public MediaOpsHandler(Net.IConnection connection) : base(connection, DomIds.SlcMedia_Ops.ModuleId)
		{
		}

		public MediaOpsHandler(DomHelper domHelper) : base(domHelper, DomIds.SlcMedia_Ops.ModuleId)
		{
		}

		public IEnumerable<Domain> GetAllDomains()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcMedia_Ops.Definitions.Domain.Id);

			return GetDomainsIterator(filter);
		}

		public IEnumerable<Domain> GetDomainsByDomInstanceIds(List<Guid> ids)
		{
			var filter = new ORFilterElement<DomInstance>(ids.Select(id => DomInstanceExposers.Id.Equal(id)).ToArray());

			return GetDomainsIterator(filter);
		}

		private IEnumerable<Domain> GetDomainsIterator(FilterElement<DomInstance> filter)
		{
			foreach (var instance in DomHelper.DomInstances.Read(filter))
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcMedia_Ops.Definitions.Domain.Id)
				{
					continue;
				}

				yield return new Domain(this, instance);
			}
		}
	}
}

