	public class People : InstanceBase<People>, ISkilled
	{
		private static readonly Dictionary<SectionDefinitionID, Action<People, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<People, Section>>
		{
			[DomIds.SlcPeople_Organizations.Sections.PeopleInformation.Id] = (obj, section) => obj.Info = new PeopleInformation(section),
			[DomIds.SlcPeople_Organizations.Sections.ContactInfo.Id] = (obj, section) => obj.ContactInfo = new ContactInfo(section),
			[DomIds.SlcPeople_Organizations.Sections.Organization.Id] = (obj, section) => obj.Organization = new Organization(section),
			[DomIds.SlcPeople_Organizations.Sections.Team.Id] = (obj, section) => obj.teams.Add(new TeamSection(section)),
			[DomIds.SlcPeople_Organizations.Sections.Resource.Id] = (obj, section) => obj.Resource = new ResourceSection(section),
		};

		private readonly List<TeamSection> teams = new List<TeamSection>();

		public People(PeopleOrganizationsHandler peopleOrganizationsHandler, DomInstance instance) : base(peopleOrganizationsHandler, instance, DomIds.SlcPeople_Organizations.Definitions.People)
		{
		}

		public People(PeopleOrganizationsHandler peopleOrganizationsHandler) : base(peopleOrganizationsHandler, DomIds.SlcPeople_Organizations.Definitions.People)
		{
		}

		public PeopleInformation Info { get; private set; }

		public ContactInfo ContactInfo { get; private set; }

		public Organization Organization { get; private set; }

		public ResourceSection Resource { get; private set; }

		public IReadOnlyCollection<TeamSection> Teams => teams;

		public IEnumerable<string> Skills => Info?.Skills ?? new HashSet<string>();

		protected override Dictionary<SectionDefinitionID, Action<People, Section>> SectionMapping => InstanceSectionMapping;

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();
			ContactInfo?.ApplyChanges();
			Organization?.ApplyChanges();
			Resource?.ApplyChanges();
			foreach (var team in teams)
			{
				team.ApplyChanges();
			}
		}

		public void AddSkills(params string[] skills)
		{
			foreach (var skill in skills)
			{
				Info.Skills.Add(skill);
			}
		}

		public void RemoveSkills(params string[] skills)
		{
			foreach (var skill in skills)
			{
				Info.Skills.Remove(skill);
			}
		}

		public void SetSkills(params string[] skills)
		{
			Info.Skills.Clear();
			foreach (var skill in skills)
			{
				Info.Skills.Add(skill);
			}
		}
	}
}

