namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.People_Organizations
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Utils.MediaOps.Common.Tools.ToBeMovedToNuget;

	public class PeopleOrganizationsHandler : ModuleHandlerBase
	{
		public PeopleOrganizationsHandler(IEngine engine) : base(engine, DomIds.SlcPeople_Organizations.ModuleId)
		{
		}

		public PeopleOrganizationsHandler(Net.IConnection connection) : base(connection, DomIds.SlcPeople_Organizations.ModuleId)
		{
		}

		public PeopleOrganizationsHandler(DomHelper domHelper) : base(domHelper, DomIds.SlcPeople_Organizations.ModuleId)
		{
		}

		public IEnumerable<Organizations> GetAllOrganizations()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcPeople_Organizations.Definitions.Organizations.Id);

			return GetOrganizationsIterator(filter);
		}

		public Organizations GetOrganizationByDomInstanceId(Guid id)
		{
			var filter = DomInstanceExposers.Id.Equal(id);

			return GetOrganizationsIterator(filter).SingleOrDefault();
		}

		public IEnumerable<Organizations> GetOrganizationsByDomInstanceIds(IEnumerable<Guid> ids)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var instances = FilterQueryExecutor.RetrieveFilteredItems(
				ids,
				x => DomInstanceExposers.Id.Equal(x),
				x => DomHelper.DomInstances.Read(x),
				new DomInstanceByIdComparer());

			return GetOrganizationsIterator(instances);
		}

		public IEnumerable<Organizations> GetOrganizations(FilterElement<DomInstance> filter)
		{
			if (filter == null)
			{
				throw new ArgumentNullException(nameof(filter));
			}

			return GetOrganizationsIterator(filter);
		}

		public IEnumerable<People> GetAllPeople()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcPeople_Organizations.Definitions.People.Id);

			return GetPeopleIterator(filter);
		}

		public IEnumerable<People> GetNonDeprecatedPeople()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcPeople_Organizations.Definitions.People.Id).AND(DomInstanceExposers.StatusId.NotEqual(DomIds.SlcPeople_Organizations.Behaviors.People_Behavior.Statuses.Deprecated));

			return GetPeopleIterator(filter);
		}

		public People GetPeopleByDomInstanceId(Guid id)
		{
			var filter = DomInstanceExposers.Id.Equal(id);

			return GetPeopleIterator(filter).SingleOrDefault();
		}

		public IEnumerable<People> GetPeopleByDomInstanceIds(IEnumerable<Guid> ids)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var instances = FilterQueryExecutor.RetrieveFilteredItems(
				ids,
				x => DomInstanceExposers.Id.Equal(x),
				x => DomHelper.DomInstances.Read(x),
				new DomInstanceByIdComparer());

			return GetPeopleIterator(instances);
		}

		public IEnumerable<Teams> GetAllTeams()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcPeople_Organizations.Definitions.Teams.Id);

			return GetTeamsIterator(filter);
		}

		public Teams GetTeamByDomInstanceId(Guid id)
		{
			var filter = DomInstanceExposers.Id.Equal(id);

			return GetTeamsIterator(filter).SingleOrDefault();
		}

		public IEnumerable<Teams> GetTeamsByDomInstanceIds(IEnumerable<Guid> ids)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var instances = FilterQueryExecutor.RetrieveFilteredItems(
				ids,
				x => DomInstanceExposers.Id.Equal(x),
				x => DomHelper.DomInstances.Read(x),
				new DomInstanceByIdComparer());

			return GetTeamsIterator(instances);
		}

		public People UpdatePerson(People person)
		{
			if (person == null)
			{
				throw new ArgumentNullException(nameof(person));
			}

			person.ApplyChanges();
			var updatedInstance = DomHelper.DomInstances.Update(person.Instance);

			return new People(this, updatedInstance);
		}

		public Teams UpdateTeam(Teams team)
		{
			if (team == null)
			{
				throw new ArgumentNullException(nameof(team));
			}

			team.ApplyChanges();
			var updatedInstance = DomHelper.DomInstances.Update(team.Instance);

			return new Teams(this, updatedInstance);
		}

		private IEnumerable<Organizations> GetOrganizationsIterator(FilterElement<DomInstance> filter)
		{
			var instances = DomHelper.DomInstances.Read(filter);

			return GetOrganizationsIterator(instances);
		}

		private IEnumerable<Organizations> GetOrganizationsIterator(IEnumerable<DomInstance> instances)
		{
			foreach (var instance in instances)
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcPeople_Organizations.Definitions.Organizations.Id)
				{
					continue;
				}

				yield return new Organizations(this, instance);
			}
		}

		private IEnumerable<People> GetPeopleIterator(FilterElement<DomInstance> filter)
		{
			var instances = DomHelper.DomInstances.Read(filter);

			return GetPeopleIterator(instances);
		}

		private IEnumerable<People> GetPeopleIterator(IEnumerable<DomInstance> instances)
		{
			foreach (var instance in instances)
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcPeople_Organizations.Definitions.People.Id)
				{
					continue;
				}

				yield return new People(this, instance);
			}
		}

		private IEnumerable<Teams> GetTeamsIterator(FilterElement<DomInstance> filter)
		{
			var instances = DomHelper.DomInstances.Read(filter);

			return GetTeamsIterator(instances);
		}

		private IEnumerable<Teams> GetTeamsIterator(IEnumerable<DomInstance> instances)
		{
			foreach (var instance in instances)
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcPeople_Organizations.Definitions.Teams.Id)
				{
					continue;
				}

				yield return new Teams(this, instance);
			}
		}
	}
}

