namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.People_Organizations
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Sections;

	public class PeopleInformation : SectionBase<PeopleInformation>
	{
		private static readonly Dictionary<FieldDescriptorID, Action<PeopleInformation, object>> SectionFieldMapping = new Dictionary<FieldDescriptorID, Action<PeopleInformation, object>>
		{
			[DomIds.SlcPeople_Organizations.Sections.PeopleInformation.FullName] = (obj, value) => obj.FullName = Convert.ToString(value),
			[DomIds.SlcPeople_Organizations.Sections.PeopleInformation.PersonalSkills] = (obj, value) => obj.Skills = StringToSkills(Convert.ToString(value)),
		};

		public PeopleInformation() : base(DomIds.SlcPeople_Organizations.Sections.PeopleInformation.Id)
		{
		}

		internal PeopleInformation(Section section) : base(section)
		{
		}

		public string FullName { get; set; }

		public HashSet<string> Skills { get; private set; } = new HashSet<string>();

		protected override Dictionary<FieldDescriptorID, Action<PeopleInformation, object>> FieldMapping => SectionFieldMapping;

		internal override void ApplyChanges()
		{
			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.PeopleInformation.FullName, FullName);
			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.PeopleInformation.PersonalSkills, SkillToString());
		}

		private string SkillToString()
		{
			return string.Join(", ", Skills);
		}

		private static HashSet<string> StringToSkills(string value)
		{
			var parts = Convert.ToString(value).Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries);
			HashSet<string> result = new HashSet<string>();
			foreach (var part in parts)
			{
				result.Add(part.Trim());
			}

			return result;
		}
	}
}

