			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.TeamInformation.TeamEmail, TeamEmail);
			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.TeamInformation.TeamDescription, TeamDescription);
			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.TeamInformation.Bookable, Bookable);
			Section.AddOrUpdateValue(DomIds.SlcPeople_Organizations.Sections.TeamInformation.TeamSkills, SkillToString());
		}

		private string SkillToString()
		{
			return string.Join(", ", Skills);
		}

		private static HashSet<string> StringToSkills(string value)
		{
			var parts = Convert.ToString(value).Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries);
			HashSet<string> result = new HashSet<string>();
			foreach (var part in parts)
			{
				result.Add(part.Trim());
			}

			return result;
		}
	}
}

