namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Properties
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;

	public class Property : InstanceBase<Property>
	{
		private static readonly Dictionary<SectionDefinitionID, Action<Property, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<Property, Section>>
		{
			[DomIds.SlcProperties.Sections.PropertyInfo.Id] = (obj, section) => obj.Info = new PropertyInfo(section),
			[DomIds.SlcProperties.Sections.Discrete.Id] = (obj, section) => obj.discretes.Add(new Discrete(section)),
			[DomIds.SlcProperties.Sections.Layout.Id] = (obj, section) => obj.Layout = new Layout(section),
		};

		private readonly List<Discrete> discretes = new List<Discrete>();

		public Property(PropertiesHandler propertiesHandler, DomInstance instance) : base(propertiesHandler, instance, DomIds.SlcProperties.Definitions.Property)
		{
		}

		public Property(PropertiesHandler propertiesHandler) : base(propertiesHandler, DomIds.SlcProperties.Definitions.Property)
		{
		}

		public Property(DomInstance instance) : base(instance, DomIds.SlcProperties.Definitions.Property)
		{
		}

		public string Name => Info?.Name;

		public PropertyInfo Info { get; private set; }

		public Layout Layout { get; private set; }

		public IReadOnlyCollection<Discrete> Discretes => discretes;

		protected override Dictionary<SectionDefinitionID, Action<Property, Section>> SectionMapping => InstanceSectionMapping;

		public void AddOrReplacePropertyInfo(PropertyInfo propertyInfo)
		{
			if (propertyInfo == null)
			{
				throw new ArgumentNullException(nameof(propertyInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			Info = propertyInfo;
			Instance.Sections.Add(propertyInfo.Section);
		}

		public void AddOrReplaceLayout(Layout layout)
		{
			if (layout == null)
			{
				throw new ArgumentNullException(nameof(layout));
			}

			if (Layout != null)
			{
				Instance.Sections.Remove(Layout.Section);
			}

			Layout = layout;
			Instance.Sections.Add(layout.Section);
		}

		public void AddDiscrete(Discrete discrete)
		{
			if (discrete == null)
			{
				throw new ArgumentNullException(nameof(discrete));
			}

			if (discretes.Exists(x => x.SectionId == discrete.SectionId))
			{
				return;
			}

			discretes.Add(discrete);
			Instance.Sections.Add(discrete.Section);
		}

		public void RemoveDiscrete(Discrete discrete)
		{
			if (discrete == null)
			{
				throw new ArgumentNullException(nameof(discrete));
			}

			RemoveDiscrete(discrete.SectionId);
		}

		public void RemoveDiscrete(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!discretes.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			discretes.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();

			foreach (var discrete in discretes)
			{
				discrete?.ApplyChanges();
			}

			Layout?.ApplyChanges();
		}
	}
}
