namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Properties
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;

	public class PropertyValues : InstanceBase<PropertyValues>
	{
		private static readonly Dictionary<SectionDefinitionID, Action<PropertyValues, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<PropertyValues, Section>>
		{
			[DomIds.SlcProperties.Sections.PropertyValueInfo.Id] = (obj, section) => obj.Info = new PropertyValueInfo(section),
			[DomIds.SlcProperties.Sections.PropertyValue.Id] = (obj, section) => obj.values.Add(new PropertyValue(section)),
		};

		private readonly List<PropertyValue> values = new List<PropertyValue>();

		public PropertyValues(PropertiesHandler propertiesHandler, DomInstance instance) : base(propertiesHandler, instance, DomIds.SlcProperties.Definitions.PropertyValues)
		{
		}

		public PropertyValues(PropertiesHandler propertiesHandler) : base(propertiesHandler, DomIds.SlcProperties.Definitions.PropertyValues)
		{
		}

		public PropertyValues(DomInstance instance) : base(instance, DomIds.SlcProperties.Definitions.PropertyValues)
		{
		}

		public PropertyValueInfo Info { get; private set; }

		public IReadOnlyCollection<PropertyValue> Values => values;

		protected override Dictionary<SectionDefinitionID, Action<PropertyValues, Section>> SectionMapping => InstanceSectionMapping;

		public void AddOrReplacePropertyInfo(PropertyValueInfo propertyInfo)
		{
			if (propertyInfo == null)
			{
				throw new ArgumentNullException(nameof(propertyInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			Info = propertyInfo;
			Instance.Sections.Add(propertyInfo.Section);
		}

		public void AddValue(PropertyValue value)
		{
			if (value == null)
			{
				throw new ArgumentNullException(nameof(value));
			}

			if (values.Exists(x => x.SectionId == value.SectionId))
			{
				return;
			}

			values.Add(value);
			Instance.Sections.Add(value.Section);
		}

		public void RemoveValue(PropertyValue value)
		{
			if (value == null)
			{
				throw new ArgumentNullException(nameof(value));
			}

			RemoveValue(value.SectionId);
		}

		public void RemoveValue(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!values.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			values.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public void ClearValues()
		{
			values.Clear();
			Instance.Sections.RemoveAll(x => x.SectionDefinitionID.Equals(DomIds.SlcProperties.Sections.PropertyValue.Id));
		}

		public PropertyValues Duplicate(string objectId, string subId = null)
		{
			var duplicatedInstance = CloneInstance();
			var clonedProps = new PropertyValues(ModuleHandler as PropertiesHandler, duplicatedInstance) { IsNew = true };
			var propertyValueInfo = new PropertyValueInfo
			{
				LinkedObjectID = objectId,
				Scope = clonedProps.Info.Scope,
			};

			if (subId != null)
			{
				propertyValueInfo.SubID = subId;
			}

			clonedProps.AddOrReplacePropertyInfo(propertyValueInfo);
			return clonedProps;
		}

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();

			foreach (var value in values)
			{
				value?.ApplyChanges();
			}
		}
	}
}

