namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Properties
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;

	public class PropertiesHandler : ModuleHandlerBase
	{
		public PropertiesHandler(IEngine engine) : base(engine, DomIds.SlcProperties.ModuleId)
		{
		}

		public PropertiesHandler(Net.IConnection connection) : base(connection, DomIds.SlcProperties.ModuleId)
		{
		}

		public PropertiesHandler(DomHelper domHelper) : base(domHelper, DomIds.SlcProperties.ModuleId)
		{
		}

		public IEnumerable<Property> GetAllProperties(string scope)
		{
			if (string.IsNullOrWhiteSpace(scope))
			{
				throw new ArgumentException("The scope has to be defined", nameof(scope));
			}

			var filter = DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcProperties.Sections.PropertyInfo.Scope).Equal(scope);
			return GetPropertyIterator(filter);
		}

		public Property CreateProperty(Property property)
		{
			if (property == null)
			{
				throw new ArgumentNullException(nameof(property));
			}

			property.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Create(property.Instance);

			return new Property(this, createdInstance);
		}

		public Property UpdateProperty(Property property)
		{
			if (property == null)
			{
				throw new ArgumentNullException(nameof(property));
			}

			property.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Update(property.Instance);

			return new Property(this, createdInstance);
		}

		public void DeleteProperty(Property property)
		{
			if (property == null)
			{
				throw new ArgumentNullException(nameof(property));
			}

			DomHelper.DomInstances.Delete(property.Instance);
		}

		public void DeleteProperties(IEnumerable<Property> properties)
		{
			if (properties == null || properties.Any(property => property == null))
			{
				throw new ArgumentNullException(nameof(properties), "The properties collection or one of its elements is null.");
			}

			DomHelper.DomInstances.BulkDelete(properties.Select(x => x.Instance));
		}

		public PropertyValues CreatePropertyValues(PropertyValues properties)
		{
			if (properties == null)
			{
				throw new ArgumentNullException(nameof(properties));
			}

			if (properties.Info == null)
			{
				throw new ArgumentNullException(nameof(properties), "PropertyValuesInfo can't be null");
			}

			if (string.IsNullOrWhiteSpace(properties.Info.LinkedObjectID))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(properties));
			}

			if (string.IsNullOrWhiteSpace(properties.Info.Scope))
			{
				throw new ArgumentException("Property Value has to be defined within a scope", nameof(properties));
			}

			properties.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Create(properties.Instance);

			return new PropertyValues(this, createdInstance);
		}

		public PropertyValues UpdatePropertyValues(PropertyValues properties)
		{
			if (properties == null)
			{
				throw new ArgumentNullException(nameof(properties));
			}

			if (string.IsNullOrWhiteSpace(properties.Info.LinkedObjectID))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(properties));
			}

			if (string.IsNullOrWhiteSpace(properties.Info.Scope))
			{
				throw new ArgumentException("Property Value has to be defined within a scope", nameof(properties));
			}

			properties.ApplyChanges();
			var updatedInstance = DomHelper.DomInstances.Update(properties.Instance);

			return new PropertyValues(this, updatedInstance);
		}

		public PropertyValues GetSingleOrDefaultPropertyValues(string scope, string id, string subId)
		{
			if (string.IsNullOrWhiteSpace(id))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(id));
			}

			if (string.IsNullOrWhiteSpace(scope))
			{
				throw new ArgumentException("The scope has to be defined", nameof(scope));
			}

			return GetPropertyValues(scope, id, subId).SingleOrDefault() ?? new PropertyValues(this);
		}

		public void DeletePropertyValues(PropertyValues properties)
		{
			if (properties == null)
			{
				throw new ArgumentNullException(nameof(properties));
			}

			DomHelper.DomInstances.Delete(properties.Instance);
		}

		public void DeletePropertyValues(string scope, string objectId, string subId = null)
		{
			if (string.IsNullOrWhiteSpace(objectId))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(objectId));
			}

			if (string.IsNullOrWhiteSpace(scope))
			{
				throw new ArgumentException("The scope has to be defined", nameof(scope));
			}

			foreach (var property in GetPropertyValues(scope, objectId, subId))
			{
				DeletePropertyValues(property);
			}
		}

		public void CopyPropertyValues(string scope, string objectIdA, string objectIdB, string subIdA = null, string subIdB = null)
		{
			if (string.IsNullOrWhiteSpace(objectIdA))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(objectIdA));
			}

			if (string.IsNullOrWhiteSpace(objectIdB))
			{
				throw new ArgumentException("Referenced Object ID can't be empty", nameof(objectIdB));
			}

			var propertiesToCopy = GetPropertyValues(scope, objectIdA, subIdA).SingleOrDefault();
			var existingProperties = GetPropertyValues(scope, objectIdB, subIdB).SingleOrDefault();
			if (propertiesToCopy == null || existingProperties != null)
			{
				DeletePropertyValues(scope, objectIdB, subIdB);
			}

			if (propertiesToCopy != null)
			{
				var copiedProps = propertiesToCopy.Duplicate(objectIdB, subIdB);
				CreatePropertyValues(copiedProps);
			}
		}

		public IEnumerable<PropertyValues> GetPropertyValues(string scope, string id, string subId = null)
		{
			var filter = DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcProperties.Sections.PropertyValueInfo.LinkedObjectID).Equal(id)
				.AND(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcProperties.Sections.PropertyValueInfo.Scope).Equal(scope));
			if (subId == null)
			{
				filter = filter.AND(DomInstanceExposers.FieldValues.KeyExists(DomIds.SlcProperties.Sections.PropertyValueInfo.SubID.Id.ToString()).Equal(false));
			}
			else if (subId != "*")
			{
				filter = filter.AND(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcProperties.Sections.PropertyValueInfo.SubID).Equal(subId));
			}
			else
			{
				// Return all items if * is used
			}

			return GetPropertyValuesIterator(filter);
		}

		private IEnumerable<PropertyValues> GetPropertyValuesIterator(FilterElement<DomInstance> filter)
		{
			foreach (var instance in DomHelper.DomInstances.Read(filter))
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcProperties.Definitions.PropertyValues.Id)
				{
					continue;
				}

				yield return new PropertyValues(this, instance);
			}
		}

		private IEnumerable<Property> GetPropertyIterator(FilterElement<DomInstance> filter)
		{
			foreach (var instance in DomHelper.DomInstances.Read(filter))
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcProperties.Definitions.Property.Id)
				{
					continue;
				}

				yield return new Property(this, instance);
			}
		}
	}
}
