namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Relationships
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;

	public class RelationshipHandler : ModuleHandlerBase
	{
		public static readonly string JobObjectTypeName = "Job";

		public RelationshipHandler(IEngine engine) : base(engine, DomIds.SlcRelationships.ModuleId)
		{
		}

		public RelationshipHandler(Net.IConnection connection) : base(connection, DomIds.SlcRelationships.ModuleId)
		{
		}

		public RelationshipHandler(DomHelper domHelper) : base(domHelper, DomIds.SlcRelationships.ModuleId)
		{
		}

		public IEnumerable<ObjectType> GetAllObjectTypes()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcRelationships.Definitions.ObjectTypes.Id);

			return GetObjectTypesIterator(filter);
		}

		public ObjectType GetObjectTypeByDomInstanceId(Guid id)
		{
			var filter = DomInstanceExposers.Id.Equal(id);

			return GetObjectTypesIterator(filter).SingleOrDefault();
		}

		public IEnumerable<ObjectType> GetObjectTypesByDomInstanceIds(List<Guid> ids)
		{
			var filter = new ORFilterElement<DomInstance>(ids.Select(id => DomInstanceExposers.Id.Equal(id)).ToArray());

			return GetObjectTypesIterator(filter);
		}

		public ObjectType GetJobObjectType()
		{
			return GetObjectTypeByName(JobObjectTypeName);
		}

		public ObjectType GetObjectTypeByName(string name)
		{
			return GetObjectTypesByNames(new List<string> { name }).SingleOrDefault();
		}

		public IEnumerable<ObjectType> GetObjectTypesByNames(List<string> names)
		{
			var filter = new ORFilterElement<DomInstance>(names.Select(name => DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.ObjectTypeInfo.ObjectName).Equal(name)).ToArray());

			return GetObjectTypesIterator(filter);
		}

		public ObjectType CreateObjectType(ObjectType objectType)
		{
			if (objectType == null)
			{
				throw new ArgumentNullException(nameof(objectType));
			}

			objectType.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Create(objectType.Instance);

			return new ObjectType(this, createdInstance);
		}

		public ObjectType UpdateObjectType(ObjectType objectType)
		{
			if (objectType == null)
			{
				throw new ArgumentNullException(nameof(objectType));
			}

			objectType.ApplyChanges();
			var updatedInstance = DomHelper.DomInstances.Update(objectType.Instance);

			return new ObjectType(this, updatedInstance);
		}

		public void DeleteObjectType(ObjectType objectType)
		{
			if (objectType == null)
			{
				throw new ArgumentNullException(nameof(objectType));
			}

			DomHelper.DomInstances.Delete(objectType.Instance);
		}

		public IEnumerable<Link> GetAllLinks()
		{
			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcRelationships.Definitions.Links.Id);

			return GetLinksIterator(filter);
		}

		public IEnumerable<Link> GetLinksByDomInstanceIds(List<Guid> ids)
		{
			var filter = new ORFilterElement<DomInstance>(ids.Select(id => DomInstanceExposers.Id.Equal(id)).ToArray());

			return GetLinksIterator(filter);
		}

		public Link GetLinkByDomInstanceId(Guid id)
		{
			var filter = DomInstanceExposers.Id.Equal(id);

			return GetLinksIterator(filter).SingleOrDefault();
		}

		public IEnumerable<Link> GetLinks(FilterElement<DomInstance> filter)
		{
			if (filter == null)
			{
				throw new ArgumentNullException(nameof(filter));
			}

			return GetLinksIterator(filter);
		}

		public IEnumerable<Link> GetLinksByParentObjectId(ObjectType parentObjectType, Guid parentObjectId)
		{
			return GetLinksByParentObjectId(parentObjectType, parentObjectId.ToString());
		}

		public IEnumerable<Link> GetLinksByParentObjectId(ObjectType parentObjectType, string parentObjectId)
		{
			var parentIdFilter = new ANDFilterElement<DomInstance>(
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectType).Equal(parentObjectType.InstanceId),
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectID).Equal(parentObjectId));

			return GetLinks(parentIdFilter);
		}

		public IEnumerable<Link> GetLinksByChildObjectId(ObjectType childObjectType, Guid childObjectId)
		{
			return GetLinksByChildObjectId(childObjectType, childObjectId.ToString());
		}

		public IEnumerable<Link> GetLinksByChildObjectId(ObjectType childObjectType, string childObjectId)
		{
			var childIdFilter = new ANDFilterElement<DomInstance>(
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectType).Equal(childObjectType.InstanceId),
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectID).Equal(childObjectId));

			return GetLinks(childIdFilter);
		}

		public IEnumerable<Link> GetLinksByLinkedObjectId(ObjectType objectType, Guid objectId)
		{
			return GetLinksByLinkedObjectId(objectType, objectId.ToString());
		}

		public IEnumerable<Link> GetLinksByLinkedObjectId(ObjectType objectType, string objectId)
		{
			var parentIdFilter = new ANDFilterElement<DomInstance>(
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectType).Equal(objectType.InstanceId),
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectID).Equal(objectId));

			var childIdFilter = new ANDFilterElement<DomInstance>(
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectType).Equal(objectType.InstanceId),
				DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectID).Equal(objectId));

			var filter = new ORFilterElement<DomInstance>(parentIdFilter, childIdFilter);

			return GetLinks(filter);
		}

		public Link CreateLink(Link link)
		{
			if (link == null)
			{
				throw new ArgumentNullException(nameof(link));
			}

			link.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Create(link.Instance);

			return new Link(this, createdInstance);
		}

		public Link UpdateLink(Link link)
		{
			if (link == null)
			{
				throw new ArgumentNullException(nameof(link));
			}

			link.ApplyChanges();
			var updatedInstance = DomHelper.DomInstances.Update(link.Instance);

			return new Link(this, updatedInstance);
		}

		public void DeleteLink(Link link)
		{
			if (link == null)
			{
				throw new ArgumentNullException(nameof(link));
			}

			DomHelper.DomInstances.Delete(link.Instance);
		}

		private IEnumerable<ObjectType> GetObjectTypesIterator(FilterElement<DomInstance> filter)
		{
			foreach (var instance in DomHelper.DomInstances.Read(filter))
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcRelationships.Definitions.ObjectTypes.Id)
				{
					continue;
				}

				yield return new ObjectType(this, instance);
			}
		}

		private IEnumerable<Link> GetLinksIterator(FilterElement<DomInstance> filter)
		{
			foreach (var instance in DomHelper.DomInstances.Read(filter))
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcRelationships.Definitions.Links.Id)
				{
					continue;
				}

				yield return new Link(this, instance);
			}
		}
	}
}
