namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Relationships
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Sections;

	public class LinkInfo : SectionBase<LinkInfo>
	{
		private static readonly Dictionary<FieldDescriptorID, Action<LinkInfo, object>> SectionFieldMapping = new Dictionary<FieldDescriptorID, Action<LinkInfo, object>>
		{
			[DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectType] = (obj, value) => obj.ChildObjectTypeId = (Guid)value,
			[DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectID] = (obj, value) => obj.ChildObjectId = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectName] = (obj, value) => obj.ChildObjectName = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ChildURL] = (obj, value) => obj.ChildURL = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ChildOrder] = (obj, value) => obj.ChildOrder = Convert.ToInt64(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectType] = (obj, value) => obj.ParentObjectTypeId = (Guid)value,
			[DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectID] = (obj, value) => obj.ParentObjectId = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectName] = (obj, value) => obj.ParentObjectName = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ParentURL] = (obj, value) => obj.ParentURL = Convert.ToString(value),
			[DomIds.SlcRelationships.Sections.LinkInfo.ParentOrder] = (obj, value) => obj.ParentOrder = Convert.ToInt64(value),
		};

		public LinkInfo() : base(DomIds.SlcRelationships.Sections.LinkInfo.Id)
		{
		}

		internal LinkInfo(Section section) : base(section)
		{
		}

		public Guid ChildObjectTypeId { get; set; }

		public string ChildObjectId { get; set; }

		public string ChildObjectName { get; set; }

		public string ChildURL { get; set; }

		public Int64 ChildOrder { get; set; }

		public Guid ParentObjectTypeId { get; set; }

		public string ParentObjectId { get; set; }

		public string ParentObjectName { get; set; }

		public string ParentURL { get; set; }

		public Int64 ParentOrder { get; set; }

		protected override Dictionary<FieldDescriptorID, Action<LinkInfo, object>> FieldMapping => SectionFieldMapping;

		internal override void ApplyChanges()
		{
			ApplyChildObjectTypeId();
			ApplyChildObjectId();
			ApplyChildObjectName();
			ApplyChildURL();
			ApplyChildOrder();
			ApplyParentObjectType();
			ApplyParentObjectId();
			ApplyParentObjectName();
			ApplyParentURL();
			ApplyParentOrder();
		}

		private void ApplyChildObjectTypeId()
		{
			if (ChildObjectTypeId != Guid.Empty)
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectType, ChildObjectTypeId);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectType);
			}
		}

		private void ApplyChildObjectId()
		{
			if (!string.IsNullOrEmpty(ChildObjectId))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectID, ChildObjectId);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectID);
			}
		}

		private void ApplyChildObjectName()
		{
			if (!string.IsNullOrEmpty(ChildObjectName))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectName, ChildObjectName);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ChildObjectName);
			}
		}

		private void ApplyChildURL()
		{
			if (!string.IsNullOrEmpty(ChildURL))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ChildURL, ChildURL);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ChildURL);
			}
		}

		private void ApplyChildOrder()
		{
			Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ChildOrder, ChildOrder);
		}

		private void ApplyParentObjectType()
		{
			if (ParentObjectTypeId != Guid.Empty)
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectType, ParentObjectTypeId);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectType);
			}
		}

		private void ApplyParentObjectId()
		{
			if (!string.IsNullOrEmpty(ParentObjectId))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectID, ParentObjectId);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectID);
			}
		}

		private void ApplyParentObjectName()
		{
			if (!string.IsNullOrEmpty(ParentObjectName))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectName, ParentObjectName);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcRelationships.Sections.LinkInfo.ParentObjectName);
			}
		}

		private void ApplyParentURL()
		{
			if (!string.IsNullOrEmpty(ParentURL))
			{
				Section.AddOrUpdateValue(DomIds.SlcRelationships.Sections.LinkInfo.ParentURL, ParentURL);
