namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling;

	public class Resource : InstanceBase<Resource>, IValidatable<Resource>
	{
		private static readonly Dictionary<SectionDefinitionID, Action<Resource, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<Resource, Section>>
		{
			[DomIds.SlcResource_Studio.Sections.ResourceInfo.Id] = (obj, section) => obj.Info = new ResourceInfo(section),
			[DomIds.SlcResource_Studio.Sections.ResourceInternalProperties.Id] = (obj, section) => obj.InternalProperties = new ResourceInternalProperties(section),
			[DomIds.SlcResource_Studio.Sections.ResourceCapacities.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count == 2)
				{
					obj.capacities.Add(new ResourceCapacity(section));
				}
			},
			[DomIds.SlcResource_Studio.Sections.ResourceCapabilities.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count >= 2)
				{
					obj.capabilities.Add(new ResourceCapability(section));
				}
			},
			[DomIds.SlcResource_Studio.Sections.ResourceProperties.Id] = (obj, section) => obj.properties.Add(new ResourceProperty(section)),
			[DomIds.SlcResource_Studio.Sections.ExternalMetadata.Id] = (obj, section) => obj.ExternalMetadata = new ExternalMetadata(section),
			[DomIds.SlcResource_Studio.Sections.ResourceOther.Id] = (obj, section) => obj.Other = new ResourceOther(section),
			[DomIds.SlcResource_Studio.Sections.ResourceControl.Id] = (obj, section) => obj.Control = new ResourceControl(section),
			[DomIds.SlcResource_Studio.Sections.Errors.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count <= 0)
				{
					return;
				}

				var error = new Errors(section);

				if (!String.IsNullOrEmpty(error.ErrorCode))
				{
					obj.errors[error.ErrorCode] = error;
				}
			},
		};

		private readonly List<ResourceCapacity> capacities = new List<ResourceCapacity>();

		private readonly List<ResourceCapability> capabilities = new List<ResourceCapability>();

		private readonly List<ResourceProperty> properties = new List<ResourceProperty>();

		private readonly Dictionary<string, Errors> errors = new Dictionary<string, Errors>();

		public Resource(ResourceStudioHandler resourceStudioHandler, DomInstance instance) : base(resourceStudioHandler, instance, DomIds.SlcResource_Studio.Definitions.Resource)
		{
		}

		public Resource(ResourceStudioHandler resourceStudioHandler) : base(resourceStudioHandler, DomIds.SlcResource_Studio.Definitions.Resource)
		{
		}

		public Resource(ResourceStudioHandler resourceStudioHandler, string statusId) : base(resourceStudioHandler, DomIds.SlcResource_Studio.Definitions.Resource)
		{
			if (string.IsNullOrEmpty(statusId))
			{
				throw new ArgumentNullException(nameof(statusId));
			}

			VerifyNewJobStatus(statusId);

			Instance.StatusId = statusId;
		}

		public ResourceInfo Info { get; private set; }

		public ResourceInternalProperties InternalProperties { get; private set; }

		public ExternalMetadata ExternalMetadata { get; private set; }

		public ResourceOther Other { get; private set; }

		public ResourceControl Control { get; private set; }

		public IReadOnlyCollection<ResourceCapacity> Capacities => capacities;

		public IReadOnlyCollection<ResourceCapability> Capabilities => capabilities;

		public IReadOnlyCollection<ResourceProperty> Properties => properties;

		public IReadOnlyDictionary<string, Errors> Errors => errors;

		public string Name => Info.Name;

		protected override Dictionary<SectionDefinitionID, Action<Resource, Section>> SectionMapping => InstanceSectionMapping;

		public void AddOrReplaceResourceInfo(ResourceInfo resourceInfo)
		{
			if (resourceInfo == null)
			{
				throw new ArgumentNullException(nameof(resourceInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			Info = resourceInfo;
			Instance.Sections.Add(resourceInfo.Section);
		}

		public void AddOrReplaceInternalProperties(ResourceInternalProperties internalProperties)
		{
			if (internalProperties == null)
			{
				throw new ArgumentNullException(nameof(internalProperties));
			}

			if (InternalProperties != null)
			{
				Instance.Sections.Remove(InternalProperties.Section);
			}

			InternalProperties = internalProperties;
			Instance.Sections.Add(internalProperties.Section);
		}

		public void AddOrReplaceExternalMetadata(ExternalMetadata externalMetadata)
		{
			if (externalMetadata == null)
			{
				throw new ArgumentNullException(nameof(externalMetadata));
			}

			if (ExternalMetadata != null)
			{
				Instance.Sections.Remove(ExternalMetadata.Section);
			}

			ExternalMetadata = externalMetadata;
			Instance.Sections.Add(externalMetadata.Section);
		}

		public void AddOrReplaceResourceOther(ResourceOther resourceOther)
		{
			if (resourceOther == null)
			{
				throw new ArgumentNullException(nameof(resourceOther));
			}

			if (Other != null)
			{
				Instance.Sections.Remove(Other.Section);
