		public Resource Duplicate()
		{
			var duplicatedInstance = CloneInstance();

			return new Resource(ModuleHandler as ResourceStudioHandler, duplicatedInstance) { IsNew = true };
		}

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();
			InternalProperties?.ApplyChanges();
			ExternalMetadata?.ApplyChanges();
			Other?.ApplyChanges();

			foreach (var capability in capabilities)
			{
				capability.ApplyChanges();
			}

			foreach (var capacity in capacities)
			{
				capacity.ApplyChanges();
			}

			foreach (var property in properties)
			{
				property.ApplyChanges();
			}

			HandleErrorChanges();
		}

		public override string ToString()
		{
			return $"Resource: {Name}";
		}

		private void VerifyNewJobStatus(string statusId)
		{
			var domStatus = GetDomStatuses().SingleOrDefault(x => x.Id == statusId);
			if (domStatus == null)
			{
				throw new InvalidOperationException($"Dom status with ID {StatusId} does not exist.");
			}
		}

		private void HandleErrorChanges()
		{
			if (errors.Count == 0)
			{
				var emptyErrorSection = Instance.Sections.SingleOrDefault(x => x.SectionDefinitionID.Id == DomIds.SlcResource_Studio.Sections.Errors.Id.Id && x.FieldValues.Count == 0);
				if (emptyErrorSection != null)
				{
					return;
				}

				Instance.Sections.Add(new Section(DomIds.SlcResource_Studio.Sections.Errors.Id));
			}
			else
			{
				foreach (var error in errors.Values)
				{
					error.ApplyChanges();
				}

				var emptyErrorSections = Instance.Sections.Where(x => x.SectionDefinitionID.Id == DomIds.SlcResource_Studio.Sections.Errors.Id.Id && x.FieldValues.Count == 0).ToList();
				if (emptyErrorSections.Count > 0)
				{
					emptyErrorSections.ForEach(x => Instance.Sections.RemoveAll(y => y.ID.Id == x.ID.Id));
				}
			}
		}

		#region IValidatable

		IReadOnlyDictionary<string, IError> IValidatable<Resource>.Errors => errors.ToDictionary(x => x.Key, x => (IError)x.Value);

		public bool HasErrors => errors.Count > 0;

		public ValidatorResults<Resource> Validate(IValidator<Resource> validator)
		{
			if (validator == null)
			{
				throw new ArgumentNullException(nameof(validator));
			}

			return validator.Validate(this);
		}

		public IError SetError(string errorCode, string message)
		{
			if (String.IsNullOrWhiteSpace(errorCode))
			{
				throw new ArgumentException("error code can't be empty", nameof(errorCode));
			}

			if (String.IsNullOrWhiteSpace(message))
			{
				throw new ArgumentException("error message can't be empty", nameof(message));
			}

			if (errors.TryGetValue(errorCode, out var error))
			{
				error.Message = message;
			}
			else
			{
				error = new Errors
				{
					ErrorCode = errorCode,
					Message = message,
				};

				errors[errorCode] = error;
				Instance.Sections.Add(error.Section);
			}

			return error;
		}

		public void SetError(IError error)
		{
			if (error == null)
			{
				throw new ArgumentNullException(nameof(error));
			}

			SetError(error.ErrorCode, error.Message);
		}

		public bool ClearError(string errorCode)
		{
			if (String.IsNullOrWhiteSpace(errorCode))
			{
				throw new ArgumentException("error code can't be empty", nameof(errorCode));
			}

			if (errors.TryGetValue(errorCode, out Errors error))
			{
				if (error.SectionId == Guid.Empty)
				{
					throw new InvalidOperationException($"error name '{errorCode}' did not have a section ID linked");
				}

				Instance.Sections.RemoveAll(x => x.ID.Id == error.SectionId);
				errors.Remove(errorCode);
				return true;
			}

			return false;
		}

		public bool ClearError(IError error)
		{
			if (error == null)
			{
				throw new ArgumentNullException(nameof(error));
			}

			return ClearError(error.ErrorCode);
		}

		#endregion
	}
}

