	{
		private static readonly Dictionary<SectionDefinitionID, Action<ResourcePool, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<ResourcePool, Section>>
		{
			[DomIds.SlcResource_Studio.Sections.ResourcePoolInfo.Id] = (obj, section) => obj.Info = new ResourcePoolInfo(section),
			[DomIds.SlcResource_Studio.Sections.ResourcePoolInternalProperties.Id] = (obj, section) => obj.InternalProperties = new ResourcePoolInternalProperties(section),
			[DomIds.SlcResource_Studio.Sections.ResourcePoolCapabilities.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count >= 2)
				{
					obj.capabilities.Add(new ResourcePoolCapability(section));
				}
			},
			[DomIds.SlcResource_Studio.Sections.ResourcePoolLinks.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count > 0)
				{
					obj.resourcePoolLinks.Add(new ResourcePoolLinks(section));
				}
			},
			[DomIds.SlcResource_Studio.Sections.ExternalMetadata.Id] = (obj, section) => obj.ExternalMetadata = new ExternalMetadata(section),
			[DomIds.SlcResource_Studio.Sections.ResourcePoolOther.Id] = (obj, section) => obj.Other = new ResourcePoolOther(section),
			[DomIds.SlcResource_Studio.Sections.ConfigurationInfo.Id] = (obj, section) => obj.ConfigurationInfo = new ConfigurationInfo(section),
			[DomIds.SlcResource_Studio.Sections.Errors.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count <= 0)
				{
					return;
				}

				var error = new Errors(section);

				if (!String.IsNullOrEmpty(error.ErrorCode))
				{
					obj.errors[error.ErrorCode] = error;
				}
			},
		};

