//---------------------------------
// DOM\Applications\Resource Studio\Handlers\CapabilitiesHandler.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Utils.MediaOps.Common.Utils;

	public class CapabilitiesHandler
	{
		#region Fields
		private readonly ResourceStudioHandler resourceStudioHandler;
		private readonly ILogger logger;

		private readonly Dictionary<Guid, ResourcePool> domResourcePoolsById = new Dictionary<Guid, ResourcePool>();

		private readonly Dictionary<Guid, IReadOnlyCollection<IConfiguredCapability>> capabilitiesByDomResourcePoolId = new Dictionary<Guid, IReadOnlyCollection<IConfiguredCapability>>();
		#endregion

		public CapabilitiesHandler(ResourceStudioHandler resourceStudioHandler, ILogger logger = null)
		{
			this.resourceStudioHandler = resourceStudioHandler ?? throw new ArgumentNullException(nameof(resourceStudioHandler));
			this.logger = logger;
		}

		#region Methods
		public IReadOnlyCollection<ResourceCapabilityChanges> GetCoreResourceCapabilitiesChanges(ResourcePool previous, ResourcePool current)
		{
			if (previous == null)
			{
				throw new ArgumentNullException(nameof(previous));
			}

			if (current == null)
			{
				throw new ArgumentNullException(nameof(current));
			}

			if (previous.InstanceId != current.InstanceId)
			{
				throw new NotSupportedException("It is not allowed to compare two different resource pools.");
			}

			var resourceChanges = new List<ResourceCapabilityChanges>();
			foreach (var domResource in resourceStudioHandler.GetResourcesByPool(previous))
			{
				var assignedCapabilities = GetConfiguredCapabilities(domResource, previous);
				var capabilitiesToAssign = GetConfiguredCapabilities(domResource, current);

				resourceChanges.Add(GetResourceCapabilityChanges(domResource, assignedCapabilities, capabilitiesToAssign));
			}

			return resourceChanges;
		}

		public ResourceCapabilityChanges GetCoreResourceCapabilitiesChanges(Resource previous, Resource current)
		{
			if (previous == null)
			{
				throw new ArgumentNullException(nameof(previous));
			}

			if (current == null)
			{
				throw new ArgumentNullException(nameof(current));
			}

			if (previous.InstanceId != current.InstanceId)
			{
				throw new NotSupportedException("It is not allowed to compare two different resources.");
			}

			var assignedCapabilities = GetConfiguredCapabilities(previous);
			var capabilitiesToAssign = GetConfiguredCapabilities(current);

			return GetResourceCapabilityChanges(current, assignedCapabilities, capabilitiesToAssign);
		}

		public IReadOnlyCollection<IConfiguredCapability> GetConfiguredCapabilities(Resource domResource)
		{
			var poolCapabilitiesByPoolIds = GetPoolCapabilitiesByPoolIds(domResource.InternalProperties.PoolIds);
			var capabilitiesToMerge = new List<IConfiguredCapability>(domResource.Capabilities);

			logger?.Debug(this, $"Capabilities from Resource: {String.Join(", ", capabilitiesToMerge.Select(y => $"PP {y.ProfileParameterId}, values: {y.StringValue}"))}");

			foreach (var poolCapabilities in poolCapabilitiesByPoolIds.Values)
			{
				logger?.Debug(this, $"Capabilities inherited from Resource Pool: {String.Join(", ", poolCapabilities.Select(y => $"PP {y.ProfileParameterId}, values: {y.StringValue}"))}");
				capabilitiesToMerge.AddRange(poolCapabilities);
			}

			return MergeCapabilities(capabilitiesToMerge);
		}

		public IReadOnlyCollection<IConfiguredCapability> GetConfiguredCapabilities(Resource domResource, ResourcePool domResourcePool)
		{
			var poolCapabilitiesByPoolIds = GetPoolCapabilitiesByPoolIds(domResource.InternalProperties.PoolIds);
			var capabilitiesToMerge = new List<IConfiguredCapability>(domResource.Capabilities);

			logger?.Debug(this, $"Capabilities from Resource: {String.Join(", ", capabilitiesToMerge.Select(y => $"PP {y.ProfileParameterId}, values: {y.StringValue}"))}");

			foreach (var poolId in poolCapabilitiesByPoolIds.Keys)
			{
				IReadOnlyCollection<IConfiguredCapability> poolCapabilities;
				if (domResourcePool.InstanceId.Equals(poolId))
				{
					poolCapabilities = domResourcePool.Capabilities.ToList();
				}
				else
				{
					poolCapabilities = poolCapabilitiesByPoolIds[poolId];
				}

				logger?.Debug(this, $"Capabilities inherited from Resource Pool: {String.Join(", ", poolCapabilities.Select(y => $"PP {y.ProfileParameterId}, values: {y.StringValue}"))}");
				capabilitiesToMerge.AddRange(poolCapabilities);
			}

			return MergeCapabilities(capabilitiesToMerge);
		}

		public IReadOnlyCollection<IConfiguredCapability> GetConfiguredPoolCapabilities(Resource domResource)
		{
			var poolCapabilitiesByPoolIds = GetPoolCapabilitiesByPoolIds(domResource.InternalProperties.PoolIds);

			return MergeCapabilities(poolCapabilitiesByPoolIds.Values.SelectMany(x => x));
		}

		private static IReadOnlyCollection<IConfiguredCapability> MergeCapabilities(IEnumerable<IConfiguredCapability> capabilities)
		{
			var configuredCapabilitiesById = new Dictionary<Guid, ConfiguredCapability>();
			if (capabilities == null)
			{
				return configuredCapabilitiesById.Values;
			}

			foreach (var capability in capabilities)
			{
				if (capability.StringValue == null)
				{
					continue;
				}

				if (!configuredCapabilitiesById.TryGetValue(capability.ProfileParameterId, out var configuredCapability))
				{
					configuredCapability = new ConfiguredCapability(capability.ProfileParameterId);

					configuredCapabilitiesById.Add(capability.ProfileParameterId, configuredCapability);
				}

				foreach (var valueToAdd in capability.StringValue.Split(';'))
				{
					configuredCapability.Values.Add(valueToAdd);
				}
			}

			return configuredCapabilitiesById.Values;
		}

		private ResourceCapabilityChanges GetResourceCapabilityChanges(Resource resource, IReadOnlyCollection<IConfiguredCapability> assignedCapabilities, IReadOnlyCollection<IConfiguredCapability> capabilitiesToAssign)
		{
			var changes = new ResourceCapabilityChanges
			{
				Resource = resource,
			};

			var assignedCapabilitiesDict = assignedCapabilities.ToDictionary(x => x.ProfileParameterId);
			var capabilitiesToAssignDict = capabilitiesToAssign.ToDictionary(x => x.ProfileParameterId);

			foreach (var capabilityToAssign in capabilitiesToAssign)
			{
				if (!assignedCapabilitiesDict.TryGetValue(capabilityToAssign.ProfileParameterId, out var assignedCapability))
				{
					logger?.Debug(this, $"Capability {capabilityToAssign.ProfileParameterId} has been added with value '{capabilityToAssign.StringValue}'");
					changes.AddedOrUpdated.Add(capabilityToAssign);
					continue;
				}

				if (!String.Equals(capabilityToAssign.StringValue, assignedCapability.StringValue))
				{
					logger?.Debug(this, $"Capability {capabilityToAssign.ProfileParameterId} has been updated from '{assignedCapability.StringValue}' to '{capabilityToAssign.StringValue}'");
					changes.AddedOrUpdated.Add(capabilityToAssign);
					continue;
				}
			}

			foreach (var assignedCapability in assignedCapabilities)
			{
				if (!capabilitiesToAssignDict.ContainsKey(assignedCapability.ProfileParameterId))
				{
					logger?.Debug(this, $"Capability {assignedCapability.ProfileParameterId} has been removed");
					changes.Removed.Add(assignedCapability.ProfileParameterId);
				}
			}

			return changes;
		}

		private IDictionary<Guid, IReadOnlyCollection<IConfiguredCapability>> GetPoolCapabilitiesByPoolIds(IEnumerable<Guid> poolIds)
		{
			if (poolIds == null)
			{
				throw new ArgumentNullException(nameof(poolIds));
			}

			var result = new Dictionary<Guid, IReadOnlyCollection<IConfiguredCapability>>();
			var idsToRetrieve = new List<Guid>();

			foreach (var id in poolIds.Where(x => x != Guid.Empty).Distinct())
			{
				if (capabilitiesByDomResourcePoolId.TryGetValue(id, out var poolCapabilities))
				{
					result[id] = poolCapabilities;
				}
				else
				{
					idsToRetrieve.Add(id);
				}
			}

			if (idsToRetrieve.Count > 0)
			{
				foreach (var domResourcePool in GetResourcePoolsByIds(idsToRetrieve).Values)
				{
					var poolCapabilities = domResourcePool.Capabilities.OfType<IConfiguredCapability>().ToList();
					result[domResourcePool.InstanceId] = poolCapabilities;
					capabilitiesByDomResourcePoolId[domResourcePool.InstanceId] = poolCapabilities;
				}
			}

			return result;
		}

		private IDictionary<Guid, ResourcePool> GetResourcePoolsByIds(IEnumerable<Guid> poolIds)
		{
			if (poolIds == null)
			{
				throw new ArgumentNullException(nameof(poolIds));
			}

			var result = new Dictionary<Guid, ResourcePool>();
			var idsToRetrieve = new List<Guid>();

			foreach (var id in poolIds.Where(x => x != Guid.Empty).Distinct())
			{
				if (domResourcePoolsById.TryGetValue(id, out var domResourcePool))
				{
					result[id] = domResourcePool;
				}
				else
				{
					idsToRetrieve.Add(id);
				}
			}

			if (idsToRetrieve.Count > 0)
			{
				foreach (var domResourcePool in resourceStudioHandler.GetResourcePoolsByDomInstanceIds(idsToRetrieve))
				{
					result[domResourcePool.InstanceId] = domResourcePool;
					domResourcePoolsById[domResourcePool.InstanceId] = domResourcePool;
				}
			}

			return result;
		}
		#endregion
	}
}

