namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	public class ConfiguredCapability : IConfiguredCapability
	{
		public ConfiguredCapability(Guid profileParameterId)
		{
			if (profileParameterId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(profileParameterId));
			}

			ProfileParameterId = profileParameterId;
		}

		public Guid ProfileParameterId { get; private set; }

		public string StringValue => String.Join(";", Values.OrderBy(x => x));

		public HashSet<String> Values { get; } = new HashSet<string>();

		public override string ToString()
		{
			return StringValue;
		}

		public override bool Equals(object obj)
		{
			if (!(obj is ConfiguredCapability other))
			{
				return false;
			}

			if (!ProfileParameterId.Equals(other.ProfileParameterId))
			{
				return false;
			}

			return String.Equals(StringValue, other.StringValue);
		}

		public override int GetHashCode()
		{
			unchecked
			{
				int hash = 17;
				hash = (hash * 23) + ProfileParameterId.GetHashCode();
				hash = (hash * 23) + (StringValue != null ? StringValue.GetHashCode() : 0);
				return hash;
			}
		}
	}
}

