		private IEnumerable<Resource> GetResourcesIterator(FilterElement<DomInstance> filter)
		{
			// Watch out not use .ToList() (or any action that iterates the full collection) here as this will degrade performance drastically.
			return GetResourcesIterator(DomHelper.DomInstances.ReadPaged(filter).Flatten());
		}

		private IEnumerable<Resource> GetResourcesIterator(IEnumerable<DomInstance> instances)
		{
			foreach (var instance in instances)
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcResource_Studio.Definitions.Resource.Id)
				{
					continue;
				}

				yield return new Resource(this, instance);
			}
		}

		private IEnumerable<ResourcePool> GetResourcePoolsIterator(FilterElement<DomInstance> filter)
		{
			return GetResourcePoolsIterator(DomHelper.DomInstances.ReadPaged(filter).SelectMany(x => x));
		}

