namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Net.Sections;

	public class ConfigurationInfo : SectionBase<ConfigurationInfo>
	{
		private static readonly Dictionary<FieldDescriptorID, Action<ConfigurationInfo, object>> SectionFieldMapping = new Dictionary<FieldDescriptorID, Action<ConfigurationInfo, object>>
		{
			[DomIds.SlcResource_Studio.Sections.ConfigurationInfo.ProfileDefinitionID] = (obj, value) => obj.ProfileDefinitionId = Convert.ToString(value),
		};

		public ConfigurationInfo() : base(DomIds.SlcResource_Studio.Sections.ConfigurationInfo.Id)
		{
		}

		internal ConfigurationInfo(Section section) : base(section)
		{
		}

		public string ProfileDefinitionId { get; set; }

		protected override Dictionary<FieldDescriptorID, Action<ConfigurationInfo, object>> FieldMapping => SectionFieldMapping;

		internal override void ApplyChanges()
		{
			if (!string.IsNullOrEmpty(ProfileDefinitionId))
			{
				Section.AddOrUpdateValue(DomIds.SlcResource_Studio.Sections.ConfigurationInfo.ProfileDefinitionID, ProfileDefinitionId);
			}
			else
			{
				Section.RemoveFieldValueById(DomIds.SlcResource_Studio.Sections.ConfigurationInfo.ProfileDefinitionID);
			}
		}
	}
}

