namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Net.Profiles;
	using Skyline.DataMiner.Net.Sections;

	public class Configuration : InstanceBase<Configuration>
	{
		private static readonly Dictionary<SectionDefinitionID, Action<Configuration, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<Configuration, Section>>
		{
			[DomIds.SlcWorkflow.Sections.ProfileParameterValues.Id] = (obj, section) => obj.profileParameterValues.Add(new ProfileParameterValue(section)),
		};

		private readonly List<ProfileParameterValue> profileParameterValues = new List<ProfileParameterValue>();

		public Configuration(WorkflowHandler workflowHandler, DomInstance instance) : base(workflowHandler, instance, DomIds.SlcWorkflow.Definitions.Configuration)
		{
		}

		public Configuration(WorkflowHandler workflowHandler) : base(workflowHandler, DomIds.SlcWorkflow.Definitions.Configuration)
		{
		}

		public IReadOnlyCollection<ProfileParameterValue> ProfileParameterValues => profileParameterValues;

		protected override Dictionary<SectionDefinitionID, Action<Configuration, Section>> SectionMapping => InstanceSectionMapping;

		public void AddProfileParameterValue(ProfileParameterValue profileParameterValue)
		{
			if (profileParameterValue == null)
			{
				throw new ArgumentNullException(nameof(profileParameterValue));
			}

			if (profileParameterValues.Exists(x => x.SectionId == profileParameterValue.SectionId))
			{
				return;
			}

			profileParameterValues.Add(profileParameterValue);
			Instance.Sections.Add(profileParameterValue.Section);
		}

		public void AddOrUpdateParameterValues(IEnumerable<ProfileParameterValue> profileParamValues)
		{
			foreach (var profileParamValue in profileParamValues)
			{
				AddOrUpdateParameterValue(profileParamValue);
			}
		}

		public void AddOrUpdateParameterValue(ProfileParameterValue profileParamValue)
		{
			if (profileParamValue == null)
			{
				throw new ArgumentNullException(nameof(profileParamValue));
			}

			var existingValue = profileParameterValues.Find(x => x.ProfileParameterId == profileParamValue.ProfileParameterId);
			if (existingValue != null)
			{
				existingValue.StringValue = profileParamValue.StringValue;
				existingValue.DoubleValue = profileParamValue.DoubleValue;
				existingValue.ReferenceId = profileParamValue.ReferenceId;
			}
			else
			{
				AddProfileParameterValue(profileParamValue);
			}
		}

		public void RemoveProfileParameterValuesById(IEnumerable<Guid> ids)
		{
			foreach (var id in ids)
			{
				var existingValue = profileParameterValues.Find(x => x.ProfileParameterId == id);
				if (existingValue != null)
				{
					RemoveProfileParameterValue(existingValue.SectionId);
				}
			}
		}

		public void RemoveProfileParameterValue(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!profileParameterValues.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			profileParameterValues.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public void RemoveProfileParameterValue(ProfileParameterValue profileParameterValue)
		{
			if (profileParameterValue == null)
			{
				throw new ArgumentNullException(nameof(profileParameterValue));
			}

			this.RemoveProfileParameterValue(profileParameterValue.SectionId);
		}

		public Configuration Duplicate()
		{
			var duplicatedInstance = CloneInstance();

			return new Configuration(ModuleHandler as WorkflowHandler, duplicatedInstance) { IsNew = true };
		}

		public Configuration GetClone()
		{
			ApplyChanges();

			var clonedInstance = Instance.Clone() as DomInstance;

			return new Configuration(ModuleHandler as WorkflowHandler, clonedInstance);
		}

		public override void ApplyChanges()
		{
			foreach (var profileParameterValue in profileParameterValues)
			{
				profileParameterValue.ApplyChanges();
			}
		}

		public ConfigurationStatus VerifyConfiguration(ProfileHelper profileHelper)
		{
			var filter = new ORFilterElement<Skyline.DataMiner.Net.Profiles.Parameter>(ProfileParameterValues.Select(x => Skyline.DataMiner.Net.Profiles.ParameterExposers.ID.Equal(x.ProfileParameterId)).ToArray());
			var parameters = profileHelper.ProfileParameters.Read(filter).ToList();

			var mandatoryParametersById = parameters.Where(x => x.IsOptional.HasValue && !x.IsOptional.Value).ToDictionary(x => x.ID);
			if (mandatoryParametersById.Keys.Any(mandatoryId => ProfileParameterValues.Any(x => x.ProfileParameterId == mandatoryId && !x.HasValue)))
			{
				return ConfigurationStatus.MandatoryValuesMissing;
			}
			else if (parameters.Count != ProfileParameterValues.Count(x => x.HasValue))
			{
				return ConfigurationStatus.NonMandatoryValuesMissing;
			}
			else
			{
				return ConfigurationStatus.AllValuesProvided;
			}
		}
	}
}

