namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;

	public class JobLite : InstanceBase<JobLite>
	{
		private static readonly Dictionary<SectionDefinitionID, Action<JobLite, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<JobLite, Section>>
		{
			[DomIds.SlcWorkflow.Sections.JobInfo.Id] = (obj, section) => obj.Info = new JobInfo(section),
			[DomIds.SlcWorkflow.Sections.CostingAndBilling.Id] = (obj, section) => obj.CostingAndBilling = new CostingAndBilling(section),
			[DomIds.SlcWorkflow.Sections.Errors.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count <= 0)
				{
					return;
				}

				var error = new Errors(section);

				if (!String.IsNullOrEmpty(error.ErrorCode))
				{
					obj.errors[error.ErrorCode] = error;
				}
			},
			[DomIds.SlcWorkflow.Sections.JobLiteMetadata.Id] = (obj, section) => obj.Metadata = new JobLiteMetadata(section),
		};

		private readonly Dictionary<string, Errors> errors = new Dictionary<string, Errors>();

		public JobLite(WorkflowHandler workflowHandler, DomInstance instance) : base(workflowHandler, instance, DomIds.SlcWorkflow.Definitions.JobsLite)
		{
		}

		public JobLite(WorkflowHandler workflowHandler) : base(workflowHandler, DomIds.SlcWorkflow.Definitions.JobsLite)
		{
		}

		public JobInfo Info { get; private set; }

		public IReadOnlyDictionary<string, Errors> Errors => errors;

		public CostingAndBilling CostingAndBilling { get; private set; }

		public JobLiteMetadata Metadata { get; private set; }

		public bool HasErrors => errors.Count > 0;

		protected override Dictionary<SectionDefinitionID, Action<JobLite, Section>> SectionMapping => InstanceSectionMapping;

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();

			CostingAndBilling?.ApplyChanges();

			foreach (var error in errors.Values)
			{
				error.ApplyChanges();
			}

			Metadata?.ApplyChanges();
		}

		internal void ParseLiteData(Job domJob)
		{
			var info = new JobInfo
			{
				Id = domJob.Info.Id,
				Name = domJob.Info.Name,
				Start = domJob.Info.Start,
				End = domJob.Info.End,
				PreRoll = domJob.Info.PreRoll,
				PostRoll = domJob.Info.PostRoll,
				Priority = domJob.Info.Priority.HasValue ? domJob.Info.Priority.Value : DomIds.SlcWorkflow.Enums.JobPriority.Normal,
				Source = domJob.Info.Source,
				ActionNeeded = domJob.Info.ActionNeeded,
				JobSeriesId = domJob.Info.JobSeriesId,
			};

			if (domJob.CostingAndBilling != null)
			{
				var costBilling = new CostingAndBilling
				{
					OrganizationId = domJob.CostingAndBilling.OrganizationId,
					JobOwnerId = domJob.CostingAndBilling.JobOwnerId,
				};

				AddOrReplaceCostingAndBilling(costBilling);
			}

			var metadata = new JobLiteMetadata
			{
				FullJobId = domJob.InstanceId,
				JobState = TranslateJobState(domJob.StatusId),
				JobDuration = domJob.Info.End - domJob.Info.Start,
			};

			var liteErrors = new List<Errors>();
			foreach (var error in domJob.Errors.Values)
			{
				var liteError = new Errors
				{
					ErrorCode = error.ErrorCode,
					Message = error.Message,
				};

				liteErrors.Add(liteError);
			}

			AddOrReplaceJobInfo(info);
			AddOrReplaceMetadata(metadata);
			SetErrors(liteErrors);
		}

		private static DomIds.SlcWorkflow.Enums.JobState TranslateJobState(string statusId)
		{
			switch (statusId)
			{
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Draft: return DomIds.SlcWorkflow.Enums.JobState.Draft;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Tentative: return DomIds.SlcWorkflow.Enums.JobState.Tentative;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Confirmed: return DomIds.SlcWorkflow.Enums.JobState.Confirmed;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Running: return DomIds.SlcWorkflow.Enums.JobState.Running;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Completed: return DomIds.SlcWorkflow.Enums.JobState.Completed;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.ReadyForInvoice: return DomIds.SlcWorkflow.Enums.JobState.ReadyForInvoice;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Canceled: return DomIds.SlcWorkflow.Enums.JobState.Canceled;
				case DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Invoiced: return DomIds.SlcWorkflow.Enums.JobState.Invoiced;

				default:
					throw new NotSupportedException($"Unknown statusId {statusId}.");
			}
		}

		private void AddOrReplaceJobInfo(JobInfo jobInfo)
		{
			if (jobInfo == null)
			{
				throw new ArgumentNullException(nameof(jobInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			Info = jobInfo;
			Instance.Sections.Add(jobInfo.Section);
		}

		private void AddOrReplaceCostingAndBilling(CostingAndBilling costingAndBilling)
		{
			if (costingAndBilling == null)
			{
				throw new ArgumentNullException(nameof(costingAndBilling));
			}

			if (CostingAndBilling != null)
			{
				Instance.Sections.Remove(CostingAndBilling.Section);
			}

			CostingAndBilling = costingAndBilling;
			Instance.Sections.Add(costingAndBilling.Section);
		}

		private void AddOrReplaceMetadata(JobLiteMetadata metadata)
		{
			if (metadata == null)
			{
				throw new ArgumentNullException(nameof(metadata));
			}

			if (Metadata != null)
			{
				Instance.Sections.Remove(Metadata.Section);
			}

			Metadata = metadata;
			Instance.Sections.Add(metadata.Section);
		}

		private void SetErrors(ICollection<Errors> errors)
		{
			if (errors == null)
			{
				throw new ArgumentNullException(nameof(errors));
			}

			this.errors.Clear();
			Instance.Sections.RemoveAll(x => x.SectionDefinitionID.Id == DomIds.SlcWorkflow.Sections.Errors.Id.Id);

			foreach (var error in errors)
			{
				SetError(error);
			}
		}

		private void SetError(Errors error)
		{
			if (error == null)
			{
				throw new ArgumentNullException(nameof(error));
			}

			errors[error.ErrorCode] = error;
			Instance.Sections.Add(error.Section);
		}
	}
}

