			{
				throw new ArgumentNullException(nameof(jobNodeRelationshipReplaceActions));
			}

			if (ReplaceActions != null)
			{
				Instance.Sections.Remove(ReplaceActions.Section);
			}

			ReplaceActions = jobNodeRelationshipReplaceActions;
