namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling;

	public class RecurringJob : InstanceBase<RecurringJob>, IJob, IValidatable<RecurringJob>
	{
		private const int MaxErrorMessageLength = 300;

		private static readonly Dictionary<SectionDefinitionID, Action<RecurringJob, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<RecurringJob, Section>>
		{
			[DomIds.SlcWorkflow.Sections.JobInfo.Id] = (obj, section) => obj.Info = new JobInfo(section),
			[DomIds.SlcWorkflow.Sections.MonitoringSettings.Id] = (obj, section) => obj.MonitoringSettings = new MonitoringSettings(section),
			[DomIds.SlcWorkflow.Sections.JobExecution.Id] = (obj, section) => obj.JobExecution = new JobExecution(section),
			[DomIds.SlcWorkflow.Sections.Nodes.Id] = (obj, section) => obj.nodes.Add(new Node(section)),
			[DomIds.SlcWorkflow.Sections.Connections.Id] = (obj, section) => obj.connections.Add(new Connection(section)),
			[DomIds.SlcWorkflow.Sections.CostingAndBilling.Id] = (obj, section) => obj.CostingAndBilling = new CostingAndBilling(section),
			[DomIds.SlcWorkflow.Sections.RecurringInfo.Id] = (obj, section) => obj.RecurringInfo = new RecurringInfo(section),
			[DomIds.SlcWorkflow.Sections.NodeRelationships.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count >= 2)
				{
					obj.relationships.Add(new NodeRelationship(section));
				}
			},
			[DomIds.SlcWorkflow.Sections.Errors.Id] = (obj, section) =>
			{
				if (section.FieldValues.Count <= 0)
				{
					return;
				}

				var error = new Errors(section);

				if (!String.IsNullOrEmpty(error.ErrorCode))
				{
					obj.errors[error.ErrorCode] = error;
				}
			},
		};

		private readonly List<Node> nodes = new List<Node>();

		private readonly List<Connection> connections = new List<Connection>();

		private readonly List<NodeRelationship> relationships = new List<NodeRelationship>();

		private readonly Dictionary<string, Errors> errors = new Dictionary<string, Errors>();

		private Lazy<NodeIdManager> nodeIdManager;

		public RecurringJob(WorkflowHandler workflowHandler, DomInstance instance) : base(workflowHandler, instance, DomIds.SlcWorkflow.Definitions.RecurringJobs)
		{
			Init();
		}

		public RecurringJob(WorkflowHandler workflowHandler) : base(workflowHandler, DomIds.SlcWorkflow.Definitions.RecurringJobs)
		{
			Init();
		}

		public string Name => Info?.Name;

		public JobInfo Info { get; private set; }

		public RecurringInfo RecurringInfo { get; private set; }

		public MonitoringSettings MonitoringSettings { get; private set; }

		public JobExecution JobExecution { get; private set; }

		public CostingAndBilling CostingAndBilling { get; private set; }

		public IReadOnlyCollection<Node> Nodes => nodes;

		public IReadOnlyCollection<Connection> Connections => connections;

		public IReadOnlyDictionary<string, Errors> Errors => errors;

		public string ExecutionScriptName => JobExecution?.Script;

		public IReadOnlyCollection<NodeRelationship> Relationships => relationships;

		private NodeIdManager NodeIdManager => nodeIdManager.Value;

		protected override Dictionary<SectionDefinitionID, Action<RecurringJob, Section>> SectionMapping => InstanceSectionMapping;

		public void AddOrReplaceJobInfo(JobInfo jobInfo)
		{
			if (jobInfo == null)
			{
				throw new ArgumentNullException(nameof(jobInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			jobInfo.Id = JobIdManager.GetNextJobId(ModuleHandler as WorkflowHandler);

			Info = jobInfo;
			Instance.Sections.Add(jobInfo.Section);
		}

		public void AddOrReplaceRecurringInfo(RecurringInfo recurringInfo)
		{
			if (recurringInfo == null)
			{
				throw new ArgumentNullException(nameof(recurringInfo));
			}

			if (RecurringInfo != null)
			{
				Instance.Sections.Remove(RecurringInfo.Section);
			}

			RecurringInfo = recurringInfo;
			Instance.Sections.Add(recurringInfo.Section);
		}

		public void AddOrReplaceMonitoringSettings(MonitoringSettings monitoringSettings)
		{
			if (monitoringSettings == null)
			{
				throw new ArgumentNullException(nameof(monitoringSettings));
			}

			if (MonitoringSettings != null)
			{
				Instance.Sections.Remove(MonitoringSettings.Section);
			}

			MonitoringSettings = monitoringSettings;
			Instance.Sections.Add(monitoringSettings.Section);
		}

		public void AddOrReplaceJobExecution(JobExecution jobExecution)
		{
			if (jobExecution == null)
			{
				throw new ArgumentNullException(nameof(jobExecution));
			}

			if (JobExecution != null)
			{
				Instance.Sections.Remove(JobExecution.Section);
			}

			JobExecution = jobExecution;
			Instance.Sections.Add(jobExecution.Section);
		}

		public void AddOrReplaceCostingAndBilling(CostingAndBilling costingAndBilling)
		{
			if (costingAndBilling == null)
			{
				throw new ArgumentNullException(nameof(costingAndBilling));
			}

			if (CostingAndBilling != null)
			{
				Instance.Sections.Remove(CostingAndBilling.Section);
			}

			CostingAndBilling = costingAndBilling;
			Instance.Sections.Add(costingAndBilling.Section);
		}

		public void AddNode(Node node)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			if (nodes.Exists(x => x.SectionId == node.SectionId))
			{
				return;
			}

			if (string.IsNullOrEmpty(node.Id))
			{
				node.AssignNodeId(NodeIdManager);
			}

			if (nodes.Exists(x => x.Id == node.Id))
			{
				throw new InvalidOperationException($"A node with ID '{node.Id}' already exists");
			}

			nodes.Add(node);
			Instance.Sections.Add(node.Section);
		}

		public void RemoveNode(Node node, bool removeConnections = false, bool removeRelationships = false)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			this.RemoveNode(node.SectionId, removeConnections, removeRelationships);
		}

		public void RemoveNode(Guid sectionId, bool removeConnections = false, bool removeRelationships = false)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			var node = nodes.Find(x => x.SectionId == sectionId);
			if (node == null)
			{
				return;
			}

			if (removeConnections)
			{
				RemoveNodeConnections(node.Id);
			}

			if (removeRelationships)
			{
				RemoveNodeRelationships(node.Id);
			}

			nodes.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public void AddConnection(Connection connection)
		{
			if (connection == null)
			{
				throw new ArgumentNullException(nameof(connection));
			}

			if (connections.Exists(x => x.SectionId == connection.SectionId))
			{
				return;
			}

			if (connections.Exists(x => x.ConnectionId == connection.ConnectionId))
			{
				throw new InvalidOperationException($"A connection with ID '{connection.ConnectionId}' already exists");
			}

			connections.Add(connection);
			Instance.Sections.Add(connection.Section);
		}

		public void RemoveConnection(Connection connection)
		{
			if (connection == null)
			{
				throw new ArgumentNullException(nameof(connection));
			}

			this.RemoveConnection(connection.SectionId);
		}

		public void RemoveConnection(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!connections.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			connections.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public void AddRelationship(NodeRelationship relationship)
		{
			if (relationship == null)
			{
				throw new ArgumentNullException(nameof(relationship));
			}

			if (relationships.Exists(x => x.SectionId == relationship.SectionId))
			{
				return;
			}

			relationships.Add(relationship);
			Instance.Sections.Add(relationship.Section);
		}

		public void RemoveRelationship(NodeRelationship relationship)
		{
			if (relationship == null)
			{
				throw new ArgumentNullException(nameof(relationship));
			}

			this.RemoveRelationship(relationship.SectionId);
		}

		public void RemoveRelationship(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!relationships.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			relationships.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public int GetTotalAmountOfOccurrences()
		{
			if (RecurringInfo?.RecurringPattern == null || Info == null)
			{
				return 0;
			}

			return RecurringInfo.RecurringPattern.CalculateOccurrences(Info.Start);
		}

		public int GetAmountOfFutureOccurences()
		{
			if (RecurringInfo?.RecurringPattern == null || Info == null)
			{
				return 0;
			}

			if (StatusId != DomIds.SlcWorkflow.Behaviors.Recurringjob_Behavior.Statuses.Active)
			{
				return 0;
			}

			return RecurringInfo.RecurringPattern.CalculateOccurrences(DateTimeOffset.UtcNow);
		}

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();
			RecurringInfo?.ApplyChanges();

			foreach (var node in nodes)
			{
				node.ApplyChanges();
			}

			MonitoringSettings?.ApplyChanges();
			JobExecution?.ApplyChanges();

			foreach (var error in errors.Values)
			{
				error.ApplyChanges();
			}

			foreach (var relationship in relationships)
			{
				relationship.ApplyChanges();
			}

			foreach (var connection in connections)
			{
				connection.ApplyChanges();
			}

			CostingAndBilling?.ApplyChanges();
		}

		private void Init()
		{
			nodeIdManager = new Lazy<NodeIdManager>(() => new NodeIdManager(nodes.Select(x => Convert.ToInt32(x.Id))));
		}

		private void RemoveNodeConnections(string nodeId)
		{
			connections
					.Where(x => x.SourceNodeId == nodeId || x.DestinationNodeId == nodeId)
					.ToList()
					.ForEach(x => this.RemoveConnection(x));
		}

		private void RemoveNodeRelationships(string nodeId)
		{
			relationships
					.Where(x => x.ParentNodeId == nodeId || x.ChildNodeId == nodeId)
					.ToList()
					.ForEach(x => this.RemoveRelationship(x));
		}

		#region IValidatable

		IReadOnlyDictionary<string, IError> IValidatable<RecurringJob>.Errors => errors.ToDictionary(x => x.Key, x => (IError)x.Value);

		public bool HasErrors => errors.Count > 0;

		public bool IsLocked => throw new NotImplementedException();

		public ValidatorResults<RecurringJob> Validate(IValidator<RecurringJob> validator)
		{
			if (validator == null)
			{
				throw new ArgumentNullException(nameof(validator));
			}

			return validator.Validate(this);
		}

		public IError SetError(string errorCode, string message)
		{
			if (String.IsNullOrWhiteSpace(errorCode))
			{
				throw new ArgumentException("error code can't be empty", nameof(errorCode));
			}

			if (String.IsNullOrWhiteSpace(message))
			{
				throw new ArgumentException("error message can't be empty", nameof(message));
			}

			if (message.Length > MaxErrorMessageLength)
			{
				var truncateSuffix = "...";
				message = message.Substring(0, MaxErrorMessageLength - truncateSuffix.Length) + truncateSuffix;
			}

			if (errors.TryGetValue(errorCode, out var error))
			{
				error.Message = message;
			}
			else
			{
				error = new Errors
				{
					ErrorCode = errorCode,
					Message = message,
				};

				errors[errorCode] = error;
				Instance.Sections.Add(error.Section);
			}

			return error;
		}

		public void SetError(IError error)
		{
			if (error == null)
			{
				throw new ArgumentNullException(nameof(error));
			}

			SetError(error.ErrorCode, error.Message);
		}

		public bool ClearError(string errorCode)
		{
			if (String.IsNullOrWhiteSpace(errorCode))
			{
				throw new ArgumentException("error code can't be empty", nameof(errorCode));
			}

			if (errors.TryGetValue(errorCode, out Errors error))
			{
				if (error.SectionId == Guid.Empty)
				{
					throw new InvalidOperationException($"error name '{errorCode}' did not have a section ID linked");
				}

				Instance.Sections.RemoveAll(x => x.ID.Id == error.SectionId);
				errors.Remove(errorCode);
				return true;
			}

			return false;
		}

		public bool ClearError(IError error)
		{
			if (error == null)
			{
				throw new ArgumentNullException(nameof(error));
			}

			return ClearError(error.ErrorCode);
		}

		public bool IsLockedBy(string username)
		{
			if (string.IsNullOrEmpty(username))
			{
				return false;
			}

			return Info.LockedBy == username;
		}

		public void Lock(string username)
		{
			var workflowHandler = this.ModuleHandler as WorkflowHandler;
			Info.LockedBy = username;
			workflowHandler.UpdateRecurringJob(this);
		}

		public string StatusAsString()
		{
			switch (StatusId)
			{
				case DomIds.SlcWorkflow.Behaviors.Recurringjob_Behavior.Statuses.Active: return "Active";
				case DomIds.SlcWorkflow.Behaviors.Recurringjob_Behavior.Statuses.Completed: return "Completed";
				case DomIds.SlcWorkflow.Behaviors.Recurringjob_Behavior.Statuses.Cancelled: return "Cancelled";
				default: throw new InvalidOperationException($"Unknown status '{StatusId}'");
			}
		}

		public void Unlock()
		{
			var workflowHandler = this.ModuleHandler as WorkflowHandler;
			Info.LockedBy = string.Empty;
			workflowHandler.UpdateRecurringJob(this);
		}
		#endregion
	}
}
