namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Sections;

	public class Workflow : InstanceBase<Workflow>, IWorkflow
	{
		private static readonly Dictionary<SectionDefinitionID, Action<Workflow, Section>> InstanceSectionMapping = new Dictionary<SectionDefinitionID, Action<Workflow, Section>>
		{
			[DomIds.SlcWorkflow.Sections.WorkflowExecution.Id] = (obj, section) => obj.Execution = new WorkflowExecution(section),
			[DomIds.SlcWorkflow.Sections.WorkflowInfo.Id] = (obj, section) => obj.Info = new WorkflowInfo(section),
			[DomIds.SlcWorkflow.Sections.MonitoringSettings.Id] = (obj, section) => obj.MonitoringSettings = new MonitoringSettings(section),
			[DomIds.SlcWorkflow.Sections.Nodes.Id] = (obj, section) => obj.nodes.Add(new Node(section)),
			[DomIds.SlcWorkflow.Sections.Connections.Id] = (obj, section) => obj.connections.Add(new Connection(section)),
		};

		private readonly List<Node> nodes = new List<Node>();

		private readonly List<Connection> connections = new List<Connection>();

		private readonly Lazy<NodeIdManager> nodeIdManager;

		public Workflow(WorkflowHandler workflowHandler, DomInstance instance) : base(workflowHandler, instance, DomIds.SlcWorkflow.Definitions.Workflows)
		{
			nodeIdManager = new Lazy<NodeIdManager>(() => new NodeIdManager(nodes.Select(x => Convert.ToInt32(x.Id))));
		}

		public Workflow(WorkflowHandler workflowHandler) : base(workflowHandler, DomIds.SlcWorkflow.Definitions.Workflows)
		{
			nodeIdManager = new Lazy<NodeIdManager>(() => new NodeIdManager(nodes.Select(x => Convert.ToInt32(x.Id))));
		}

		public Workflow(DomInstance instance) : base(instance, DomIds.SlcWorkflow.Definitions.Workflows)
		{
			nodeIdManager = new Lazy<NodeIdManager>(() => new NodeIdManager(nodes.Select(x => Convert.ToInt32(x.Id))));
		}

		public string Name => Info?.Name;

		public WorkflowExecution Execution { get; set; }

		public WorkflowInfo Info { get; set; }

		public MonitoringSettings MonitoringSettings { get; set; }

		public IReadOnlyCollection<Node> Nodes => nodes;

		public IReadOnlyCollection<Connection> Connections => connections;

		public string ExecutionScriptName => Execution?.Script;

		protected override Dictionary<SectionDefinitionID, Action<Workflow, Section>> SectionMapping => InstanceSectionMapping;

		private NodeIdManager NodeIdManager => nodeIdManager.Value;

		public void AddNode(Node node)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			if (nodes.Exists(x => x.SectionId == node.SectionId))
			{
				return;
			}

			if (string.IsNullOrEmpty(node.Id))
			{
				node.AssignNodeId(NodeIdManager);
			}

			nodes.Add(node);
			Instance.Sections.Add(node.Section);
		}

		public void RemoveNode(Node node)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			this.RemoveNode(node.SectionId);
		}

		public void RemoveNode(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!nodes.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			nodes.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public void AddConnection(Connection connection)
		{
			if (connection == null)
			{
				throw new ArgumentNullException(nameof(connection));
			}

			if (connections.Exists(x => x.SectionId == connection.SectionId))
			{
				return;
			}

			connections.Add(connection);
			Instance.Sections.Add(connection.Section);
		}

		public void RemoveConnection(Connection connection)
		{
			if (connection == null)
			{
				throw new ArgumentNullException(nameof(connection));
			}

			this.RemoveConnection(connection.SectionId);
		}

		public void RemoveConnection(Guid sectionId)
		{
			if (sectionId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(sectionId));
			}

			if (!connections.Exists(x => x.SectionId == sectionId))
			{
				return;
			}

			connections.RemoveAll(x => x.SectionId == sectionId);
			Instance.Sections.RemoveAll(x => x.ID.Id == sectionId);
		}

		public int CalculateNextNodeID()
		{
			return nodes.Select(x => Convert.ToInt32(x.Id)).DefaultIfEmpty().Max() + 1;
		}

		public override void ApplyChanges()
		{
			Info?.ApplyChanges();
			Execution?.ApplyChanges();

			foreach (var node in nodes)
			{
				node?.ApplyChanges();
			}

			foreach (var connection in connections)
			{
				connection?.ApplyChanges();
			}
		}

		public Workflow Duplicate()
		{
			var duplicatedInstance = CloneInstance();

			if (ModuleHandler is WorkflowHandler workflowHandler)
			{
				return new Workflow(workflowHandler, duplicatedInstance) { IsNew = true };
			}
			else
			{
				return new Workflow(duplicatedInstance) { IsNew = true };
			}
		}

		public void AddOrReplaceWorkflowInfo(WorkflowInfo workflowInfo)
		{
			if (workflowInfo == null)
			{
				throw new ArgumentNullException(nameof(workflowInfo));
			}

			if (Info != null)
			{
				Instance.Sections.Remove(Info.Section);
			}

			Info = workflowInfo;
			Instance.Sections.Add(workflowInfo.Section);
		}

		public void AddOrReplaceWorkflowExecution(WorkflowExecution workflowExecution)
		{
			if (workflowExecution == null)
			{
				throw new ArgumentNullException(nameof(workflowExecution));
			}

			if (Execution != null)
			{
				Instance.Sections.Remove(Execution.Section);
			}

			Execution = workflowExecution;
			Instance.Sections.Add(workflowExecution.Section);
		}
	}
}
