namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.MediaOps.Communication.Exceptions;
	using Skyline.DataMiner.MediaOps.Communication.TraceData;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Net.Profiles;
	using Skyline.DataMiner.Net.SRM.Capabilities;
	using Skyline.DataMiner.Utils.MediaOps.Common.Applications.Workflows.TraceData;
	using Skyline.DataMiner.Utils.MediaOps.Common.IOData.Scheduling.Scripts.JobHandler.Objects;
	using Skyline.DataMiner.Utils.MediaOps.Common.Utils;
	using Skyline.DataMiner.Utils.MediaOps.Extensions;

	public class ConfigurationHandler
	{
		#region Fields
		private readonly WorkflowHandler workflowHandler;
		private readonly ProfileHelper profileHelper;
		private readonly ILogger logger;

		private readonly Dictionary<Guid, Skyline.DataMiner.Net.Profiles.Parameter> profileParametersById = new Dictionary<Guid, Net.Profiles.Parameter>();

		private Dictionary<Guid, ConfigurationValue> referenceValuesById;
		#endregion

		public ConfigurationHandler(WorkflowHandler workflowHandler, ProfileHelper profileHelper, ILogger logger = null)
		{
			this.workflowHandler = workflowHandler ?? throw new ArgumentNullException(nameof(workflowHandler));
			this.profileHelper = profileHelper ?? throw new ArgumentNullException(nameof(profileHelper));
			this.logger = logger;
		}

		#region Methods
		public static IEnumerable<Skyline.DataMiner.Net.SRM.Capacities.MultiResourceCapacityUsage> ComposeCapacities(IEnumerable<ConfigurationValue> capacityParameters, bool ignoreEmptyConfigurationValues = false)
		{
			var capacities = new List<Skyline.DataMiner.Net.SRM.Capacities.MultiResourceCapacityUsage>();
			if (capacityParameters == null || !capacityParameters.Any())
			{
				return capacities;
			}

			var errorData = new List<MediaOpsErrorData>();
			foreach (var capacityParameter in capacityParameters)
			{
				if (!capacityParameter.DoubleValue.HasValue)
				{
					if (!ignoreEmptyConfigurationValues)
					{
						errorData.Add(new ConfigurationConfigurationError
						{
							ErrorReason = ConfigurationConfigurationError.Reason.InvalidOverriddenValue,
							ErrorMessage = $"Empty value not allowed for capacity parameter {capacityParameter.ProfileParameter.Name} ({capacityParameter.ProfileParameter.ID})",
						});
					}

					continue;
				}

				capacities.Add(new Skyline.DataMiner.Net.SRM.Capacities.MultiResourceCapacityUsage
				{
					CapacityProfileID = capacityParameter.ProfileParameter.ID,
					DecimalQuantity = Convert.ToDecimal(capacityParameter.DoubleValue),
				});
			}

			if (errorData.Count > 0)
			{
				var traceData = new MediaOpsTraceData
				{
					ErrorData = errorData,
				};

				throw new MediaOpsException(traceData);
			}

			return capacities;
		}

		public static Dictionary<Guid, NodeConfigFilter.CapacityFilter> ComposeCapacitiesFilter(IEnumerable<ConfigurationValue> capacityParameters)
		{
			var capacities = new Dictionary<Guid, NodeConfigFilter.CapacityFilter>();
			if (capacityParameters == null || !capacityParameters.Any())
			{
				return capacities;
			}

			foreach (var capacityParameter in capacityParameters)
			{
				var capacity = new NodeConfigFilter.CapacityFilter
				{
					Id = capacityParameter.ProfileParameter.ID,
				};

				if (capacityParameter.ProfileParameter.Type == Net.Profiles.Parameter.ParameterType.Number)
				{
					capacity.Value = Convert.ToDecimal(capacityParameter.DoubleValue);
				}
				else
				{
					continue;
				}

				capacities[capacityParameter.ProfileParameter.ID] = capacity;
			}

			return capacities;
		}

		public IEnumerable<Skyline.DataMiner.Net.SRM.Capabilities.ResourceCapabilityUsage> ComposeCapabilities(IEnumerable<ConfigurationValue> capabilityParameters, bool ignoreEmptyConfigurationValues = false)
		{
			if (capabilityParameters == null)
			{
				throw new ArgumentNullException(nameof(capabilityParameters));
			}

			logger?.Debug(this, $"Composing capabilities for parameters: {string.Join(", ", capabilityParameters.Select(x => $"PP {x.ProfileParameter.ID}, values: {x.StringValue}"))}");

			var capabilities = new List<Skyline.DataMiner.Net.SRM.Capabilities.ResourceCapabilityUsage>();

			var linkedTimeDependentCapabilities = GetParameters(capabilityParameters
				.Where(x => x.ProfileParameter.HasLinkedTimeDependentParameter())
				.Select(x => x.ProfileParameter.LinkedTimeDependentParameterId()));

			var errorData = new List<MediaOpsErrorData>();
			foreach (var capabilityParameter in capabilityParameters)
			{
				if (!capabilityParameter.DoubleValue.HasValue && capabilityParameter.StringValue == null)
				{
					if (!ignoreEmptyConfigurationValues)
					{
						errorData.Add(new ConfigurationConfigurationError
						{
							ErrorReason = ConfigurationConfigurationError.Reason.InvalidOverriddenValue,
							ErrorMessage = $"Empty value not allowed for capability parameter {capabilityParameter.ProfileParameter.Name} ({capabilityParameter.ProfileParameter.ID})",
						});
					}

					continue;
				}

				if (!TryCreateCapabilityUsage(capabilityParameter, out var capabilityUsage))
				{
					continue;
				}

				if (capabilityParameter.ProfileParameter.HasLinkedTimeDependentParameter())
				{
					logger?.Debug(this, $"Capability {capabilityParameter.ProfileParameter.ID} has linked time-dependent capability.");

					Guid linkedTimeDependentCapabilityId = capabilityParameter.ProfileParameter.LinkedTimeDependentParameterId();
					if (!linkedTimeDependentCapabilities.TryGetValue(linkedTimeDependentCapabilityId, out var linkedTimeDependentCapability))
					{
						// Don't assign capability if linked TDC cannot be found
						logger?.Debug(this, $"Unable to find linked TDC with ID: {linkedTimeDependentCapabilityId}, capability {capabilityParameter.ProfileParameter.Name} [{capabilityParameter.ProfileParameter.ID}] will not assigned to the reservation");
						continue;
					}

					if (!TryCreateLinkedTimeDependentCapabilityUsage(capabilityParameter, linkedTimeDependentCapability, out var timeDependentUsage))
					{
						continue;
					}

					capabilities.Add(timeDependentUsage);
				}

				capabilities.Add(capabilityUsage);
			}

			if (errorData.Count > 0)
			{
				var traceData = new MediaOpsTraceData
				{
					ErrorData = errorData,
				};

				throw new MediaOpsException(traceData);
			}

			return capabilities;
		}

		public static Dictionary<Guid, NodeConfigFilter.CapabilityFilter> ComposeCapabilitiesFilter(IEnumerable<ConfigurationValue> capabilityParameters)
		{
			var capabilities = new Dictionary<Guid, NodeConfigFilter.CapabilityFilter>();
			if (capabilityParameters == null || !capabilityParameters.Any())
			{
				return capabilities;
			}

			foreach (var capabilityParameter in capabilityParameters)
			{
				var capability = new NodeConfigFilter.CapabilityFilter
				{
					Id = capabilityParameter.ProfileParameter.ID,
				};

				if (capabilityParameter.ProfileParameter.Type == Net.Profiles.Parameter.ParameterType.Text)
				{
					capability.Values = new List<string> { capabilityParameter.StringValue };
				}
				else if (capabilityParameter.ProfileParameter.Type == Net.Profiles.Parameter.ParameterType.Number)
				{
					capability.Values = new List<string> { Convert.ToString(capabilityParameter.DoubleValue.Value) };
				}
				else if (capabilityParameter.ProfileParameter.Type == Net.Profiles.Parameter.ParameterType.Discrete)
				{
					capability.Values = new List<string> { capabilityParameter.StringValue };
				}
				else
				{
					continue;
				}

				capabilities[capabilityParameter.ProfileParameter.ID] = capability;
			}

			return capabilities;
		}

		public IEnumerable<ConfigurationOverview> GetConfigurations(IEnumerable<Guid> nodeConfigurationIds, Guid referenceConfigurationId, IEnumerable<Configuration> loadedConfigurations = null)
		{
			if (nodeConfigurationIds == null)
			{
				return Array.Empty<ConfigurationOverview>();
			}

			var domConfigurationIds = nodeConfigurationIds.ToList();
			if (domConfigurationIds.Count == 0)
			{
				return Array.Empty<ConfigurationOverview>();
			}

			domConfigurationIds.Add(referenceConfigurationId);
			if (loadedConfigurations != null)
			{
				// Removed loaded configurations. This is typically for updated configuration objects that aren't stored in DOM.
				foreach (var loadedConfiguration in loadedConfigurations)
				{
					domConfigurationIds.Remove(loadedConfiguration.InstanceId);
				}
			}

			var domConfigurationsById = workflowHandler.GetConfigurationsByDomInstanceIds(domConfigurationIds).ToDictionary(x => x.InstanceId);
			if (loadedConfigurations != null)
			{
				foreach (var loadedConfiguration in loadedConfigurations)
				{
					domConfigurationsById.Add(loadedConfiguration.InstanceId, loadedConfiguration);
				}
			}

			if (domConfigurationsById.TryGetValue(referenceConfigurationId, out var domReferenceConfiguration))
			{
				referenceValuesById = ParseConfiguration(domReferenceConfiguration).ToDictionary(x => x.ProfileParameter.ID);
			}

			var data = new List<ConfigurationOverview>();
			foreach (var nodeConfigurationId in nodeConfigurationIds)
			{
				if (!domConfigurationsById.TryGetValue(nodeConfigurationId, out var domNodeConfiguration))
				{
					continue;
				}

				data.Add(ParseNodeConfiguration(domNodeConfiguration));
			}

			return data;
		}

		private static bool TryCreateCapabilityUsage(ConfigurationValue capabilityParameter, out ResourceCapabilityUsage capability)
		{
			capability = new Skyline.DataMiner.Net.SRM.Capabilities.ResourceCapabilityUsage
			{
				CapabilityProfileID = capabilityParameter.ProfileParameter.ID,
			};

			if (capabilityParameter.ProfileParameter.Type == Skyline.DataMiner.Net.Profiles.Parameter.ParameterType.Text)
			{
				capability.RequiredString = capabilityParameter.StringValue;
			}
			else if (capabilityParameter.ProfileParameter.Type == Skyline.DataMiner.Net.Profiles.Parameter.ParameterType.Number)
			{
				capability.RequiredRangePoint = capabilityParameter.DoubleValue.Value;
			}
			else if (capabilityParameter.ProfileParameter.Type == Skyline.DataMiner.Net.Profiles.Parameter.ParameterType.Discrete)
			{
				capability.RequiredDiscreet = capabilityParameter.StringValue;
			}
			else
			{
				return false;
			}

			return true;
		}

		private bool TryCreateLinkedTimeDependentCapabilityUsage(ConfigurationValue capabilityParameter, Skyline.DataMiner.Net.Profiles.Parameter linkedTimeDependentCapability, out ResourceCapabilityUsage capability)
		{
			capability = new Skyline.DataMiner.Net.SRM.Capabilities.ResourceCapabilityUsage
			{
				CapabilityProfileID = linkedTimeDependentCapability.ID,
			};

			if (linkedTimeDependentCapability.Type != Net.Profiles.Parameter.ParameterType.Text)
			{
				// Only Text Capabilities can be assigned as being time-dependent to resources
				logger?.Debug(this, $"Linked TDC {linkedTimeDependentCapability.Name} [{linkedTimeDependentCapability.ID}] is not of type Text");
				return false;
			}

			if (capabilityParameter.ProfileParameter.Type != Skyline.DataMiner.Net.Profiles.Parameter.ParameterType.Discrete)
			{
				// Only Discrete Capabilities require the use of a linked text time-dependent capability
				logger?.Debug(this, $"Capability {capabilityParameter.ProfileParameter.Name} [{capabilityParameter.ProfileParameter.ID}] is not of type Discrete");
				return false;
			}

			capability.RequiredString = capabilityParameter.StringValue;
			return true;
		}

		private static void AddParameterValueToConfigurationData(ConfigurationOverview data, ConfigurationValue configurationValue)
		{
			if (configurationValue.ProfileParameter.Categories.HasFlag(Skyline.DataMiner.Net.Profiles.ProfileParameterCategory.Capacity))
			{
				data.CapacityParameters.Add(configurationValue);
			}
			else if (configurationValue.ProfileParameter.Categories.HasFlag(Skyline.DataMiner.Net.Profiles.ProfileParameterCategory.Capability))
			{
				data.CapabilityParameters.Add(configurationValue);
			}
			else
			{
				data.ConfigParameters.Add(configurationValue);
			}
		}

		private ConfigurationOverview ParseNodeConfiguration(Configuration domConfiguration)
		{
			var data = new ConfigurationOverview
			{
				DomConfigurationId = domConfiguration.InstanceId,
				ConfigParameters = new List<ConfigurationValue>(),
				CapabilityParameters = new List<ConfigurationValue>(),
				CapacityParameters = new List<ConfigurationValue>(),
			};

			var configurationValues = ParseConfiguration(domConfiguration);
			if (configurationValues.Count == 0)
			{
				return data;
			}

			foreach (var configurationValue in configurationValues)
			{
				AddParameterValueToConfigurationData(data, configurationValue);
			}

			return data;
		}

		private ICollection<ConfigurationValue> ParseConfiguration(Configuration domConfiguration)
		{
			var values = new List<ConfigurationValue>();
			if (domConfiguration.ProfileParameterValues.Count == 0)
			{
				return values;
			}

			var parametersById = GetParameters(domConfiguration.ProfileParameterValues.Select(x => x.ProfileParameterId));
			foreach (var domProfileParameterValue in domConfiguration.ProfileParameterValues)
			{
				if (!parametersById.TryGetValue(domProfileParameterValue.ProfileParameterId, out var profileParameter))
				{
					continue;
				}

				var configurationValue = new ConfigurationValue
				{
					ProfileParameter = profileParameter,
				};

				SetConfigurationValue(configurationValue, domProfileParameterValue);
				values.Add(configurationValue);
			}

			return values;
		}

		private void SetConfigurationValue(ConfigurationValue configurationValue, ProfileParameterValue domProfileParameterValue)
		{
			if (referenceValuesById != null && referenceValuesById.TryGetValue(domProfileParameterValue.ReferenceId, out var referenceValue))
			{
				configurationValue.StringValue = referenceValue.StringValue;
				configurationValue.DoubleValue = referenceValue.DoubleValue;

				return;
			}

			configurationValue.StringValue = domProfileParameterValue.StringValue;
			configurationValue.DoubleValue = domProfileParameterValue.DoubleValue;
		}

		private IDictionary<Guid, Skyline.DataMiner.Net.Profiles.Parameter> GetParameters(IEnumerable<Guid> ids)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var result = new Dictionary<Guid, Skyline.DataMiner.Net.Profiles.Parameter>();
			var idsToRetrieve = new List<Guid>();

			foreach (var id in ids.Where(x => x != Guid.Empty).Distinct())
			{
				if (profileParametersById.TryGetValue(id, out var parameter))
				{
					result[id] = parameter;
				}
				else
				{
					idsToRetrieve.Add(id);
				}
			}

			if (idsToRetrieve.Count > 0)
			{
				var filter = new ORFilterElement<Skyline.DataMiner.Net.Profiles.Parameter>(idsToRetrieve.Select(id => ParameterExposers.ID.Equal(id)).ToArray());
				foreach (var parameter in profileHelper.ProfileParameters.Read(filter))
				{
					profileParametersById.Add(parameter.ID, parameter);
					result[parameter.ID] = parameter;
				}
			}

			return result;
		}
		#endregion
	}
}

