// DOM\Applications\Workflow\Objects\JobIdManager.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System.Linq;

	internal static class JobIdManager
	{
		public static string GetNextJobId(WorkflowHandler workflowHandler)
		{
			using (WorkflowHandler.LockAppSettings())
			{
				var appSettings = workflowHandler.GetAllAppSettings().SingleOrDefault();
				if (appSettings == null)
				{
					return string.Empty;
				}

				var jobId = ComposeJobId(appSettings.JobSettings);

				CalculateNextSequence(appSettings.JobSettings);
				workflowHandler.UpdateAppSettings(appSettings);

				return jobId;
			}
		}

		private static string ComposeJobId(JobSettings jobSettings)
		{
			var sequence = jobSettings.JobIdNextSequence.ToString($"D{jobSettings.JobIdMinimumDigits}");

			return $"{jobSettings.JobIdPrefix}{sequence}";
		}

		private static void CalculateNextSequence(JobSettings jobSettings)
		{
			jobSettings.JobIdNextSequence += jobSettings.JobIdIncrement;
		}
	}
}

