//---------------------------------
// DOM\Applications\Workflow\Objects\NodeIdManager.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	public class NodeIdManager
	{
		private readonly HashSet<int> _assignedNodeIds;

		internal NodeIdManager(IEnumerable<int> assignedNodeIds)
		{
			_assignedNodeIds = new HashSet<int>(assignedNodeIds);
		}

		public void ExcludeNodeIds(params string[] nodeIdsToExclude)
		{
			foreach (var nodeId in nodeIdsToExclude)
			{
				if (string.IsNullOrWhiteSpace(nodeId))
				{
					continue;
				}

				if (!int.TryParse(nodeId, out var parsedNodeId))
				{
					continue;
				}

				if (!_assignedNodeIds.Add(parsedNodeId))
				{
					throw new InvalidOperationException($"Unable to exclude Node ID {parsedNodeId}. This ID was already assigned to another node in the job.");
				}
			}
		}

		internal int GetNextNodeId()
		{
			int nextNodeId = 1;
			if (_assignedNodeIds.Count > 0)
			{
				nextNodeId = _assignedNodeIds.Max() + 1;
			}

			_assignedNodeIds.Add(nextNodeId);
			return nextNodeId;
		}
	}
}

