	public class Connection : SectionBase<Connection>
	{
		private static readonly Dictionary<FieldDescriptorID, Action<Connection, object>> SectionFieldMapping = new Dictionary<FieldDescriptorID, Action<Connection, object>>
		{
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionID] = (obj, value) => obj.ConnectionId = Convert.ToString(value),
			[DomIds.SlcWorkflow.Sections.Connections.SourceNodeID] = (obj, value) => obj.SourceNodeId = Convert.ToString(value),
			[DomIds.SlcWorkflow.Sections.Connections.DestinationNodeID] = (obj, value) => obj.DestinationNodeId = Convert.ToString(value),
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionAlias] = (obj, value) => obj.ConnectionAlias = Convert.ToString(value),
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionExecutionOrder] = (obj, value) => obj.ConnectionExecutionOrder = Convert.ToInt64(value),
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionExecutionScript] = (obj, value) => obj.ConnectionExecutionScript = Convert.ToString(value),
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionType] = (obj, value) => obj.ConnectionType = (DomIds.SlcWorkflow.Enums.ConnectionType)value,
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionSubtype] = (obj, value) => obj.ConnectionSubtype = (DomIds.SlcWorkflow.Enums.ConnectionSubtype)value,
			[DomIds.SlcWorkflow.Sections.Connections.PredefinedSubset] = (obj, value) => obj.PredefinedSubset = (DomIds.SlcWorkflow.Enums.PredefinedSubset)value,
			[DomIds.SlcWorkflow.Sections.Connections.ConnectionDetails] = (obj, value) => obj.ConnectionDetails = Convert.ToString(value),
		};

		public Connection() : base(DomIds.SlcWorkflow.Sections.Connections.Id)
		{
		}

		internal Connection(Section section) : base(section)
		{
		}

		public string ConnectionAlias { get; set; }

		public Int64 ConnectionExecutionOrder { get; set; }

		public string ConnectionExecutionScript { get; set; }

		public string ConnectionId { get; set; }

		public string DestinationNodeId { get; set; }

		public string SourceNodeId { get; set; }

		public DomIds.SlcWorkflow.Enums.ConnectionType ConnectionType { get; set; }

		public DomIds.SlcWorkflow.Enums.ConnectionSubtype ConnectionSubtype { get; set; }

		public DomIds.SlcWorkflow.Enums.PredefinedSubset PredefinedSubset { get; set; }

		public string ConnectionDetails { get; set; }

		protected override Dictionary<FieldDescriptorID, Action<Connection, object>> FieldMapping => SectionFieldMapping;

		public Connection Duplicate()
		{
			var duplicatedSection = Section.Clone() as Section;
			duplicatedSection.ID = new SectionID(Guid.NewGuid());

			return new Connection(duplicatedSection);
		}

		internal override void ApplyChanges()
		{
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionID, ConnectionId);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.SourceNodeID, SourceNodeId);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.DestinationNodeID, DestinationNodeId);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionAlias, ConnectionAlias);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionExecutionOrder, ConnectionExecutionOrder);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionExecutionScript, ConnectionExecutionScript);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionType, (int)ConnectionType);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionSubtype, (int)ConnectionSubtype);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.PredefinedSubset, (int)PredefinedSubset);
			Section.SetField(DomIds.SlcWorkflow.Sections.Connections.ConnectionDetails, ConnectionDetails);
		}
	}
