	public class JobExecution : SectionBase<JobExecution>
	{
		private static readonly Dictionary<FieldDescriptorID, Action<JobExecution, object>> SectionFieldMapping = new Dictionary<FieldDescriptorID, Action<JobExecution, object>>
		{
