		public DateTimeOffset Start { get; set; }

		public DateTimeOffset End { get; set; }

		public bool Hidden { get; set; }

		public bool Billable { get; set; }

		public Guid LinkedBookingId { get; set; }

		public Int64 ExecutionOrder { get; set; }

		public string AdHocControlScript { get; set; }

		public DomIds.SlcWorkflow.Enums.ResourceSelectMode? ResourceSelectMode { get; set; }

		public DomIds.SlcWorkflow.Enums.ResourceSelectState? ResourceSelectState { get; set; }

		public Guid ConfigurationId { get; set; }

		public DomIds.SlcWorkflow.Enums.NodeConfigurationStatus? ConfigurationStatus { get; set; }

		protected override Dictionary<FieldDescriptorID, Action<Node, object>> FieldMapping => SectionFieldMapping;

		public Node Duplicate()
		{
			var duplicatedSection = Section.Clone() as Section;
			duplicatedSection.ID = new SectionID(Guid.NewGuid());

			return new Node(duplicatedSection);
		}

		public bool IsSource()
		{
			switch (NodeType)
			{
				case DomIds.SlcWorkflow.Enums.NodeType.Source:
				case DomIds.SlcWorkflow.Enums.NodeType.SourceType:
				case DomIds.SlcWorkflow.Enums.NodeType.SourceInstance:
					return true;
				default:
					return false;
			}
		}

		public bool IsDestination()
		{
			switch (NodeType)
			{
				case DomIds.SlcWorkflow.Enums.NodeType.Destination:
				case DomIds.SlcWorkflow.Enums.NodeType.DestinationType:
				case DomIds.SlcWorkflow.Enums.NodeType.DestinationInstance:
					return true;
				default:
					return false;
			}
		}

		public void AssignNodeId(NodeIdManager nodeIdManager)
		{
			if (nodeIdManager == null)
			{
				throw new ArgumentNullException(nameof(nodeIdManager));
			}

			if (!String.IsNullOrWhiteSpace(Id))
			{
				// Node already has an ID assigned to it.
				return;
			}

			Id = Convert.ToString(nodeIdManager.GetNextNodeId());
		}

		public string NodeTypeAsString()
		{
			if (!NodeType.HasValue)
			{
				return String.Empty;
			}

			switch (NodeType)
			{
				case DomIds.SlcWorkflow.Enums.NodeType.Source: return "source";
				case DomIds.SlcWorkflow.Enums.NodeType.SourceType: return "source type";
				case DomIds.SlcWorkflow.Enums.NodeType.Resource: return "resource";
				case DomIds.SlcWorkflow.Enums.NodeType.ResourcePool: return "resource pool";
				case DomIds.SlcWorkflow.Enums.NodeType.Destination: return "destination";
				case DomIds.SlcWorkflow.Enums.NodeType.DestinationType: return "destination type";
				case DomIds.SlcWorkflow.Enums.NodeType.SourceInstance: return "source instance";
				case DomIds.SlcWorkflow.Enums.NodeType.DestinationInstance: return "destination instance";

				default: throw new InvalidOperationException($"Unknown node type '{NodeType}'");
			}
		}

		internal override void ApplyChanges()
		{
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.NodeID, Id);

			ApplyAliasChanges();
			ApplyNodeTypeChanges();
			ApplyReferenceIdChanges();
			ApplyParentReferenceIdChanges();
			ApplyIconChanges();

			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.Hidden, Hidden);
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.Billable, Billable);
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.NodeStartTime, Start.UtcDateTime);
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.NodeEndTime, End.UtcDateTime);
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.Nodes.NodeConfigurationExecutionOrder, ExecutionOrder);

			ApplyLinkedBookingIdChanges();
			ApplyResourceSelectModeChanges();
			ApplyResourceSelectStateChanges();
			ApplyAdHocControlScriptChanges();
			ApplyConfigurationIdChanges();
			ApplyConfigurationStatusChanges();
		}

