			[DomIds.SlcWorkflow.Sections.RecurringInfo.TimeZone] = (obj, value) => obj.TimeZone = TimeZoneInfo.FromSerializedString(Convert.ToString(value)),
			[DomIds.SlcWorkflow.Sections.RecurringInfo.RecurringPattern] = (obj, value) => obj.RecurringPattern = RecurringPattern.Deserialize(Convert.ToString(value)),
			[DomIds.SlcWorkflow.Sections.RecurringInfo.ProcessStatus] = (obj, value) => obj.ProcessStatus = (DomIds.SlcWorkflow.Enums.ProcessStatus)value,
			[DomIds.SlcWorkflow.Sections.RecurringInfo.DesiredJobStatus] = (obj, value) => obj.DesiredJobStatus = (DomIds.SlcWorkflow.Enums.DesiredJobStatus)value,
		};

