		{
		}

		public TimeSpan Duration { get; set; }

		public TimeZoneInfo TimeZone { get; set; }

		public RecurringPattern RecurringPattern { get; set; }

		public DomIds.SlcWorkflow.Enums.ProcessStatus ProcessStatus { get; set; }

		public DomIds.SlcWorkflow.Enums.DesiredJobStatus DesiredJobStatus { get; set; }

		protected override Dictionary<FieldDescriptorID, Action<RecurringInfo, object>> FieldMapping => SectionFieldMapping;

		public string ProcessingStatusAsString()
		{
			switch (ProcessStatus)
			{
				case DomIds.SlcWorkflow.Enums.ProcessStatus.UpdatingSeries:
					return "Creating Jobs...";
				case DomIds.SlcWorkflow.Enums.ProcessStatus.UpdateFailed:
					return "Fail";
				case DomIds.SlcWorkflow.Enums.ProcessStatus.SeriesUpdated:
					return "OK";
				case DomIds.SlcWorkflow.Enums.ProcessStatus.NA:
				default:
					return "N/A";
			}
		}

		public string DesiredJobStatusAsString()
		{
			return DesiredJobStatus.ToString();
		}

		internal override void ApplyChanges()
		{
			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.RecurringInfo.RecurringPattern, RecurringPattern.Serialize());

			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.RecurringInfo.TimeZone, TimeZone.ToSerializedString());

			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.RecurringInfo.ProcessStatus, (int)ProcessStatus);

			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.RecurringInfo.DesiredJobStatus, (int)DesiredJobStatus);

			Section.AddOrUpdateValue(DomIds.SlcWorkflow.Sections.RecurringInfo.Duration, Duration);
		}
	}
}
