namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel.General;
	using Skyline.DataMiner.Net.Helper;
	using Skyline.DataMiner.Net.Jobs;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Net.Sections;
	using Skyline.DataMiner.Utils.MediaOps.Common.Extensions;
	using Skyline.DataMiner.Utils.MediaOps.Common.Tools.ToBeMovedToNuget;

	using SLDataGateway.API.Types.Querying;

	using DomIds = Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;

	public class WorkflowHandler : ModuleHandlerBase
	{
		private static readonly Net.LockManager _appSettingsLock = new Net.LockManager();

		private static readonly string _appSettingsLockId = "0ac44eb1-4daa-49e7-a810-293860f40799";

		private static readonly Net.LockManager _jobLock = new Net.LockManager();

		private static readonly Net.LockManager _jobLiteLock = new Net.LockManager();

		public WorkflowHandler(IEngine engine) : base(engine, DomIds.SlcWorkflow.ModuleId)
		{
		}

		public WorkflowHandler(Net.IConnection connection) : base(connection, DomIds.SlcWorkflow.ModuleId)
		{
		}

		public WorkflowHandler(DomHelper domHelper) : base(domHelper, DomIds.SlcWorkflow.ModuleId)
		{
		}

		public static JobLock LockJob(Guid id)
		{
			_jobLock.Lock(Convert.ToString(id));

			return new JobLock(id);
		}

		public static void UnlockJob(Guid id)
		{
			_jobLock.Unlock(Convert.ToString(id));
		}

		public static AppSettingsLock LockAppSettings()
		{
			_appSettingsLock.Lock(_appSettingsLockId);

			return new AppSettingsLock();
		}

		public static void UnlockAppSettings()
		{
