		public Job CreateJob(Job job)
		{
			if (job == null)
			{
				throw new ArgumentNullException(nameof(job));
			}

			if (job.Info != null && string.IsNullOrEmpty(job.Info.Id))
			{
				job.Info.Id = GetNextJobId();
			}

			job.ApplyChanges();
			var createdInstance = DomHelper.DomInstances.Create(job.Instance);
			var createdJob = new Job(this, createdInstance);

			CreateOrUpdateJobLite(createdJob);

			return createdJob;
		}

		public void BulkCreateJobs(ICollection<Job> jobs)
		{
			if (jobs == null)
			{
				throw new ArgumentNullException(nameof(jobs));
			}

			foreach (var pagedJobs in jobs.Batch(100))
			{
				pagedJobs.ForEach(job =>
				{
					if (job.Info != null && string.IsNullOrEmpty(job.Info.Id))
					{
						job.Info.Id = GetNextJobId();
					}

					job.ApplyChanges();
				});

				DomHelper.DomInstances.TryCreateOrUpdate(pagedJobs.Select(x => x.Instance).ToList(), out var result);
				if (result.SuccessfulItems.Count > 0)
				{
					BulkCreateJobsLite(result.SuccessfulItems.Select(x => new Job(this, x)).ToList());
				}

				result.ThrowOnFailure();
			}
		}

