		public void BulkDeleteJobs(ICollection<Job> jobs)
		{
			if (jobs == null)
			{
				throw new ArgumentNullException(nameof(jobs));
			}

			foreach (var x in jobs.Batch(100))
			{
				DomHelper.DomInstances.TryDelete(x.Select(y => y.Instance).ToList(), out var result);
				if (result.SuccessfulIds.Count > 0)
