		public void CreateOrUpdateJobLite(Job job)
		{
			if (job == null)
			{
				throw new ArgumentNullException(nameof(job));
			}

			using (LockJobLite(job.InstanceId))
			{
				var filter = DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.JobLiteMetadata.FullJobID).Equal(job.InstanceId);

				var jobLite = GetJobsLiteIterator(filter).SingleOrDefault();
				if (jobLite == null)
				{
					jobLite = new JobLite(this);
					jobLite.ParseLiteData(job);

					jobLite.ApplyChanges();
					DomHelper.DomInstances.Create(jobLite.Instance);
				}
				else
				{
					var previous = jobLite.Instance.Clone() as DomInstance;

					jobLite.ParseLiteData(job);
					jobLite.ApplyChanges();

					var current = jobLite.Instance;

					var diffs = DomTools.CompareDomInstances(previous, current);
					if (diffs.FieldValues.Any())
					{
						DomHelper.DomInstances.Update(jobLite.Instance);
					}
				}
			}
		}

