		public IEnumerable<Job> GetJobsContainingParentReferenceIdInTimeRange(Guid nodeParentReferenceId, DateTime start, DateTime end)
		{
			if (nodeParentReferenceId == Guid.Empty)
			{
				throw new ArgumentNullException(nameof(nodeParentReferenceId));
			}

			if (end <= start)
			{
				throw new InvalidOperationException($"End time must be greater than start time.");
			}

			var filter = DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcWorkflow.Definitions.Jobs.Id)
				.AND(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.Nodes.NodeParentReferenceID).Equal(Convert.ToString(nodeParentReferenceId))
				.AND(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.JobInfo.JobStart).LessThan(end)
				.AND(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.JobInfo.JobEnd).GreaterThan(start))));

			return GetJobsIterator(filter);
		}

		public IEnumerable<Job> GetRunningJobsContainingReferenceIds(params Guid[] nodeReferenceIds)
		{
			if (nodeReferenceIds == null)
			{
				throw new ArgumentNullException(nameof(nodeReferenceIds));
			}

			var filters = new List<FilterElement<DomInstance>>
			{
				DomInstanceExposers.DomDefinitionId.Equal(DomIds.SlcWorkflow.Definitions.Jobs.Id),
				DomInstanceExposers.StatusId.Equal(DomIds.SlcWorkflow.Behaviors.Job_Behavior.Statuses.Running),
			};

			foreach (var nodeReferenceId in nodeReferenceIds)
			{
				filters.Add(DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.Nodes.NodeReferenceID).Equal(Convert.ToString(nodeReferenceId)));
			}

			var filter = new ANDFilterElement<DomInstance>(filters.ToArray());

			return GetJobsIterator(filter);
		}

