		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var instances = FilterQueryExecutor.RetrieveFilteredItems(
				ids,
				x => DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.JobLiteMetadata.FullJobID).Equal(x),
				x => DomHelper.DomInstances.Read(x),
				new DomInstanceByIdComparer());

			return GetJobsLiteIterator(instances);
		}

		private void BulkCreateJobsLite(ICollection<Job> jobs)
		{
			if (jobs == null)
			{
				throw new ArgumentNullException(nameof(jobs));
			}

			foreach (var pagedJobs in jobs.Batch(100))
			{
				var jobsLiteByJobId = GetJobsLiteForJobId(pagedJobs.Select(x => x.InstanceId)).ToDictionary(x => x.Metadata.FullJobId);

				var jobsLite = new List<JobLite>();
				foreach (var job in pagedJobs)
				{
					if (TryPrepareLiteJob(job, jobsLiteByJobId, out var jobLite))
					{
						jobsLite.Add(jobLite);
					}
				}

				if (jobsLite.Count > 0)
				{
					DomHelper.DomInstances.CreateOrUpdate(jobsLite.Select(x => x.Instance).ToList()).ThrowOnFailure();
				}
			}
		}

		private bool TryPrepareLiteJob(Job job, IDictionary<Guid, JobLite> jobsLiteByJobId, out JobLite jobLite)
		{
			DomInstance previous = null;

			if (!jobsLiteByJobId.TryGetValue(job.InstanceId, out jobLite))
			{
				jobLite = new JobLite(this);
			}
			else
			{
				previous = jobLite.Instance.Clone() as DomInstance;
			}

			jobLite.ParseLiteData(job);
			jobLite.ApplyChanges();

			var current = jobLite.Instance;

			if (previous != null)
			{
				var diffs = DomTools.CompareDomInstances(previous, current);
				if (!diffs.FieldValues.Any())
				{
					return false;
				}
			}

			return true;
		}

		private void DeleteJobLite(Job job)
		{
			if (job == null)
			{
				throw new ArgumentNullException(nameof(job));
			}

			var filter = DomInstanceExposers.FieldValues.DomInstanceField(DomIds.SlcWorkflow.Sections.JobLiteMetadata.FullJobID).Equal(job.InstanceId);

			var jobLite = GetJobsLiteIterator(filter).SingleOrDefault();
			if (jobLite != null)
			{
				DomHelper.DomInstances.Delete(jobLite.Instance);
			}
		}

		private void BulkDeleteJobsLite(ICollection<Guid> jobIds)
		{
			if (jobIds == null)
			{
				throw new ArgumentNullException(nameof(jobIds));
			}

			var jobsLite = GetJobsLiteForJobId(jobIds).ToList();
			if (jobsLite.Count == 0)
			{
				return;
			}

			DomHelper.DomInstances.BulkDelete(jobsLite.Select(x => x.Instance).ToList());
		}

		private IEnumerable<Job> GetJobsIterator(FilterElement<DomInstance> filter)
		{
			var instances = DomHelper.DomInstances.Read(filter);

			return GetJobsIterator(instances);
		}

		private IEnumerable<Job> GetJobsIterator(IQuery<DomInstance> filter)
		{
			var instances = DomHelper.DomInstances.Read(filter);

