		}

		private IEnumerable<Job> GetJobsIterator(IEnumerable<DomInstance> instances)
		{
			foreach (var instance in instances)
			{
				if (instance == null || instance.DomDefinitionId.Id != DomIds.SlcWorkflow.Definitions.Jobs.Id)
				{
					continue;
				}

				yield return new Job(this, instance);
			}
		}

