//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling
{
	using System.Collections.Generic;

	/// <summary>
	/// This interface defines a DOM object that can be validated and store errors.
	/// </summary>
	/// <typeparam name="T">
	/// The type of the object that implements the <see cref="IValidatable{T}"/> interface.
	/// </typeparam>
	public interface IValidatable<T> where T : IValidatable<T>
	{
		ValidatorResults<T> Validate(IValidator<T> validator);

		/// <summary>
		/// Gets the errors by error code that are present.
		/// </summary>
		IReadOnlyDictionary<string, IError> Errors { get; }

		/// <summary>
		/// Gets a value indicating whether any error is present.
		/// </summary>
		bool HasErrors { get; }

		/// <summary>
		/// Add or update the error with the provided code.
		/// </summary>
		/// <param name="error">The error to set.</param>
		void SetError(IError error);

		/// <summary>
		/// Add or update the error with the provided code.
		/// </summary>
		/// <param name="errorCode">The error code is a unique identifier for the issue reported.</param>
		/// <param name="message">The message that explains why the error is present.</param>
		/// <returns>An instance of <see cref="IError"/> representing the error.</returns>
		IError SetError(string errorCode, string message);

		/// <summary>
		/// Clears the provided error.
		/// </summary>
		/// <param name="error">The error to clear.</param>
		/// <returns>True if the error was removed, else false.</returns>
		bool ClearError(IError error);

		/// <summary>
		/// Clears the error with the provided code.
		/// </summary>
		/// <param name="errorCode">The error code to clear.</param>
		/// <returns>True if the error was removed, else false.</returns>
		bool ClearError(string errorCode);
	}
}

