namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling
{
	using System;
	using System.Collections.Generic;

	public sealed class Result : IError, IEquatable<Result>
	{
		public Result(ErrorDefinition definition, string message)
		{
			if (String.IsNullOrWhiteSpace(message))
			{
				throw new ArgumentException($"'{nameof(message)}' cannot be null or whitespace.", nameof(message));
			}

			Definition = definition ?? throw new ArgumentNullException(nameof(definition));
			Message = message;
		}

		public ErrorDefinition Definition { get; }

		public string ErrorCode => Definition.ErrorCode;

		public string Message { get; }

		public override bool Equals(object obj)
		{
			return Equals(obj as Result);
		}

		public bool Equals(Result other)
		{
			return !(other is null) &&
				   EqualityComparer<ErrorDefinition>.Default.Equals(Definition, other.Definition) &&
				   Message == other.Message;
		}

		public override int GetHashCode()
		{
			var hashCode = 692613916;
			hashCode = (hashCode * -1521134295) + EqualityComparer<ErrorDefinition>.Default.GetHashCode(Definition);
			hashCode = (hashCode * -1521134295) + EqualityComparer<string>.Default.GetHashCode(Message);
			return hashCode;
		}

		public static bool operator ==(Result left, Result right)
		{
			return EqualityComparer<Result>.Default.Equals(left, right);
		}

		public static bool operator !=(Result left, Result right)
		{
			return !(left == right);
		}
	}
}

//---------------------------------
// DOM\ErrorHandling\ValidatorResults.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.DOM.ErrorHandling
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Utils.MediaOps.Common.Extensions;

	public sealed class ValidatorResults<T> where T : IValidatable<T>
	{
		private readonly Dictionary<string, Result> _results = new Dictionary<string, Result>();

		public ValidatorResults(T instance)
		{
			if (instance == null)
			{
				throw new ArgumentNullException(nameof(instance));
			}

			Instance = instance;
		}

		public ValidatorResults(T instance, IEnumerable<Result> results) : this(instance)
		{
			if (results == null)
			{
				throw new ArgumentNullException(nameof(results));
			}

			foreach (var result in results)
			{
				SetResult(result);
			}
		}

		public T Instance { get; private set; }

		public IReadOnlyCollection<IError> Errors => _results.Values;

		public bool HasErrors => _results.Count == 0;

		public bool HasError(string errorCode)
		{
			if (String.IsNullOrWhiteSpace(errorCode))
			{
				throw new ArgumentException($"'{nameof(errorCode)}' cannot be null or whitespace.", nameof(errorCode));
			}

			return _results.ContainsKey(errorCode);
		}

		public bool SyncResultsToInstance()
		{
			var hasChanges = false;

			var fullOuterJoin = Errors.FullOuterJoin(
				Instance.Errors.Values,
				l => l.ErrorCode,
				r => r.ErrorCode,
				(l, r, key) => new { ErrorCode = key, NewError = l, OldError = r, });

			foreach (var item in fullOuterJoin)
			{
				if (item.NewError != null)
				{
					if (!Instance.Errors.TryGetValue(item.ErrorCode, out var existing) ||
						!EqualityComparer<IError>.Default.Equals(item.NewError, existing))
					{
						Instance.SetError(item.NewError);
						hasChanges = true;
					}
				}
				else if (item.OldError != null)
				{
					if (Instance.Errors.ContainsKey(item.ErrorCode))
					{
						Instance.ClearError(item.OldError);
						hasChanges = true;
					}
				}
				else
				{
					throw new InvalidOperationException("should not be reachable");
				}
			}

			return hasChanges;
		}

		internal void SetResult(Result result)
		{
			if (result == null)
			{
				throw new ArgumentNullException(nameof(result));
			}

			_results[result.ErrorCode] = result;
		}
	}
}

