namespace Skyline.DataMiner.Utils.MediaOps.Common.Extensions
{
	using System;
	using System.Collections.Generic;
	using System.ComponentModel;
	using System.Linq;
	using System.Reflection;

	using Skyline.DataMiner.Net.GenericEnums;

	public static class GenericEnumExtensions
	{
		public static string FindDisplayName<T>(this GenericEnum<T> genericEnum, T value)
		{
			return genericEnum.Entries
				.First(entry => EqualityComparer<T>.Default.Equals(entry.Value, value))
				.DisplayName;
		}

		public static string FindDisplayName(this IGenericEnum genericEnum, object value)
		{
			return genericEnum.Entries
				.First(entry => Equals(entry.Value, value))
				.DisplayName;
		}

		public static T FindValue<T>(this GenericEnum<T> genericEnum, string displayName)
		{
			return genericEnum.Entries
				.First(entry => StringComparer.OrdinalIgnoreCase.Equals(entry.DisplayName, displayName))
				.Value;
		}

		public static object FindValue(this IGenericEnum genericEnum, string displayName)
		{
			return genericEnum.Entries
				.First(entry => StringComparer.OrdinalIgnoreCase.Equals(entry.DisplayName, displayName))
				.Value;
		}
	}

	public static class EnumExtensions
	{
		public static TTarget MapEnum<TSource, TTarget>(this TSource sourceEnum)
		{
			if (EqualityComparer<TSource>.Default.Equals(sourceEnum, default))
			{
				return default;
			}

			return Enum.GetValues(typeof(TTarget))
				.Cast<TTarget>()
				.Single(target => target.ToString().Equals(sourceEnum.ToString(), StringComparison.OrdinalIgnoreCase));
		}

		public static bool TryFromDescription<T>(this string description, out T configType) where T : Enum
		{
			configType = default;
			if (description == null)
				return false;

			var type = typeof(T);
			foreach (var field in type.GetFields(BindingFlags.Public | BindingFlags.Static))
			{
				var attribute = field.GetCustomAttribute<DescriptionAttribute>();
				if (attribute != null)
				{
					if (string.Equals(attribute.Description, description, StringComparison.OrdinalIgnoreCase))
					{
						configType = (T)field.GetValue(null);
						return true;
					}
				}
				else
				{
					if (string.Equals(field.Name, description, StringComparison.OrdinalIgnoreCase))
					{
						configType = (T)field.GetValue(null);
						return true;
					}
				}
			}

			return false;
		}

		public static string GetDescription(this Enum value)
		{
			FieldInfo fi = value.GetType().GetField(value.ToString());

			DescriptionAttribute[] attributes = fi.GetCustomAttributes(typeof(DescriptionAttribute), false) as DescriptionAttribute[];
			if (attributes != null && attributes.Any())
			{
				return attributes.First().Description;
			}

			return value.ToString();
		}
	}
}
