namespace Skyline.DataMiner.Utils.MediaOps.Common.Extensions
{
	using System;
	using System.Collections.Generic;

	using Newtonsoft.Json;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Utils.MediaOps.Common.Exceptions;

	public static class ScriptExtensions
	{
		public static IList<T> ReadScriptParamListFromApp<T>(this IEngine engine, string name)
		{
			if (String.IsNullOrWhiteSpace(name))
			{
				throw new ArgumentException("Value cannot be null or whitespace.", nameof(name));
			}

			var param = engine.GetScriptParam(name);

			if (param == null)
			{
				throw new ArgumentException($"Couldn't find script parameter with name '{name}'");
			}

			try
			{
				if (String.IsNullOrWhiteSpace(param.Value))
				{
					return Array.Empty<T>();
				}

				try
				{
					return JsonConvert.DeserializeObject<T[]>(param.Value);
				}
				catch (Exception)
				{
					// needed for when the value is not encapsulated with []
					return new[] { TryConvertSingleValue<T>(param.Value) };
				}
			}
			catch
			{
				throw new InvalidOperationException($"Unable to convert script parameter '{name}' to list of {typeof(T).Name} (value: {param.Value}).");
			}
		}

		public static IList<string> ReadScriptParamListFromApp(this IEngine engine, string name)
		{
			return ReadScriptParamListFromApp<string>(engine, name);
		}

		public static bool TryReadScriptParamSingleFromApp<T>(this IEngine engine, string name, out T value)
		{
			try
			{
				value = engine.ReadScriptParamSingleFromApp<T>(name);
				return true;
			}
			catch (Exception)
			{
				value = default;
				return false;
			}
		}

		public static T ReadScriptParamSingleFromApp<T>(this IEngine engine, string name)
		{
			var values = ReadScriptParamListFromApp<T>(engine, name);

			if (values.Count == 0)
			{
				throw new InvalidScriptInputException($"No value was provided for parameter '{name}'");
			}

			if (values.Count > 1)
			{
				throw new InvalidScriptInputException($"Multiple values were provided for parameter '{name}'");
			}

			return values[0];
		}

		public static T ReadScriptParamSingleFromApp<T>(this IEngine engine, string name, T defaultValue)
		{
			var values = ReadScriptParamListFromApp<T>(engine, name);

			if (values.Count == 0)
			{
				return defaultValue;
			}

			if (values.Count > 1)
			{
				throw new InvalidScriptInputException($"Multiple values were provided for parameter '{name}'");
			}

			return values[0];
		}

		public static string ReadScriptParamSingleFromApp(this IEngine engine, string name)
		{
			return ReadScriptParamSingleFromApp<string>(engine, name);
		}

		private static T TryConvertSingleValue<T>(string value)
		{
			if (typeof(T) == typeof(Guid) && Guid.TryParse(value, out var guid))
			{
				return (T)(object)guid;
			}

			if (typeof(IConvertible).IsAssignableFrom(typeof(T)))
			{
				return (T)Convert.ChangeType(value, typeof(T));
			}

			return JsonConvert.DeserializeObject<T>(value);
		}
	}
}
//---------------------------------
// Extensions/StringExtensions.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Extensions
{
	using System;
	using System.IO;
	using System.Linq;
	using System.Text;
	using System.Text.RegularExpressions;

	public static class StringExtensions
	{
		public static string Wrap(this string text, int width, bool wrapWords = false)
		{
			var result = new StringBuilder();

			using (var sr = new StringReader(text))
			{
				string line;
				while ((line = sr.ReadLine()) != null)
				{
					if (result.Length > 0)
					{
						result.AppendLine();
					}

					result.Append(WrapLine(line, width, wrapWords));
				}
			}

			return result.ToString();
		}

		public static string WrapLine(this string text, int width, bool wrapWords)
		{
			var result = new StringBuilder();
			var line = new StringBuilder();

			var words = text.Split(' ');

			foreach (var word in words)
			{
				if (line.Length + word.Length >= width)
				{
					if (wrapWords && word.Length > width)
					{
						if (line.Length > 0)
							line.Append(" ");

						var remainingLength = width - line.Length - 3;
						var firstPart = word.Substring(0, remainingLength);
						var otherPart = word.Substring(firstPart.Length);

						var trailingWidth = width - 3;
						var parts = Enumerable.Range(0, (int)Math.Ceiling(Convert.ToDouble(otherPart.Length) / trailingWidth)).Select(i => (i * trailingWidth + trailingWidth) <= otherPart.Length ? otherPart.Substring(i * trailingWidth, trailingWidth) : otherPart.Substring(i * trailingWidth)).ToList();

						line.Append($"{firstPart}...");
						result.Append(line.ToString());

						for (int i = 0; i < parts.Count; i++)
						{
							if (i == parts.Count - 1)
							{
								line.Clear();
								line.Append(parts[i]);
							}
							else
							{
								result.AppendLine();
								result.Append($"{parts[i]}...");
							}
						}

						continue;
					}
					else
					{
						if (result.Length > 0)
							result.AppendLine();
						result.Append(line.ToString());
						line.Clear();
					}
				}

				if (line.Length > 0)
					line.Append(" ");

				line.Append(word);
			}

			if (line.Length > 0)
			{
				if (result.Length > 0)
					result.AppendLine();
				result.Append(line.ToString());
			}

			return result.ToString();
		}

		/// <summary>
		/// Truncates a string to first maxLength characters, and then adds an ellipsis at the end.
		/// If the input string shorter than maxLEngth, returns the same string.
		/// If the input is null, returns null.
		/// </summary>
		/// <param name="text">Input string to be truncated.</param>
		/// <param name="maxLength">Maximum length of the string to be truncated.</param>
		/// <returns>If the string is truncated, returns truncated string with additional ellipsis at the end, with total length of maxLength + 3.</returns>
		public static string TruncateWithEllipsis(this string text, int maxLength)
		{
			if (string.IsNullOrEmpty(text) || text.Length <= maxLength)
			{
				return text;
			}
			else
			{
				return text.Substring(0, maxLength) + "...";
			}
		}

		/// <summary>
		/// Extracts GUID from a string which either already has GUID format, or
		/// is of the format `word[GUID]`, where a word is any alphanumeric word.
		/// </summary>
		/// <param name="input">Parameter necessary for extension method.</param>
		/// <returns>Parsed GUID.</returns>
		/// <exception cref="ArgumentException">Throws exception in case the input string is malformed.</exception>
		public static Guid TryGuidParse(this string input)
		{
			// If string is a guid, convert it to Guid and return
			if (Guid.TryParse(input, out Guid guid))
			{
				return guid;
			}

			// Regex pattern
			string pattern = @"\b\w+\[([0-9a-zA-Z\-]+)\]";

			// Create a new regex object and match the input against the pattern
			Regex regex = new Regex(pattern);
			Match match = regex.Match(input);

			// If input matches the pattern, extract it and try to convert to guid.
			if (match.Success)
			{
				// Extract the matching group
				string guidString = match.Groups[1].Value;

				// Try to parse the extracted matching group as a GUID
				if (Guid.TryParse(guidString, out Guid parsedGuid))
				{
					return parsedGuid;
				}
			}

			// Handle the case where no valid GUID is found
			throw new ArgumentException("The input string does not contain a valid GUID:");
		}
	}
}

