//---------------------------------
// Extensions\IEnumerableExtensions.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Extensions
{
	using System;
	using System.Collections.Concurrent;
	using System.Collections.Generic;
	using System.Linq;
	using System.Threading;
	using System.Threading.Tasks;

	public static class IEnumerableExtensions
	{
		public static bool ScrambledEquals<T>(this IEnumerable<T> first, IEnumerable<T> second)
		{
			var cnt = new Dictionary<T, int>();

			foreach (T s in first)
			{
				if (cnt.ContainsKey(s))
				{
					cnt[s]++;
				}
				else
				{
					cnt.Add(s, 1);
				}
			}

			foreach (T s in second)
			{
				if (!cnt.TryGetValue(s, out var c) || c == 0)
				{
					return false;
				}

				cnt[s]--;
			}

			return cnt.Values.All(c => c == 0);
		}

		public static IEnumerable<T> OrEmptyIfNull<T>(this IEnumerable<T> source)
		{
			return source ?? Enumerable.Empty<T>();
		}

		public static Dictionary<TKey, TElement> SafeToDictionary<TSource, TKey, TElement>(
			 this IEnumerable<TSource> source,
			 Func<TSource, TKey> keySelector,
			 Func<TSource, TElement> elementSelector,
			 IEqualityComparer<TKey> comparer = null)
		{
			var dictionary = new Dictionary<TKey, TElement>(comparer);

			if (source == null)
			{
				return dictionary;
			}

			foreach (TSource element in source)
			{
				dictionary[keySelector(element)] = elementSelector(element);
			}

			return dictionary;
		}

		public static Dictionary<TKey, TSource> SafeToDictionary<TSource, TKey>(
			this IEnumerable<TSource> source,
			Func<TSource, TKey> keySelector,
			IEqualityComparer<TKey> comparer = null)
		{
			return SafeToDictionary(source, keySelector, x => x, comparer);
		}

		public static bool AllOfType<T>(this IEnumerable<object> source)
		{
			return source.All(x => x is T);
		}

		public static IEnumerable<TResult> FullOuterJoin<TLeft, TRight, TKey, TResult>(
									this IEnumerable<TLeft> leftItems,
									IEnumerable<TRight> rightItems,
									Func<TLeft, TKey> leftKeySelector,
									Func<TRight, TKey> rightKeySelector,
									Func<TLeft, TRight, TKey, TResult> resultSelector)
		{
			var leftLookup = leftItems.ToLookup(leftKeySelector);
			var rightLookup = rightItems.ToLookup(rightKeySelector);

			var allKeys = leftLookup.Select(p => p.Key).Concat(rightLookup.Select(p => p.Key)).Distinct();

			foreach (var key in allKeys)
			{
				foreach (var result in FullOuterJoinForKey(leftLookup, rightLookup, key, resultSelector))
				{
					yield return result;
				}
			}
		}

		private static IEnumerable<TResult> FullOuterJoinForKey<TLeft, TRight, TKey, TResult>(
									ILookup<TKey, TLeft> leftLookup,
									ILookup<TKey, TRight> rightLookup,
									TKey key,
									Func<TLeft, TRight, TKey, TResult> resultSelector)
		{
			var leftGroup = leftLookup[key];
			var rightGroup = rightLookup[key];

			if (leftGroup.Any() && rightGroup.Any())
			{
				foreach (var left in leftGroup)
				{
					foreach (var right in rightGroup)
					{
						yield return resultSelector(left, right, key);
					}
				}
			}
			else if (leftGroup.Any())
			{
				foreach (var left in leftGroup)
				{
					yield return resultSelector(left, default, key);
				}
			}
			else if (rightGroup.Any())
			{
				foreach (var right in rightGroup)
				{
					yield return resultSelector(default, right, key);
				}
			}
		}

		public static void Compare<T>(this IEnumerable<T> oldItems, IEnumerable<T> newItems, Action<T> added = null, Action<T> equal = null, Action<T> removed = null)
		{
			var fullOuterJoin = FullOuterJoin(
				oldItems,
				newItems,
				l => l,
				r => r,
				(l, r, key) => new { OldItem = l, NewItem = r, });

			foreach (var item in fullOuterJoin)
			{
				if (item.OldItem != null && item.NewItem != null)
				{
					equal?.Invoke(item.NewItem);
				}
				else if (item.NewItem != null)
				{
					added?.Invoke(item.NewItem);
				}
				else if (item.OldItem != null)
				{
					removed?.Invoke(item.OldItem);
				}
				else
				{
					throw new InvalidOperationException("should not be reachable");
				}
			}
		}

		public static IEnumerable<TSource> DistinctBy<TSource, TKey>(this IEnumerable<TSource> source, Func<TSource, TKey> keySelector, IEqualityComparer<TKey> comparer = null)
		{
			var knownKeys = comparer != null
				? new HashSet<TKey>(comparer)
				: new HashSet<TKey>();

			foreach (TSource element in source)
			{
				if (knownKeys.Add(keySelector(element)))
				{
					yield return element;
				}
			}
		}

		public static string Join(this IEnumerable<string> values, string separator)
		{
			if (values == null)
			{
				return String.Empty;
			}

			return String.Join(separator, values);
		}

		public static IEnumerable<T> Flatten<T>(this IEnumerable<IEnumerable<T>> source)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			return source.SelectMany(x => x);
		}

		public static IEnumerable<TSource> Duplicates<TSource, TKey>(this IEnumerable<TSource> source, Func<TSource, TKey> selector, IEqualityComparer<TKey> comparer = null)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			if (selector == null)
			{
				throw new ArgumentNullException(nameof(selector));
			}

			return DuplicatesIterator(source, selector, comparer);
		}

		private static IEnumerable<TSource> DuplicatesIterator<TSource, TKey>(this IEnumerable<TSource> source, Func<TSource, TKey> selector, IEqualityComparer<TKey> comparer = null)
		{
			var set = new HashSet<TKey>(comparer);

			foreach (var item in source)
			{
				if (!set.Add(selector(item)))
				{
					yield return item;
				}
			}
		}

		public static IEnumerable<TSource> Duplicates<TSource>(this IEnumerable<TSource> source, IEqualityComparer<TSource> comparer = null)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			return Duplicates(source, x => x, comparer);
		}

		public static ICollection<TSource> AsCollection<TSource>(this IEnumerable<TSource> source)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			return source as ICollection<TSource> ?? source.ToList();
		}

		public static IList<TSource> AsList<TSource>(this IEnumerable<TSource> source)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			return source as IList<TSource> ?? source.ToList();
		}

		public static IEnumerable<T> Prefetch<T>(this IEnumerable<T> source, int bufferSize = 1)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			if (bufferSize < 1)
			{
				throw new ArgumentException("Buffer size must be greater than 0", nameof(bufferSize));
			}

			IEnumerable<T> PrefetchIterator()
			{
				using (var buffer = new BlockingCollection<T>(bufferSize))
				using (var cancellationTokenSource = new CancellationTokenSource())
				{
					var prefetchTask = Task.Run(
						() =>
						{
							try
							{
								foreach (var item in source)
								{
									buffer.Add(item, cancellationTokenSource.Token);
								}
							}
							catch (OperationCanceledException)
							{
								// ignore
							}
							finally
							{
								buffer.CompleteAdding();
							}
						}, cancellationTokenSource.Token);

					try
					{
						foreach (var item in buffer.GetConsumingEnumerable(cancellationTokenSource.Token))
						{
							yield return item;
						}
					}
					finally
					{
						cancellationTokenSource.Cancel();
						prefetchTask.Wait();
					}
				}
			}

			return PrefetchIterator();
		}
	}
}

