namespace Skyline.DataMiner.Utils.MediaOps.Common.Extensions
{
	using System;

	public static class TimeZoneInfoExtensions
	{
		public static string GetTimeZoneName(this TimeZoneInfo timeZoneInfo, DateTimeOffset dateTimeOffset)
		{
			if (timeZoneInfo == null)
			{
				return string.Empty;
			}

			TimeSpan currentUtcOffset = timeZoneInfo.GetUtcOffset(dateTimeOffset);

			if (!timeZoneInfo.SupportsDaylightSavingTime)
			{
				return timeZoneInfo.DisplayName;
			}

			string FormatOffset(TimeSpan offset)
			{
				if (offset == TimeSpan.Zero) return "UTC";
				string sign = offset < TimeSpan.Zero ? "-" : "+";
				offset = offset.Duration();
				return $"UTC{sign}{offset:hh\\:mm}";
			}

			string standardUtc = FormatOffset(currentUtcOffset);

			return $"({standardUtc}) {timeZoneInfo.DisplayName.Split(')')[timeZoneInfo.DisplayName.Split(')').Length - 1].Trim()}";
		}

		public static string GetTimeZoneName(this TimeZoneInfo timeZoneInfo)
		{
			return GetTimeZoneName(timeZoneInfo, DateTimeOffset.Now);
		}
	}
}

