//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.IO;

	using Skyline.DataMiner.Analytics.GenericInterface;
	using Skyline.DataMiner.Net;
	using Skyline.DataMiner.Net.Exceptions;
	using Skyline.DataMiner.Net.Messages;

	public static class ConnectionHelper
	{
		public static Connection CreateConnection(GQIDMS dms, string clientName)
		{
			if (dms == null)
			{
				throw new ArgumentNullException(nameof(dms));
			}

			if (String.IsNullOrWhiteSpace(clientName))
			{
				throw new ArgumentException($"'{nameof(clientName)}' cannot be null or whitespace.", nameof(clientName));
			}

			var attributes = ConnectionAttributes.AllowMessageThrottling;

			try
			{
				var connection = ConnectionSettings.GetConnection("localhost", attributes);
				connection.ClientApplicationName = clientName;
				connection.AuthenticateUsingTicket(RequestCloneTicket(dms));
				connection.Subscribe();

				return connection;
			}
			catch (Exception ex)
			{
				throw new DataMinerException("Failed to setup a connection with the DataMiner Agent: " + ex.Message, ex);
			}
		}

		/// <summary>
		/// Requests a one time ticket that can be used to authenticate another connection.
		/// </summary>
		/// <returns>Ticket.</returns>
		private static string RequestCloneTicket(GQIDMS dms)
		{
			var requestInfo = new RequestTicketMessage(TicketType.Authentication, ExportConfig());
			var ticketInfo = dms.SendMessage(requestInfo) as TicketResponseMessage;

			if (ticketInfo == null)
			{
				throw new DataMinerException("Did not receive ticket.");
			}

			return ticketInfo.Ticket;
		}

		/// <summary>
		/// Exports the clientside configuration for polling, zipping etc. Does not include
		/// connection uris and the like.
		/// </summary>
		/// <returns>Flags.</returns>
		private static byte[] ExportConfig()
		{
			using (MemoryStream ms = new MemoryStream())
			{
				using (BinaryWriter bw = new BinaryWriter(ms))
				{
					bw.Write(1); // version
					bw.Write(1000); // ms PollingInterval
					bw.Write(100); // ms PollingIntervalFast
					bw.Write(1000); // StackOverflowSize
					bw.Write(5000); // ms ConnectionCheckingInterval
					bw.Write(10); // MaxSimultaneousCalls

					ConnectionAttributes attributesToAdd = ConnectionAttributes.AllowMessageThrottling;
					bw.Write((int)attributesToAdd);

					bw.Write("r"); // connection is remoting or IPC (which inherits from remoting)
					bw.Write(1); // version
					bw.Write(30); // s PollingFallbackTime
				}

				return ms.ToArray();
			}
		}
	}
}
//---------------------------------
// GQI\RealTimeUpdates\DomDefinitionCache.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.Collections.Concurrent;
	using System.Collections.Generic;
	using System.Linq;
	using System.Threading.Tasks;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM;
	using Skyline.DataMiner.Utils.MediaOps.Common.Extensions;

	using SLDataGateway.API.Querying;

	public class DomDefinitionCache
	{
		private readonly DomDefinitionId _definitionId;
		private readonly DomHelper _domHelper;

		private readonly ConcurrentDictionary<Guid, DomInstance> _instances = new ConcurrentDictionary<Guid, DomInstance>();

		private readonly Task _loadInitialDataTask;

		public DomDefinitionCache(DomDefinitionId definitionId, DomHelper domHelper)
		{
			_definitionId = definitionId ?? throw new ArgumentNullException(nameof(definitionId));
			_domHelper = domHelper ?? throw new ArgumentNullException(nameof(domHelper));

			_loadInitialDataTask = LoadDataAsync();
		}

		public DomInstance GetInstanceById(Guid id)
		{
			var isInitialDataLoaded = _loadInitialDataTask.IsCompleted;

			if (!_instances.TryGetValue(id, out var instance) && !isInitialDataLoaded)
			{
				instance = _domHelper.DomInstances.GetByID(id);

				if (instance != null)
				{
					_instances[instance.ID.Id] = instance;
				}
			}

			return instance;
		}

		public IDictionary<Guid, DomInstance> GetInstancesById(IEnumerable<Guid> ids)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var result = new Dictionary<Guid, DomInstance>();
			var idsToRetrieve = new List<Guid>();

			var isInitialDataLoaded = _loadInitialDataTask.IsCompleted;

			foreach (var id in ids)
			{
				if (_instances.TryGetValue(id, out var instance))
					result[id] = instance;
				else
					idsToRetrieve.Add(id);
			}

			if (idsToRetrieve.Count > 0 && !isInitialDataLoaded)
			{
				// retrieve the remaining instances from server
				var instances = _domHelper.DomInstances.GetByIDs(idsToRetrieve);

				foreach (var instance in instances)
				{
					result[instance.ID.Id] = instance;
					_instances[instance.ID.Id] = instance;
				}
			}

			return result;
		}

		public IEnumerable<DomInstance> GetAllInstances()
		{
			if (_loadInitialDataTask.IsCompleted)
			{
				foreach (var kvp in _instances)
				{
					yield return kvp.Value;
				}
			}
			else
			{
				// keep returning data while still loading in the background (useful for paging)
				var isCompleted = false;
				var returnedKeys = new HashSet<Guid>();

				while (!isCompleted)
				{
					isCompleted = _loadInitialDataTask.Wait(TimeSpan.FromSeconds(1));

					// return the remaining (new) items
					foreach (var kvp in _instances)
					{
						if (returnedKeys.Add(kvp.Key))
						{
							yield return kvp.Value;
						}
					}
				}
			}
		}

		public IEnumerable<DomInstance> GetInstances(FilterElement<DomInstance> filter)
		{
			if (filter == null)
			{
				throw new ArgumentNullException(nameof(filter));
			}

			var isInitialDataLoaded = _loadInitialDataTask.IsCompleted;

			if (isInitialDataLoaded)
			{
				var allInstances = GetAllInstances();
				var instances = filter.ToQuery().ExecuteInMemory(allInstances);

				foreach (var instance in instances)
				{
					yield return instance;
				}
			}
			else
			{
				var instances = _domHelper.DomInstances.ReadPaged(filter).Flatten();

				foreach (var instance in instances)
				{
					yield return instance;
				}
			}
		}

		public void AddOrUpdate(DomInstance instance)
		{
			if (instance == null)
			{
				throw new ArgumentNullException(nameof(instance));
			}

			if (!instance.DomDefinitionId.Equals(_definitionId))
			{
				throw new ArgumentException("Unexpected DOM definition");
			}

			_instances[instance.ID.Id] = instance;
		}

		public void Remove(DomInstance instance)
		{
			if (instance == null)
			{
				throw new ArgumentNullException(nameof(instance));
			}

			if (!instance.DomDefinitionId.Equals(_definitionId))
			{
				throw new ArgumentException("Unexpected DOM definition");
			}

			_instances.TryRemove(instance.ID.Id, out _);
		}

		private void LoadData()
		{
			var filter = GetDefinitionFilter();
			var instances = _domHelper.DomInstances.ReadPaged(filter).Flatten();

			foreach (var instance in instances)
			{
				_instances[instance.ID.Id] = instance;
			}
		}

		private Task LoadDataAsync()
		{
			return Task.Factory.StartNew(LoadData, TaskCreationOptions.LongRunning);
		}

		private FilterElement<DomInstance> GetDefinitionFilter()
		{
			return DomInstanceExposers.DomDefinitionId.Equal(_definitionId.Id);
		}
	}
}
