// GQI\RealTimeUpdates\DomModuleCache.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.Collections.Concurrent;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net;
	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Net.Helper;
	using Skyline.DataMiner.Net.Messages;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;

	public sealed class DomModuleCache : IDisposable
	{
		private readonly DomHelper _helper;
		private readonly DomWatcher _watcher;

		private readonly ConcurrentDictionary<DomDefinitionId, DomDefinitionCache> _definitionInstances = new ConcurrentDictionary<DomDefinitionId, DomDefinitionCache>();

		public DomModuleCache(IConnection connection, string moduleName)
		{
			if (connection is null)
			{
				throw new ArgumentNullException(nameof(connection));
			}

			if (String.IsNullOrWhiteSpace(moduleName))
			{
				throw new ArgumentException($"'{nameof(moduleName)}' cannot be null or whitespace.", nameof(moduleName));
			}

			_helper = new DomHelper(connection.HandleMessages, moduleName);

			_watcher = new DomWatcher(moduleName, connection);
			_watcher.Changed += Watcher_OnChanged;
		}

		public event EventHandler<DomInstancesChangedEventMessage> Changed;

		public DomInstance GetInstanceById(DomDefinitionId definitionId, Guid id)
		{
			if (definitionId == null)
			{
				throw new ArgumentNullException(nameof(definitionId));
			}

			var cache = GetOrCreateDefinitionCache(definitionId);
			return cache.GetInstanceById(id);
		}

		public IDictionary<Guid, DomInstance> GetInstancesById(DomDefinitionId definitionId, IEnumerable<Guid> ids)
		{
			if (definitionId == null)
			{
				throw new ArgumentNullException(nameof(definitionId));
			}

			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			var cache = GetOrCreateDefinitionCache(definitionId);
			return cache.GetInstancesById(ids);
		}

		public IEnumerable<DomInstance> GetInstancesByDefinition(DomDefinitionId definitionId)
		{
			if (definitionId == null)
			{
				throw new ArgumentNullException(nameof(definitionId));
			}

			var cache = GetOrCreateDefinitionCache(definitionId);
			return cache.GetAllInstances();
		}

		public IEnumerable<DomInstance> GetInstances(DomDefinitionId definitionId, FilterElement<DomInstance> filter)
		{
			if (definitionId == null)
			{
				throw new ArgumentNullException(nameof(definitionId));
			}

			if (filter == null)
			{
				throw new ArgumentNullException(nameof(filter));
			}

			var cache = GetOrCreateDefinitionCache(definitionId);
			return cache.GetInstances(filter);
		}

		public DomDefinitionCache GetOrCreateDefinitionCache(DomDefinitionId definitionId)
		{
			if (definitionId == null)
			{
				throw new ArgumentNullException(nameof(definitionId));
			}

			return _definitionInstances.GetOrAdd(definitionId, d => new DomDefinitionCache(d, _helper));
		}

		public DomDefinitionCache GetOrCreateDefinitionCache(DomInstance instance)
		{
			if (instance == null)
			{
				throw new ArgumentNullException(nameof(instance));
			}

			return GetOrCreateDefinitionCache(instance.DomDefinitionId);
		}

		public void Dispose()
		{
			_watcher.Changed -= Watcher_OnChanged;
			_watcher.Dispose();
		}

		private void Watcher_OnChanged(object sender, DomInstancesChangedEventMessage e)
		{
			e.Created.Concat(e.Updated).ForEach(x =>
			{
				var cache = GetOrCreateDefinitionCache(x);
				cache.AddOrUpdate(x);
			});

			e.Deleted.ForEach(x =>
			{
				var cache = GetOrCreateDefinitionCache(x);
				cache.Remove(x);
			});

			Changed?.Invoke(this, e);
		}
	}
}
//---------------------------------
// GQI\RealTimeUpdates\DomWatcher.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;

	using Skyline.DataMiner.Net;
	using Skyline.DataMiner.Net.Messages;
	using Skyline.DataMiner.Net.SubscriptionFilters;

	public sealed class DomWatcher : IDisposable
	{
		private readonly string _moduleName;
		private readonly IConnection _connection;
		private readonly SubscriptionFilter _subscriptionFilter;

		public DomWatcher(string moduleName, IConnection connection)
		{
			if (String.IsNullOrWhiteSpace(moduleName))
			{
				throw new ArgumentException($"'{nameof(moduleName)}' cannot be null or whitespace.", nameof(moduleName));
			}

			_moduleName = moduleName;

			_connection = connection ?? throw new ArgumentNullException(nameof(connection));
			_connection.OnNewMessage += Connection_OnNewMessage;

			_subscriptionFilter = new ModuleEventSubscriptionFilter<DomInstancesChangedEventMessage>(moduleName);
			_connection.AddSubscription($"DomWatcher_{moduleName}", _subscriptionFilter);
		}

		public event EventHandler<DomInstancesChangedEventMessage> Changed;

		public void Dispose()
		{
			try
			{
				_connection.RemoveSubscription($"DomWatcher_{_moduleName}", _subscriptionFilter);
				_connection.OnNewMessage -= Connection_OnNewMessage;
			}
			catch (Exception)
			{
				// ignore
			}
		}

		private void Connection_OnNewMessage(object sender, NewMessageEventArgs e)
		{
			if (e.Message is DomInstancesChangedEventMessage domChange && domChange.ModuleId == _moduleName)
			{
				Changed?.Invoke(this, domChange);
			}
		}
	}
}
