//---------------------------------
// GQI\RealTimeUpdates\GqiRowComparer.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Analytics.GenericInterface;

	public class GqiRowComparer : IEqualityComparer<GQIRow>
	{
		public static readonly GqiRowComparer Instance = new GqiRowComparer();

		public bool Equals(GQIRow x, GQIRow y)
		{
			if (ReferenceEquals(x, y))
			{
				return true;
			}

			if (x == null || y == null ||
				!String.Equals(x.Key, y.Key) ||
				x.Cells.Length != y.Cells.Length)
			{
				return false;
			}

			for (int i = 0; i < x.Cells.Length; i++)
			{
				var cx = x.Cells[i];
				var cy = y.Cells[i];

				if (!EqualityComparer<object>.Default.Equals(cx.Value, cy.Value) ||
					!String.Equals(cx.DisplayValue, cy.DisplayValue))
				{
					return false;
				}
			}

			return true;
		}

		public int GetHashCode(GQIRow row)
		{
			return row.Key?.GetHashCode() ?? 0;
		}
	}
}

//---------------------------------
// GQI\RealTimeUpdates\GqiTableComparer.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Analytics.GenericInterface;
	using Skyline.DataMiner.Net.Helper;

	public class GqiTableComparer
	{
		public GqiTableComparer(ICollection<GQIRow> oldRows, ICollection<GQIRow> newRows)
		{
			if (oldRows == null)
			{
				throw new ArgumentNullException(nameof(oldRows));
			}

			if (newRows == null)
			{
				throw new ArgumentNullException(nameof(newRows));
			}

			AddedRows = newRows.ExceptBy(oldRows, x => x.Key).ToList();

			RemovedRows = oldRows.ExceptBy(newRows, x => x.Key).ToList();

			UpdatedRows = oldRows.Join(
				newRows,
				oldRow => oldRow.Key,
				newRow => newRow.Key,
				(oldRow, newRow) => new { OldRow = oldRow, NewRow = newRow })
				.Where(x => !GqiRowComparer.Instance.Equals(x.OldRow, x.NewRow))
				.Select(x => x.NewRow)
				.ToList();
		}

		public ICollection<GQIRow> AddedRows { get; }

		public ICollection<GQIRow> UpdatedRows { get; }

		public ICollection<GQIRow> RemovedRows { get; }

		public override string ToString()
		{
			return $"{AddedRows.Count} added, {UpdatedRows.Count} updated, {RemovedRows.Count} removed";
		}
	}
}

//---------------------------------
// GQI\RealTimeUpdates\GqiUpdateableDataSource.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Analytics.GenericInterface;

	public abstract class GqiUpdateableDataSource : IGQIDataSource, IGQIUpdateable
	{
		private readonly object _lock = new object();

		private readonly Dictionary<string, RowInfo> _rows = new Dictionary<string, RowInfo>();

		private IGQIUpdater _updater;

		GQIColumn[] IGQIDataSource.GetColumns()
		{
			return GetColumnsInternal();
		}

		GQIPage IGQIDataSource.GetNextPage(GetNextPageInputArgs args)
		{
			var page = GetNextPageInternal(args);

			lock (_lock)
			{
				var newRows = new List<GQIRow>(page.Rows.Length);

				// replace rows that were already updated in the meantime
				foreach (var row in page.Rows)
				{
					var rowInfo = GetOrCreateRowInfo(row.Key);

					if (rowInfo.LastUpdateType == UpdateType.None)
					{
						rowInfo.Row = row;
					}

					if (rowInfo.IsSentToClient ||
						rowInfo.LastUpdateType == UpdateType.Remove)
					{
						// If the row was already sent to the client or removed, skip it
						continue;
					}

					rowInfo.IsSentToClient = true;
					newRows.Add(rowInfo.Row);
				}

				return new GQIPage(newRows.ToArray())
				{
					HasNextPage = page.HasNextPage,
				};
			}
		}

		void IGQIUpdateable.OnStartUpdates(IGQIUpdater updater)
		{
			_updater = updater;
			OnStartUpdatesInternal(updater);
		}

		void IGQIUpdateable.OnStopUpdates()
		{
			OnStopUpdatesInternal();
			_updater = null;
		}

		public abstract GQIColumn[] GetColumnsInternal();

		public abstract GQIPage GetNextPageInternal(GetNextPageInputArgs args);

		public abstract void OnStartUpdatesInternal(IGQIUpdater updater);

		public abstract void OnStopUpdatesInternal();

		public void AddRow(GQIRow row)
		{
			if (row == null)
			{
				throw new ArgumentNullException(nameof(row));
			}

			lock (_lock)
			{
				var rowInfo = GetOrCreateRowInfo(row.Key);
				rowInfo.LastUpdateType = UpdateType.Add;
				rowInfo.Row = row;

				EnsureGqiUpdaterIsAvailable();
				_updater.AddRow(row);

				rowInfo.IsSentToClient = true;
			}
		}

		public void UpdateRow(GQIRow row)
		{
			if (row == null)
			{
				throw new ArgumentNullException(nameof(row));
			}

			lock (_lock)
			{
				var rowInfo = GetOrCreateRowInfo(row.Key);
				rowInfo.LastUpdateType = UpdateType.Update;
				rowInfo.Row = row;

				if (rowInfo.IsSentToClient)
				{
					EnsureGqiUpdaterIsAvailable();
					_updater.UpdateRow(row);
				}
			}
		}

		public void AddOrUpdateRow(GQIRow row)
		{
			if (row == null)
			{
				throw new ArgumentNullException(nameof(row));
			}

			lock (_lock)
			{
				var rowInfo = GetOrCreateRowInfo(row.Key);
				rowInfo.Row = row;

				EnsureGqiUpdaterIsAvailable();

				if (!rowInfo.IsSentToClient)
				{
					rowInfo.LastUpdateType = UpdateType.Add;

					_updater.AddRow(row);
					rowInfo.IsSentToClient = true;
				}
				else
				{
					rowInfo.LastUpdateType = UpdateType.Update;

					_updater.UpdateRow(row);
				}
			}
		}

		public void RemoveRow(string rowKey)
		{
			if (rowKey == null)
			{
				throw new ArgumentNullException(nameof(rowKey));
			}

			lock (_lock)
			{
				var rowInfo = GetOrCreateRowInfo(rowKey);
				rowInfo.LastUpdateType = UpdateType.Remove;
				rowInfo.Row = null;

				if (rowInfo.IsSentToClient)
				{
					EnsureGqiUpdaterIsAvailable();
					_updater.RemoveRow(rowKey);
				}
			}
		}

		private void EnsureGqiUpdaterIsAvailable()
		{
			if (_updater == null)
			{
				throw new InvalidOperationException($"{nameof(OnStartUpdatesInternal)} wasn't called yet (updater is not available)");
			}
		}

		private RowInfo GetOrCreateRowInfo(string key)
		{
			if (!_rows.TryGetValue(key, out var rowInfo))
			{
				rowInfo = new RowInfo(key);
				_rows.Add(key, rowInfo);
			}

			return rowInfo;
		}

		private enum UpdateType
		{
			None,
			Add,
			Update,
			Remove,
		}

		private sealed class RowInfo
		{
			public string Key { get; }

			public GQIRow Row { get; set; }

			public bool IsSentToClient { get; set; }

			public UpdateType LastUpdateType { get; set; }

			public RowInfo(string key)
			{
				Key = key ?? throw new ArgumentNullException(nameof(key));

				LastUpdateType = UpdateType.None;
			}
		}
	}
}

//---------------------------------
// GQI\RealTimeUpdates\ResourceManagerWatcher.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI.RealTimeUpdates
{
	using System;

	using Skyline.DataMiner.Net;
	using Skyline.DataMiner.Net.Messages;

	public sealed class ResourceManagerWatcher : IDisposable
	{
		private readonly IConnection _connection;
		private readonly SubscriptionFilter _subscriptionFilter;
		private readonly string _subscriptionSetId;

		public ResourceManagerWatcher(IConnection connection)
		{
			_connection = connection ?? throw new ArgumentNullException(nameof(connection));
			_subscriptionFilter = new SubscriptionFilter(typeof(ResourceManagerEventMessage));

			_subscriptionSetId = $"ResourceManagerWatcher_{Guid.NewGuid()}";

			_connection.OnNewMessage += Connection_OnNewMessage;
			_connection.AddSubscription(_subscriptionSetId, _subscriptionFilter);
		}

		public event EventHandler<ResourceManagerEventMessage> Changed;

		public void Dispose()
		{
			try
			{
				_connection.RemoveSubscription(_subscriptionSetId, _subscriptionFilter);
				_connection.OnNewMessage -= Connection_OnNewMessage;
			}
			catch (Exception)
			{
				// ignore
			}
		}

		private void Connection_OnNewMessage(object sender, NewMessageEventArgs e)
		{
			if (e.Message is ResourceManagerEventMessage reservationChange)
			{
				Changed?.Invoke(this, reservationChange);
			}
		}
	}
}
//---------------------------------
// GQI\Tools.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.GQI
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Analytics.GenericInterface;
	using Skyline.DataMiner.Net.Sections;

	public static class Tools
	{
		private static IDictionary<Type, GQIColumnType> _columnTypeMapping = new Dictionary<Type, GQIColumnType>
		{
			{typeof(string)  , GQIColumnType.String},
			{typeof(Guid)    , GQIColumnType.String},
			{typeof(int)     , GQIColumnType.Int },
			{typeof(double)  , GQIColumnType.Double },
			{typeof(long)    , GQIColumnType.Double },
			{typeof(bool)    , GQIColumnType.Boolean },
			{typeof(DateTime), GQIColumnType.DateTime },
			{typeof(TimeSpan), GQIColumnType.TimeSpan },
		};

		public static GQIColumnType GetColumnType(Type type)
		{
			if (type == null)
				throw new ArgumentNullException(nameof(type));

			if (_columnTypeMapping.TryGetValue(type, out var columnType))
			{
				return columnType;
			}

			throw new ArgumentException($"Unknown type: '{type.Name}'");
		}

		public static GQIColumn CreateColumn(string name, Type type)
		{
			if (name == null)
				throw new ArgumentNullException(nameof(name));

			if (type == null)
				throw new ArgumentNullException(nameof(type));

			switch (GetColumnType(type))
			{
				case GQIColumnType.Int:
					return new GQIIntColumn(name);
				case GQIColumnType.Double:
					return new GQIDoubleColumn(name);
				case GQIColumnType.Boolean:
					return new GQIBooleanColumn(name);
				case GQIColumnType.DateTime:
					return new GQIDateTimeColumn(name);
				case GQIColumnType.TimeSpan:
					return new GQITimeSpanColumn(name);
				case GQIColumnType.String:
				default:
					return new GQIStringColumn(name);
			}
		}

		public static GQIColumn CreateColumn(string name, FieldDescriptor descriptor)
		{
			if (name == null)
				throw new ArgumentNullException(nameof(name));

			if (descriptor == null)
				throw new ArgumentNullException(nameof(descriptor));

			switch (descriptor)
			{
				case GenericEnumFieldDescriptor _:
					return new GQIStringColumn(name);
				default:
					return CreateColumn(name, descriptor.FieldType);
			}
		}
	}
}
