//---------------------------------
// IAS/Extensions/EngineExtensions.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IAS
{
	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Utils.MediaOps.Common.IAS.Dialogs.DismissibleConfirmDialog;
	using Skyline.DataMiner.Utils.MediaOps.Common.IAS.Dialogs.YesNoCancelDialog;

	public static class EngineExtensions
	{
		public static void ShowErrorDialog(this IEngine engine, string message, string title = "Script execution failed")
		{
			var model = new Dialogs.ErrorDialog.ErrorDialogModel(message);
			var view = new Dialogs.ErrorDialog.ErrorDialogView(engine)
			{
				Title = $"⚠️ {title}",
				ShowScriptAbortPopup = false,
			};

			var presenter = new Dialogs.ErrorDialog.ErrorDialogPresenter(view, model);

			presenter.Close += (sender, arg) =>
			{
				engine.ExitSuccess(string.Empty);
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();
		}

		public static void ShowErrorDialogWithReturn(this IEngine engine, string message, string title = "Script execution failed")
		{
			var model = new Dialogs.ErrorDialog.ErrorDialogModel(message);
			var view = new Dialogs.ErrorDialog.ErrorDialogView(engine)
			{
				Title = $"⚠️ {title}",
				ShowScriptAbortPopup = false,
			};

			var presenter = new Dialogs.ErrorDialog.ErrorDialogPresenter(view, model);

			presenter.Close += (sender, arg) =>
			{
				// Do nothing
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();
		}

		public static void ShowInfoDialog(this IEngine engine, string message, string title)
		{
			var model = new Dialogs.InfoDialog.InfoDialogModel(message);
			var view = new Dialogs.InfoDialog.InfoDialogView(engine)
			{
				Title = title,
				ShowScriptAbortPopup = false,
			};

			var presenter = new Dialogs.InfoDialog.InfoDialogPresenter(view, model);

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show(false);
		}

		public static bool ShowConfirmDialog(this IEngine engine, string message, string confirmLabel = "Confirm", string cancelLabel = "Cancel")
		{
			var model = new Dialogs.ConfirmDialog.ConfirmDialogModel(message);
			var view = new Dialogs.ConfirmDialog.ConfirmDialogView(engine) { ShowScriptAbortPopup = false };
			var presenter = new Dialogs.ConfirmDialog.ConfirmDialogPresenter(view, model);

			view.ConfirmButton.Text = confirmLabel;
			view.CancelButton.Text = cancelLabel;

			var confirmed = false;
			presenter.Cancel += (sender, arg) =>
			{
				confirmed = false;
			};
			presenter.Confirm += (sender, arg) =>
			{
				confirmed = true;
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();

			return confirmed;
		}

		public static bool ShowDismissibleConfirmDialog(this IEngine engine, string title, string message, string proceedLabel, string cancelLabel, DialogType dialogType)
		{
			var model = new DismissibleConfirmDialogModel(title, message, proceedLabel, cancelLabel);
			var view = new DismissibleConfirmDialogView(engine) { ShowScriptAbortPopup = false };
			var presenter = new DismissibleConfirmDialogPresenter(view, model, engine.UserLoginName, dialogType);

			if (!presenter.IsShown())
			{
				return true;
			}

			bool confirmed = false;
			presenter.Cancel += (sender, arg) =>
			{
				confirmed = false;
			};

			presenter.Proceed += (sender, arg) =>
			{
				confirmed = true;
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();

			return confirmed;
		}

		public static void ShowLinkedNodesResultDialog(this IEngine engine, LinkedNodesResult result)
		{
			var model = new Dialogs.LinkedNodesResult.LinkedNodesResultModel(result);
			var view = new Dialogs.LinkedNodesResult.LinkedNodesResultView(engine) { ShowScriptAbortPopup = false };
			var presenter = new Dialogs.LinkedNodesResult.LinkedNodesResultPresenter(view, model);

			presenter.Close += (sender, arg) =>
			{
				engine.ExitSuccess(string.Empty);
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();
		}

		public static YesNoCancelOption ShowYesNoCancelDialog(this IEngine engine, string message, string yesLabel = "yes", string noLabel = "no", string cancelLabel = "cancel")
		{
			return ShowYesNoCancelDialog(engine, new YesNoCancelDialogViewConfiguration
			{
				YesButtonText = yesLabel,
				NoButtonText = noLabel,
				CancelButtonText = cancelLabel,
				Message = message,
			});
		}

		public static YesNoCancelOption ShowYesNoCancelDialog(this IEngine engine, YesNoCancelDialogViewConfiguration configuration)
		{
			var model = new YesNoCancelDialogModel(configuration.Message);
			var view = new YesNoCancelDialogView(engine) { ShowScriptAbortPopup = false };
			var presenter = new YesNoCancelDialogPresenter(view, model);

			view.YesButton.Text = configuration.YesButtonText;
			view.NoButton.Text = configuration.NoButtonText;
			view.CancelButton.Text = configuration.CancelButtonText;

			view.YesButton.Width = configuration.YesButtonWidth;
			view.NoButton.Width = configuration.NoButtonWidth;
			view.CancelButton.Width = configuration.CancelButtonWidth;

			YesNoCancelOption result = YesNoCancelOption.Cancel;
			presenter.Cancel += (sender, arg) =>
			{
				result = YesNoCancelOption.Cancel;
			};

			presenter.Yes += (sender, arg) =>
			{
				result = YesNoCancelOption.Yes;
			};

			presenter.No += (sender, arg) =>
			{
				result = YesNoCancelOption.No;
			};

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show();

			return result;
		}
	}
}

//---------------------------------
// IAS/Extensions/NumericExtensions.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IAS.Extensions
{
	using System;

	using Skyline.DataMiner.Utils.InteractiveAutomationScript;

	public static class NumericExtensions
	{
		public static double ClipValue(this Numeric numeric, double value)
		{
			if (numeric == null)
			{
				throw new ArgumentNullException(nameof(numeric));
			}

			if (value <= numeric.Minimum)
			{
				return numeric.Minimum;
			}

			if (value >= numeric.Maximum)
			{
				return numeric.Maximum;
			}

			return value;
		}
	}
}

//---------------------------------
// IAS/MediaOpsInteractiveScript.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IAS
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Utils.InteractiveAutomationScript;
	using Skyline.DataMiner.Utils.MediaOps.Common;
	using Skyline.DataMiner.Utils.MediaOps.Common.Exceptions;

	using static Skyline.DataMiner.Utils.InteractiveAutomationScript.YesNoDialog;

	public abstract class MediaOpsInteractiveScript : MediaOpsScript
	{
		private InteractiveController app;

		public InteractiveController Controller => app;

		protected virtual string ExceptionTitle { get; set; } = "Something unexpected happened";

		protected override void Initialize()
		{
			base.Initialize();

			app = new InteractiveController(Context.Engine) { ScriptAbortPopupBehavior = ScriptAbortPopupBehavior.HideAlways };
		}

		/// <summary>
		/// DataMiner evaluates if the script needs to launch in interactive mode.
		/// This is determined by a simple string search looking for "engine.ShowUI" in the source code.
		/// However, because of the toolkit NuGet package, this string cannot be found here.
		/// So this comment is here as a workaround.
		/// </summary>
		protected abstract void EngineShowUiInComments();

		protected override void HandleException(Exception exception)
		{
			string message = $"Some unexpected issue happened. Please contact Skyline Communications and ask them to check the {ScriptType} logging around {DateTime.Now}.";
			string title = ExceptionTitle;
			if (exception is InvalidScriptInputException)
			{
				message = $"Could it be you forgot to select an item? If not, please contact Skyline Communications and ask them to check the {ScriptType} logging around {DateTime.Now}.";
				title = "Invalid input arguments";
			}

			ShowError(message, title, () => Exit());
		}

		protected void ShowDialog(Dialog dialog)
		{
			app.ShowDialog(dialog);
		}

		/// <summary>
		/// Method for showing simple dialog to user with custom message, title of dialog and OK button.
		/// This blocks further script execution until the user clicks the <see cref="MessageDialog.OkButton"/> button.
		/// </summary>
		/// <param name="message">Information that will be shown to user.</param>
		/// <param name="title">Title of dialog.</param>
		/// <param name="onOkButtonPressed">Action that is executed when the <see cref="MessageDialog.OkButton"/> is clicked.</param>
		protected void ShowMessage(string message, string title, Action onOkButtonPressed)
		{
			var dialog = new MessageDialog(Context.Engine, message) { Title = title, ShowScriptAbortPopup = false };
			dialog.OkButton.Pressed += (sender, args) => onOkButtonPressed?.Invoke();
			dialog.OkButton.Width = 130;
			dialog.OkButton.Height = 25;

			dialog.SetColumnWidth(0, 600);
			dialog.SetWidgetLayout(dialog.OkButton, new WidgetLayout(1, 0, HorizontalAlignment.Right));

			dialog.Show(true);
		}

		/// <summary>
		/// Method for showing simple dialog to user with custom message, title of dialog and OK button.
		/// The script is exited upon clicking the <see cref="MessageDialog.OkButton"/> button.
		/// </summary>
		/// <param name="message">Information that will be shown to user.</param>
		/// <param name="title">Title of dialog.</param>
		protected virtual void ShowMessage(string message, string title)
		{
			ShowMessage(message, title, () => Exit());
		}

		/// <summary>
		/// Used to show a warning to the user.
		/// This blocks further script execution until the user clicks the <see cref="MessageDialog.OkButton"/> button.
		/// </summary>
		/// <param name="message">Warning to display.</param>
		protected virtual void ShowWarning(string message)
		{
			ShowWarning(message, "Warning", () => { /* Do nothing */ });
		}

		/// <summary>
		/// Used to show a warning to the user.
		/// This blocks further script execution until the user clicks the <see cref="MessageDialog.OkButton"/> button.
		/// </summary>
		/// <param name="lines">Lines of the warning to display.</param>
		protected void ShowWarning(IEnumerable<string> lines)
		{
			ShowWarning(String.Join(Environment.NewLine, lines), "Warning", () => { /* Do nothing */ });
		}

		/// <summary>
		/// Used to show a warning to the user.
		/// This blocks further script execution until the user clicks the <see cref="MessageDialog.OkButton"/> button.
		/// </summary>
		/// <param name="message">Warning to display.</param>
		/// <param name="title">Title of the warning dialog.</param>
