		protected void ShowLinkedNodesResultDialog(LinkedNodesResult result)
		{
			var model = new Dialogs.LinkedNodesResult.LinkedNodesResultModel(result);
			var view = new Dialogs.LinkedNodesResult.LinkedNodesResultView(Context.Engine) { ShowScriptAbortPopup = false };
			var presenter = new Dialogs.LinkedNodesResult.LinkedNodesResultPresenter(view, model);

			presenter.Close += (sender, arg) => Exit();

			presenter.LoadFromModel();
			presenter.BuildView();

			view.Show(true);
		}

		protected bool ShowYesNoDialog(string message, string title = "Are you sure?", CallToAction callToAction = CallToAction.Yes)
		{
			YesNoDialog dialog = new YesNoDialog(Context.Engine, message, callToAction)
			{
				Title = title,
			};

			bool yesButtonPressed = false;
			dialog.YesButton.Pressed += (s, e) => yesButtonPressed = true;
			dialog.NoButton.Pressed += (s, e) => yesButtonPressed = false;

			dialog.Show(true);

			return yesButtonPressed;
		}

		protected void StopScript()
		{
			app.Stop();
		}

		protected void HideUi()
		{
			app.Hide();
		}
	}
}

