//---------------------------------
// IOData/ResourceScheduling/Scripts/BookingHandler/Objects/InputData.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IOData.ResourceScheduling.Scripts.BookingHandler
{
	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.MediaOps.Communication.Exceptions;

	/// <summary>
	/// Represents the base class for input data.
	/// </summary>
	public class InputData
	{
		/// <summary>
		/// Initializes a new instance of the <see cref="InputData"/> class.
		/// </summary>
		protected InputData()
		{
		}

		public OutputData SendToBookingHandler(IEngine engine)
		{
			var data = new BookingHandlerData
			{
				Input = this,
			};

			var subScript = engine.PrepareSubScript("Scheduling_Core_BookingHandler");

			using (data)
			{
				subScript.SelectScriptParam("Input Data", data.Key);
				subScript.Synchronous = true;
				subScript.LockElements = true;
				subScript.StartScript();
			}

			data.Output.RethrowException();

			if (data.Output.TraceData != null && !data.Output.TraceData.HasSucceeded())
			{
				throw new MediaOpsException(data.Output.TraceData);
			}

			return data.Output;
		}
	}
}

