//---------------------------------
// IOData/Workflow/Scripts/SelectConfiguration/Extensions/ConfigurationTargetExtension.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IOData.Workflow.Scripts.SelectConfiguration
{
	public static class ConfigurationTargetExtension
	{
		public static bool IsRecurring(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.RecurringJob || configType == ConfigurationTarget.RecurringJobNode;
		}

		public static bool IsWorkflow(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.Workflow || configType == ConfigurationTarget.WorkflowNode;
		}

		public static bool IsJob(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.Job || configType == ConfigurationTarget.JobNode || configType == ConfigurationTarget.SwapJobNode || configType == ConfigurationTarget.AddJobNodeView;
		}

		public static bool HasEligibleContext(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.AddJobNodeView || configType == ConfigurationTarget.SwapJobNode;
		}

		public static bool HasNodeConfig(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.SwapJobNode || configType == ConfigurationTarget.JobNode || configType == ConfigurationTarget.RecurringJobNode || configType == ConfigurationTarget.WorkflowNode;
		}

		public static bool FilterOutput(this ConfigurationTarget configType)
		{
			return configType == ConfigurationTarget.AddJobNodeView || configType == ConfigurationTarget.SwapJobNode || configType == ConfigurationTarget.ResourceView;
		}

		public static bool HasPoolContext(this ConfigurationTarget configType)
		{
			return configType != ConfigurationTarget.Job && configType != ConfigurationTarget.RecurringJob && configType != ConfigurationTarget.Workflow;
		}

		public static string WorkflowText(this ConfigurationTarget configType)
		{
			if (configType.IsRecurring())
			{
				return "recurring job";
			}
			else if (configType.IsWorkflow())
			{
				return "workflow";
			}
			else
			{
				return "job";
			}
		}
	}
}
