//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.IOData.Workflow.Scripts.SelectConfiguration
{
	using Skyline.DataMiner.Automation;

	public class InputData
	{
		public ConfigurationContext Context { get; set; }

		public OutputData ExecuteScript(IEngine engine)
		{
			var selectConfigurationData = new SelectConfigurationData
			{
				Input = this,
			};

			var subScriptOptions = engine.PrepareSubScript("Workflow_Generic_Select Configuration");
			using (selectConfigurationData)
			{
				subScriptOptions.SelectScriptParam("Input Data", selectConfigurationData.Key);
				subScriptOptions.Synchronous = true;
				subScriptOptions.LockElements = true;
				subScriptOptions.StartScript();
			}

			selectConfigurationData.Output.RethrowException();

			return selectConfigurationData.Output;
		}
	}
}

