namespace Skyline.DataMiner.Utils.MediaOps.Common.LCA
{
	using System;
	using System.Collections.Generic;
	using System.IO;
	using System.Linq;

	using Newtonsoft.Json;

	public static class Applications
	{
		public const string ApplicationsDirectory = @"C:\Skyline DataMiner\applications";

		private static string[] _mediaopsApplicationNames = new[]
		{
			"Control Surface",
			"Cost & Billing",
			"Flow Engineering",
			"Flow Monitoring",
			"People & Organizations",
			"Resource Studio",
			"Scheduling",
			"Virtual Signal Groups",
			"Workflow Designer",
		};

		public static IEnumerable<App> GetApps()
		{
			foreach (string directory in Directory.GetDirectories(ApplicationsDirectory))
			{
				AppInfo appInfo;
				AppConfig publishedConfig;
				AppConfig draftConfig = null;
				try
				{
					appInfo = JsonConvert.DeserializeObject<AppInfo>(File.ReadAllText(Path.Combine(directory, "App.info.json")));
					publishedConfig = JsonConvert.DeserializeObject<AppConfig>(File.ReadAllText(Path.Combine(directory, $"version_{appInfo.PublicVersion}", "App.config.json")));

					if (appInfo.DraftVersion > 0)
					{
						draftConfig = JsonConvert.DeserializeObject<AppConfig>(File.ReadAllText(Path.Combine(directory, $"version_{appInfo.DraftVersion}", "App.config.json")));
					}
				}
				catch (Exception)
				{
					continue;
				}

				yield return new App(appInfo, publishedConfig, draftConfig, directory);
			}
		}

		public static bool IsMediaOpsApp(App app)
		{
			if (app == null)
			{
				throw new ArgumentNullException(nameof(app));
			}

			return _mediaopsApplicationNames.Contains(app.Name);
		}
	}
}

//---------------------------------
// LCA\Data\App.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.LCA
{
	using System.Collections.Generic;
	using System.IO;
	using System.Linq;

	using Newtonsoft.Json.Linq;

	public class App
	{
		public App(AppInfo appInfo, AppConfig publishedConfig, AppConfig draftConfig, string path)
		{
			Path = path;

			Info = appInfo;
			Config = publishedConfig;
			DraftConfig = draftConfig;
		}

		public AppInfo Info { get; }

		public AppConfig Config { get; }

		public AppConfig DraftConfig { get; }

		public string Path { get; }

		public string ID => Config.ID;

		public string Name => Config.Name;

		public ICollection<string> GetReferencedScriptNames()
		{
			var scriptNames = new HashSet<string>();

			var version = Info.PublicVersion;
			var dir = new DirectoryInfo(System.IO.Path.Combine(Path, $"version_{version}"));

			foreach (var jsonFile in dir.EnumerateFiles("*.json", SearchOption.AllDirectories))
			{
				var json = File.ReadAllText(jsonFile.FullName);
				var jsonObj = (JContainer)JObject.Parse(json);
				var scriptTokens = GetDescendantPropertyTokens(jsonObj, "Script");

				scriptNames.UnionWith(scriptTokens.Select(x => x.ToString()));
			}

			return scriptNames;
		}

		private IEnumerable<JToken> GetDescendantPropertyTokens(JContainer container, string propertyName)
		{
			foreach (var descendant in container.DescendantsAndSelf())
			{
				if (descendant is JProperty property && property.Name == propertyName)
				{
					yield return property.Value;
				}
			}
		}
	}
}

