namespace Skyline.DataMiner.Utils.MediaOps.Common.SRM
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.ManagerStore;
	using Skyline.DataMiner.Net.Messages;
	using Skyline.DataMiner.Net.Messages.SLDataGateway;
	using Skyline.DataMiner.Net.ResourceManager.Objects;

	using SLDataGateway.API.Types.Querying;

	public static class ResourceManagerExtensions
	{
		public static ResourcePool GetResourcePoolByName(this ResourceManagerHelper resourceManagerHelper, string name)
		{
			return resourceManagerHelper.GetResourcePools(new ResourcePool { Name = name }).FirstOrDefault();
		}

		public static Resource GetResourceByName(this ResourceManagerHelper resourceManagerHelper, string name)
		{
			return resourceManagerHelper.GetResources(ResourceExposers.Name.Equal(name)).FirstOrDefault();
		}

		public static List<Resource> GetResourcesByNames(this ResourceManagerHelper resourceManagerHelper, List<string> resourceNames)
		{
			var filter = new ORFilterElement<Resource>(resourceNames.Select(name => ResourceExposers.Name.Equal(name)).ToArray());

			return resourceManagerHelper.GetResources(filter).ToList();
		}

		public static List<Resource> GetResourcesFromPool(this ResourceManagerHelper resourceManagerHelper, Guid poolId)
		{
			return resourceManagerHelper.GetResources(ResourceExposers.PoolGUIDs.Contains(poolId)).ToList();
		}

		public static IEnumerable<ICollection<Resource>> ReadPaged(this ResourceManagerHelper helper, IQuery<Resource> query, long pageSize = 500)
		{
			if (helper == null)
			{
				throw new ArgumentNullException(nameof(helper));
			}

			if (query == null)
			{
				throw new ArgumentNullException(nameof(query));
			}

			return ReadPagedIterator(helper, query, pageSize);
		}

		public static IEnumerable<ICollection<ReservationInstance>> ReadPaged(this ResourceManagerHelper helper, IQuery<ReservationInstance> query, long pageSize = 500)
		{
			if (helper == null)
			{
				throw new ArgumentNullException(nameof(helper));
			}

			if (query == null)
			{
				throw new ArgumentNullException(nameof(query));
			}

			return ReadPagedIterator(helper, query, pageSize);
		}

		private static IEnumerable<ICollection<Resource>> ReadPagedIterator(ResourceManagerHelper helper, IQuery<Resource> query, long pageSize)
		{
			var pagingHelper = helper.PrepareResourcePaging(query, pageSize);

			return ReadPagedIterator(pagingHelper);
		}

		private static IEnumerable<ICollection<ReservationInstance>> ReadPagedIterator(ResourceManagerHelper helper, IQuery<ReservationInstance> query, long pageSize)
		{
			var pagingHelper = helper.PrepareReservationInstancePaging(query, pageSize);

			return ReadPagedIterator(pagingHelper);
		}

		private static IEnumerable<ICollection<T>> ReadPagedIterator<T>(PagingHelper<T> pagingHelper) where T : DataType
		{
			while (pagingHelper.HasNextPage())
			{
				pagingHelper.MoveToNextPage();

				yield return pagingHelper.GetCurrentPage();
			}
		}
	}
}
