//---------------------------------
// Take/Graph/Graph.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Take.Graph
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	public class Graph<TNode, TConnection>
		where TConnection : IGraphConnection<TNode>
		where TNode : IGraphNode
	{
		public Graph(ICollection<TConnection> connections)
		{
			Connections = connections ?? throw new ArgumentNullException(nameof(connections));
		}

		public ICollection<TConnection> Connections { get; }

		public IEnumerable<TConnection> GetPrevious(TNode node)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			return Connections.Where(x => EqualityComparer<TNode>.Default.Equals(x.ToNode, node));
		}

		public IEnumerable<TConnection> GetNexts(TNode node)
		{
			if (node == null)
			{
				throw new ArgumentNullException(nameof(node));
			}

			return Connections.Where(x => EqualityComparer<TNode>.Default.Equals(x.FromNode, node));
		}

		public IEnumerable<TNode> GetSources()
		{
			return Connections.Select(x => x.FromNode)
				.Distinct()
				.Where(x => !GetPrevious(x).Any());
		}

		public IEnumerable<TNode> GetDestinations()
		{
			return Connections.Select(x => x.ToNode)
				.Distinct()
				.Where(x => !GetNexts(x).Any());
		}

		public IEnumerable<IEnumerable<TConnection>> GetPaths(TNode source, TNode destination)
		{
			if (source == null)
			{
				throw new ArgumentNullException(nameof(source));
			}

			if (destination == null)
			{
				throw new ArgumentNullException(nameof(destination));
			}

			var emptyPath = Enumerable.Empty<TConnection>();

			foreach (var path in GetPathsInternal(source, destination, emptyPath))
			{
				yield return path;
			}
		}

		private IEnumerable<IEnumerable<TConnection>> GetPathsInternal(TNode current, TNode end, IEnumerable<TConnection> path)
		{
			foreach (var next in GetNexts(current))
			{
				if (path.Contains(next))
				{
					continue;
				}

				var nextPath = path.Append(next);

				if (EqualityComparer<TNode>.Default.Equals(next.ToNode, end))
				{
					yield return nextPath;
					continue;
				}

				foreach (var subPath in GetPathsInternal(next.ToNode, end, nextPath))
				{
					yield return subPath;
				}
			}
		}
	}
}

