namespace Skyline.DataMiner.Utils.MediaOps.Common.Take.Workflows
{
	using System;

	using Skyline.DataMiner.Net.Apps.DataMinerObjectModel;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Builders;

	public class DefaultWorkflow : Workflow
	{
		private DefaultWorkflow(DomInstance domInstance) : base(domInstance)
		{
		}

		public static DefaultWorkflow WorkFlow { get; } = CreateInstance();

		private static DefaultWorkflow CreateInstance()
		{
			var domInstance = new SlcWorkflowBuilder()
				.WithID(Guid.Parse("42193bda-58e3-451a-b31c-61f0c910ab8c"))
				.WithName("Default Workflow")
				.WithScriptName(ScriptNames.WorkflowDefault)
				.AddNode(builder => builder
					.WithNodeID("1")
					.WithNodeType(SlcWorkflow.Enums.NodeType.Source))
				.AddNode(builder => builder
					.WithNodeID("2")
					.WithNodeType(SlcWorkflow.Enums.NodeType.Destination))
				.AddConnection(builder => builder
					.WithConnectionID("1")
					.WithSourceNodeID("1")
					.WithDestinationNodeID("2")
					.WithConnectionExecutionScript(ScriptNames.WorkflowConnectionDefault))
				.Build();

			return new DefaultWorkflow(domInstance);
		}
	}
}

