//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Take.Workflows
{
	using System;
	using System.Collections.Generic;

	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow;
	using Skyline.DataMiner.Utils.MediaOps.Common.Take.Graph;

	public sealed class WorkflowConnection : IEquatable<WorkflowConnection>, IGraphConnection<WorkflowNode>
	{
		public WorkflowConnection(Connection connection, WorkflowNode from, WorkflowNode to)
		{
			DomConnection = connection ?? throw new ArgumentNullException(nameof(connection));
			FromNode = from ?? throw new ArgumentNullException(nameof(from));
			ToNode = to ?? throw new ArgumentNullException(nameof(to));
		}

		// For unit tests.
		internal WorkflowConnection()
		{
		}

		public Connection DomConnection { get; private set; }

		public string ID => DomConnection.ConnectionId;

		public WorkflowNode FromNode { get; private set; }

		public WorkflowNode ToNode { get; private set; }

		public string GetConnectionExecutionScriptName()
		{
			if (String.IsNullOrWhiteSpace(DomConnection.ConnectionExecutionScript))
			{
				return ScriptNames.WorkflowConnectionDefault;
			}

			return DomConnection.ConnectionExecutionScript;
		}

		public override string ToString()
		{
			return $"{FromNode} -> {ToNode}";
		}

		#region IEquatable

		public override bool Equals(object obj)
		{
			return Equals(obj as WorkflowConnection);
		}

		public bool Equals(WorkflowConnection other)
		{
			if (other == null)
				return false;

			if (ReferenceEquals(this, other))
				return true;

			return ID == other.ID;
		}

		public override int GetHashCode()
		{
			return ID.GetHashCode();
		}

		public static bool operator ==(WorkflowConnection left, WorkflowConnection right)
		{
			return EqualityComparer<WorkflowConnection>.Default.Equals(left, right);
		}

		public static bool operator !=(WorkflowConnection left, WorkflowConnection right)
		{
			return !(left == right);
		}

		#endregion
	}
}

