// Take/Workflows/WorkflowNode.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Take.Workflows
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Messages;
	using Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Workflow;
	using Skyline.DataMiner.Utils.MediaOps.Common.Take;
	using Skyline.DataMiner.Utils.MediaOps.Common.Take.Exceptions;
	using Skyline.DataMiner.Utils.MediaOps.Common.Take.Graph;
	using Skyline.DataMiner.Utils.MediaOps.Common.Take.ScriptData;

	using DomIds = Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.DomIds;
	using ResourceStudio = Skyline.DataMiner.Utils.MediaOps.Common.DOM.Applications.Resource_Studio;

	public sealed class WorkflowNode : IEquatable<WorkflowNode>, IGraphNode
	{
		public WorkflowNode(Node node)
		{
			DomNode = node ?? throw new ArgumentNullException(nameof(node));
		}

		// For unit tests.
		internal WorkflowNode()
		{
		}

		public Node DomNode { get; }

		public string ID => DomNode.Id;

		public ResourceStudio.Resource Resource { get; private set; }

		public ResourceStudio.ResourcePool ResourcePool { get; private set; }

		public Resource SrmResource { get; private set; }

		public ICollection<WorkflowConnection> IncomingConnections { get; } = new HashSet<WorkflowConnection>();

		public ICollection<WorkflowConnection> OutgoingConnections { get; } = new HashSet<WorkflowConnection>();

		public void LoadData(WorkflowData workflowData)
		{
			if (workflowData == null)
			{
				throw new ArgumentNullException(nameof(workflowData));
			}

			switch (DomNode.NodeType)
			{
				case DomIds.SlcWorkflow.Enums.NodeType.Resource:
					LoadResourceNode(DomNode, workflowData.DataProvider);
					break;

				case DomIds.SlcWorkflow.Enums.NodeType.ResourcePool:
					LoadResourcePoolNode(DomNode, workflowData.DataProvider);
					break;
			}
		}

		public void SetResource(ResourceStudio.Resource domResource, Resource srmResource, DataProvider dataProvider)
		{
			if (srmResource == null)
			{
				throw new ArgumentNullException(nameof(srmResource));
			}

			if (domResource == null)
			{
				throw new ArgumentNullException(nameof(domResource));
			}

			if (dataProvider == null)
			{
				throw new ArgumentNullException(nameof(dataProvider));
			}

			Resource = domResource;
			SrmResource = srmResource;
		}

		private void LoadResourceNode(
			Node node,
			DataProvider dataProvider)
		{
			var domResource = dataProvider.ResourceStudioHandler.GetResourceByDomInstanceId(node.ReferenceId);
			if (domResource == null)
			{
				throw new TakeException($"Couldn't find DOM resource with ID '{node.ReferenceId}'");
			}

			var resourceId = domResource.InternalProperties?.ResourceId;
			if (resourceId.HasValue && resourceId.Value != Guid.Empty)
			{
				var srmResource = dataProvider.SrmHelpers.ResourceManagerHelper.GetResource(resourceId.Value);
				if (srmResource == null)
				{
					throw new TakeException($"Couldn't find SRM resource with ID '{resourceId.Value}' (DOM resource: '{domResource.Name}')");
				}

				SetResource(domResource, srmResource, dataProvider);
			}
		}

		private void LoadResourcePoolNode(
			Node node,
			DataProvider dataProvider)
		{
			var resourceStudioHandler = dataProvider.ResourceStudioHandler;

			ResourcePool = resourceStudioHandler.GetResourcePoolByDomInstanceId(node.ReferenceId);
			if (ResourcePool == null)
			{
				throw new TakeException($"Couldn't find DOM resource pool with ID '{node.ReferenceId}'");
			}
		}

		public override string ToString()
		{
			if (Resource != null)
			{
				return Resource.Name;
			}
			else if (ResourcePool != null)
			{
				return ResourcePool.Name;
			}
			else if (!String.IsNullOrWhiteSpace(DomNode.Alias))
			{
				return DomNode.Alias;
			}
			else
			{
				return base.ToString();
			}
		}

		#region IEquatable

		public override bool Equals(object obj)
		{
			return Equals(obj as WorkflowNode);
		}

		public bool Equals(WorkflowNode other)
		{
			if (other == null)
				return false;

			if (ReferenceEquals(this, other))
				return true;

			return ID == other.ID;
		}

		public override int GetHashCode()
		{
			return ID.GetHashCode();
		}

		public static bool operator ==(WorkflowNode left, WorkflowNode right)
		{
			return EqualityComparer<WorkflowNode>.Default.Equals(left, right);
		}

		public static bool operator !=(WorkflowNode left, WorkflowNode right)
		{
			return !(left == right);
		}

		#endregion
	}
}

