namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	using System;
	using System.ComponentModel;

	public static class Enums
	{
		public static string GetDescription<T>(this T value) where T : struct, Enum
		{
			var name = Convert.ToString(value);
			var field = typeof(T).GetField(name);

			if (field != null &&
				Attribute.GetCustomAttribute(field, typeof(DescriptionAttribute)) is DescriptionAttribute attr)
			{
				return attr.Description;
			}

			return name;
		}
	}
}

//---------------------------------
// Tools\FilterQueryExecutor.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools.ToBeMovedToNuget
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Net.Messages.SLDataGateway;

	public static class FilterQueryExecutor
	{
		public static IEnumerable<TResult> RetrieveFilteredItems<TId, TFilter, TResult>(
			IEnumerable<TId> ids,
			Func<TId, FilterElement<TFilter>> filterProvider,
			Func<FilterElement<TFilter>, IEnumerable<TResult>> filterResolver,
			IEqualityComparer<TResult> comparer = null)
		{
			ValidateRetrieveFilteredItemsParameters(ids, filterProvider, filterResolver);

			var _comparer = comparer ?? EqualityComparer<TResult>.Default;
			HashSet<TResult> seenIds = new HashSet<TResult>(_comparer);
			var splittedFilter = SplitFilter(ids, filterProvider);
			foreach (var filterPart in splittedFilter)
			{
				var pagedResult = filterResolver(filterPart);
				foreach (var item in pagedResult)
				{
					if (seenIds.Add(item))
					{
						yield return item;
					}
				}
			}
		}

		public static IEnumerable<TResult> RetrieveFilteredItems<TId, TFilter, TResult>(
			IEnumerable<TId> ids,
			Func<TId, FilterElement<TFilter>> filterProvider,
			Func<FilterElement<TFilter>, IEnumerable<IEnumerable<TResult>>> filterResolver,
			IEqualityComparer<TResult> comparer = null)
		{
			ValidateRetrieveFilteredItemsParameters(ids, filterProvider, filterResolver);

			var _comparer = comparer ?? EqualityComparer<TResult>.Default;
			HashSet<TResult> seenIds = new HashSet<TResult>(_comparer);
			var splittedFilter = SplitFilter(ids, filterProvider);
			foreach (var filterPart in splittedFilter)
			{
				var pagedResult = filterResolver(filterPart);
				foreach (var page in pagedResult)
				{
					foreach (var item in page)
					{
						if (seenIds.Add(item))
						{
							yield return item;
						}
					}
				}
			}
		}

		private static void ValidateRetrieveFilteredItemsParameters<TId, TFilter, TResult>(
			IEnumerable<TId> ids,
			Func<TId, FilterElement<TFilter>> filterProvider,
			Func<FilterElement<TFilter>, IEnumerable<TResult>> filterResolver)
		{
			if (ids == null)
			{
				throw new ArgumentNullException(nameof(ids));
			}

			if (filterProvider == null)
			{
				throw new ArgumentNullException(nameof(filterProvider));
			}

			if (filterResolver == null)
			{
				throw new ArgumentNullException(nameof(filterResolver));
			}
		}

		private static IEnumerable<FilterElement<TFilter>> SplitFilter<TId, TFilter>(IEnumerable<TId> ids, Func<TId, FilterElement<TFilter>> filterProvider)
		{
			var batch = new List<FilterElement<TFilter>>();
			var count = 0;

			// max_clause_count is by default set to minimum 1024
			// https://www.elastic.co/guide/en/elasticsearch/reference/7.17/search-settings.html
			const int limit = 1000;

			int CountSubFilters(FilterElement<TFilter> filter)
			{
				switch (filter)
				{
					case ANDFilterElement<TFilter> and: return and.subFilters.Sum(CountSubFilters);
					case ORFilterElement<TFilter> or: return or.subFilters.Sum(CountSubFilters);
					case ManagedFilterIdentifier managedFilter when managedFilter.getValue() is DateTime: return 2;
					default: return 1;
				}
			}

			foreach (var id in ids.Distinct())
			{
				var filter = filterProvider(id);
				var subfilterCount = filter.flatten().Sum(CountSubFilters);

				if (count + subfilterCount > limit && batch.Any())
				{
					yield return new ORFilterElement<TFilter>(batch.ToArray());

					batch.Clear();
					count = 0;
				}

				batch.Add(filter);
				count += subfilterCount;
			}

			// don't forget the last items
			if (batch.Any())
			{
				yield return new ORFilterElement<TFilter>(batch.ToArray());
			}
		}
	}
}

//---------------------------------
// Tools\HashCode.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	public static class HashCode
	{
		public static int Combine(params object[] objects)
		{
			unchecked
			{
				var hash = 17;

				foreach (var obj in objects)
				{
					hash *= 23;
					hash += obj?.GetHashCode() ?? 0;
				}

				return hash;
			}
		}
	}
}

//---------------------------------
// Tools\ItemsCache.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	using System;
	using System.Collections.Concurrent;
	using System.Collections.Generic;
	using System.Linq;

	using Skyline.DataMiner.Utils.MediaOps.Common.Extensions;

	public class ItemsCache<TKey, TItem>
	{
		private readonly ConcurrentDictionary<TKey, TItem> items = new ConcurrentDictionary<TKey, TItem>();

		private readonly Func<IEnumerable<TKey>, IEnumerable<TItem>> getItems;
		private readonly Func<TItem, TKey> getKey;

		public ItemsCache(Func<TItem, TKey> getKey, Func<IEnumerable<TKey>, IEnumerable<TItem>> getItems)
		{
			this.getItems = getItems;
			this.getKey = getKey;
		}

		public int Count => items.Count;

		public TItem Get(TKey key)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			if (!items.TryGetValue(key, out var item))
			{
				item = getItems(new[] { key }).FirstOrDefault();
				items[key] = item;
			}

			return item;
		}

		public IDictionary<TKey, TItem> Get(IEnumerable<TKey> keys)
		{
			if (keys == null)
			{
				throw new ArgumentNullException(nameof(keys));
			}

			var result = new Dictionary<TKey, TItem>();
			var keysToRetrieve = new List<TKey>();

			foreach (var key in keys.Distinct())
			{
				if (items.TryGetValue(key, out var instance))
					result[key] = instance;
				else
					keysToRetrieve.Add(key);
			}

			if (keysToRetrieve.Count > 0)
			{
				// retrieve the remaining items
				var newItems = getItems(keysToRetrieve).SafeToDictionary(x => getKey(x));

				foreach (var key in keysToRetrieve)
				{
					newItems.TryGetValue(key, out var retrievedItem);

					result[key] = retrievedItem;

					// Store the item in the cache, even if it was not found in the retrieved items
					// to avoid retrieving it again in the future
					items[key] = retrievedItem;
				}
			}

			return result;
		}

		public void Store(TItem item)
		{
			if (item == null)
			{
				throw new ArgumentNullException(nameof(item));
			}

			var key = getKey(item);

			if (key != null)
			{
				items[key] = item;
			}
		}

		public void Store(IEnumerable<TItem> items)
		{
			if (items == null)
			{
				throw new ArgumentNullException(nameof(items));
			}

			foreach (var item in items)
			{
				Store(item);
			}
		}

		public void Clear()
		{
			items.Clear();
		}

		public void Clear(TKey key)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			items.TryRemove(key, out _);
		}
	}
}
//---------------------------------
// Tools\LazyConcurrentDictionary.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	using System;
	using System.Collections.Concurrent;

	public class LazyConcurrentDictionary<TKey, TValue>
	{
		private readonly ConcurrentDictionary<TKey, Lazy<TValue>> _concurrentDictionary;

		public LazyConcurrentDictionary()
		{
			_concurrentDictionary = new ConcurrentDictionary<TKey, Lazy<TValue>>();
		}

		public TValue GetOrAdd(TKey key, TValue value)
		{
			var lazyResult = _concurrentDictionary.GetOrAdd(key, k => new Lazy<TValue>(() => value));
			return lazyResult.Value;
		}

		public TValue GetOrAdd(TKey key, Func<TKey, TValue> valueFactory)
		{
			var lazyResult = _concurrentDictionary.GetOrAdd(key, k => new Lazy<TValue>(() => valueFactory(k)));
			return lazyResult.Value;
		}

		public bool TryGetValue(TKey key, out TValue value)
		{
			var success = _concurrentDictionary.TryGetValue(key, out var lazyResult);
			value = success ? lazyResult.Value : default;
			return success;
		}

		public bool TryRemove(TKey key, out TValue value)
		{
			var success = _concurrentDictionary.TryRemove(key, out var lazyResult);
			value = success ? lazyResult.Value : default;
			return success;
		}
	}
}

//---------------------------------
// Tools\ListDictionary.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	using System;
	using System.Collections.Generic;
	using System.Linq;

	public class ListDictionary<TKey, TValue>
	{
		private readonly Dictionary<TKey, List<TValue>> _dictionary = new Dictionary<TKey, List<TValue>>();

		public IEnumerable<TKey> Keys => _dictionary.Keys;

		public IEnumerable<TValue> Values => _dictionary.Values.SelectMany(x => x);

		public int ValuesCount => _dictionary.Values.Sum(list => list.Count);

		public int Count => _dictionary.Count;

		public IReadOnlyList<TValue> this[TKey key]
		{
			get
			{
				if (key == null)
				{
					throw new ArgumentNullException(nameof(key));
				}

				if (_dictionary.TryGetValue(key, out var list))
				{
					return list.AsReadOnly();
				}

				return Array.Empty<TValue>();
			}
		}

		public void Add(TKey key, TValue value)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			if (!_dictionary.TryGetValue(key, out var list))
			{
				list = new List<TValue>();
				_dictionary.Add(key, list);
			}

			list.Add(value);
		}

		public bool Remove(TKey key, TValue value)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			if (!_dictionary.TryGetValue(key, out var list))
			{
				return false;
			}

			var removed = list.Remove(value);

			if (list.Count == 0)
			{
				_dictionary.Remove(key);
			}

			return removed;
		}

		public void Replace(TKey key, TValue oldValue, TValue newValue)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			if (!_dictionary.TryGetValue(key, out var list))
			{
				throw new KeyNotFoundException($"Key '{key}' not found.");
			}

			var index = list.IndexOf(oldValue);
			if (index == -1)
			{
				throw new ArgumentException($"Value '{oldValue}' not found for key '{key}'.");
			}

			list[index] = newValue;
		}

		public bool ContainsKey(TKey key)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			return _dictionary.TryGetValue(key, out var list) && list.Count > 0;
		}

		public bool TryGetValues(TKey key, out IReadOnlyList<TValue> values)
		{
			if (key == null)
			{
				throw new ArgumentNullException(nameof(key));
			}

			if (_dictionary.TryGetValue(key, out var list))
			{
				values = list.AsReadOnly();
				return true;
			}

			values = null;
			return false;
		}

		public void Clear()
		{
			_dictionary.Clear();
		}
	}
}

//---------------------------------
// Tools\OneToOneMapping.cs
//---------------------------------
namespace Skyline.DataMiner.Utils.MediaOps.Common.Tools
{
	using System;
	using System.Collections.Generic;

	public class OneToOneMapping<Ta, Tb>
	{
		private readonly Dictionary<Ta, Tb> _forwardMapping = new Dictionary<Ta, Tb>();
		private readonly Dictionary<Tb, Ta> _reverseMapping = new Dictionary<Tb, Ta>();

		public IReadOnlyDictionary<Ta, Tb> Forward
		{
			get { return _forwardMapping; }
		}

		public IReadOnlyDictionary<Tb, Ta> Reverse
		{
			get { return _reverseMapping; }
		}

		public int Count
		{
			get { return _forwardMapping.Count; }
		}

		public void Add(Ta a, Tb b)
		{
			if (a.Equals(default(Ta)))
			{
				throw new ArgumentNullException("a", "Key cannot be null");
			}

			if (b.Equals(default(Tb)))
			{
				throw new ArgumentNullException("b", "Key cannot be null");
			}

			if (_forwardMapping.ContainsKey(a))
			{
				throw new ArgumentException("Key already exists", "a");
			}

			if (_reverseMapping.ContainsKey(b))
			{
				throw new ArgumentException("Key already exists", "b");
			}

			_forwardMapping.Add(a, b);
			_reverseMapping.Add(b, a);
		}

		public void RemoveForward(Ta a)
		{
			if (a.Equals(default(Ta)))
			{
				throw new ArgumentNullException("a", "Key cannot be null");
			}

			if (!_forwardMapping.TryGetValue(a, out var b))
			{
				throw new ArgumentException("Key does not exist", "a");
			}

			_forwardMapping.Remove(a);
			_reverseMapping.Remove(b);
		}

		public void RemoveReverse(Tb b)
		{
			if (b.Equals(default(Tb)))
			{
				throw new ArgumentNullException("b", "Key cannot be null");
			}

			if (!_reverseMapping.TryGetValue(b, out var a))
			{
				throw new ArgumentException("Key does not exist", "b");
			}

			_forwardMapping.Remove(a);
			_reverseMapping.Remove(b);
		}

		public void Clear()
		{
			_forwardMapping.Clear();
			_reverseMapping.Clear();
		}
	}
}

