namespace Skyline.DataMiner.Utils.MediaOps.Common.UnitTesting
{
	using System;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Core.DataMinerSystem.Automation;
	using Skyline.DataMiner.Core.DataMinerSystem.Common;

	public static class Extensions
	{
		public static IDms GetDmsWithUnitTestSupport(this IEngine engine)
		{
			if (engine == null)
			{
				throw new ArgumentNullException(nameof(engine));
			}

			if (UnitTestDetector.IsInUnitTest)
			{
				var communication = new SimpleSLNetCommunication(engine);
				return DmsFactory.CreateDms(communication);
			}
			else
			{
				return engine.GetDms();
			}
		}
	}
}

