namespace Skyline.DataMiner.Utils.MediaOps.Common.Utils
{
	using System;

	using Skyline.DataMiner.Automation;
	using Skyline.DataMiner.Net.Messages;

	public static class Tools
	{
		public static string GetUserName(IEngine engine)
		{
			if (engine == null)
			{
				throw new ArgumentNullException(nameof(engine));
			}

			var message = new GetUserFullNameMessage();
			var response = (GetUserFullNameResponseMessage)engine.SendSLNetSingleResponseMessage(message);

			return response.User;
		}
	}
}